	struct superblock	*sb;

	struct sleeplock	lock;	// mutex, I/O control
	struct inode_op		*op;
	struct file_op		*fop;
	struct spinlock		ilock;	// protect itself
	// struct mapped 		*maphead;
	struct rb_root		mapping;

	struct dentry		*entry;
}

struct dentry {
	char				filename[MAXNAME + 1];
	// int					ref;
	struct inode		*inode;
	struct dentry		*parent;
	struct dentry		*next;
	struct dentry		*child;
	struct dentry_op	*op;
	struct superblock	*mount;
}

static inline struct dentry *de_mnt_in(struct dentry *de)
{
	while (de->mount != NULL)
		de = de->mount->root;
	return de;
}

static inline void iunlockput(struct inode *ip)
{
	iunlock(ip);
	iput(ip);
}

struct pipe {
	struct spinlock		lock;
	struct wait_queue	wqueue;
	struct wait_queue	rqueue;
	uint	nread;			// number of bytes read
	uint	nwrite;			// number of bytes written
	int		readopen;		// read fd is still open
	int		writeopen;		// write fd is still open
	char	data[PIPESIZE];
}

struct pollfd {
	int32 fd;         /* file descriptor */
