{
	acquire(&wq->lock);
	dlist_add_before(&wq->head, &node->list);
	release(&wq->lock);
}

static inline void wait_queue_del_locked(struct wait_queue *wq, struct wait_node *node)
{
	acquire(&wq->lock);
	dlist_del(&node->list);
