	node->next = next;
	node->prev = prev;
}

static inline void __dlist_link(struct d_list *prev, struct d_list *next) {
	prev->next = next;
	next->prev = prev;
}

static inline void dlist_init(struct d_list *node) {
	node->prev = node->next = node;
