static int pushstack(pagetable_t pt, uint64 table[], char **utable, int maxc, uint64 *spp)
{
	//printf("NNN: enter pushstack!!!\n");
	uint64 sp = *spp;
	uint64 stackbase = PGROUNDDOWN(sp);
	uint64 argc, argp;
	char *buf;

	if ((buf = allocpage()) == NULL) {
		//printf("NNN: allocpage failed!\n");
		return -ENOMEM;
	}
	for (argc = 0; utable; argc++) {
		if (argc >= maxc || fetchaddr((uint64)(utable + argc), &argp) < 0){
			//printf("NNN: get arg[%d] failed!\n",argc);
			goto bad;
		}
		__debug_info("pushstack", "argp=%p\n", argp);
		if (argp == 0){
			// 正常应该来到这里
			break;
		}
		// IMP: in fetchstr using copyinstr2
		int arglen = fetchstr(argp, buf, PGSIZE);   // '\0' included in PGSIZE, but not in envlen
		__debug_info("pushstack", "arglen = %d\n", arglen);
		//printf("NNN: arg[%d] arhlen = %d!\n",argc,arglen);
		if (arglen++ < 0) {                               // including '\0'
			__debug_warn("pushstack", "didn't get null\n");
			//printf("NNN: didn't get null!\n");
			goto bad;
		}
		sp -= arglen;
		// 把用户空间的字符串拷贝到栈上
		if (sp < stackbase || copyout(pt, sp, buf, arglen) < 0){
			//printf("NNN: from buf to stack failed!\n");
			goto bad;
		}
		table[argc] = sp; // 新的字符串首地址(转移到用户栈上)
	}
	table[argc] = 0;
	*spp = sp;
	freepage(buf);
	return argc;

bad:
	if (buf)
		freepage(buf);
	return -EFAULT;
}

void show_vm_load(pagetable_t pagetable, uint64 where_addr)
{
	struct proc *p = myproc();
	w_satp(MAKE_SATP(pagetable));
	sfence_vma();
	permit_usr_mem();
	pageDump((char *)(where_addr));
	protect_usr_mem();
	w_satp(MAKE_SATP(p->pagetable));
	sfence_vma();
}

void many_vm_load(pagetable_t pagetable, uint64 where_addr, uint64 end) // end = where_addr + size
{
	for(int start = where_addr;start < end; start += PGSIZE){
		show_vm_load(pagetable,start);
	}
}

