  }
}

uint64
size4mapping(struct elfhdr* interp_elfhdr, struct inode* interpreter){
  uint64 low_bound = -1, upper_bound = 0;
  int valid = 0;
  struct proghdr ph;
  // 先理解好interpreter这个文件的意义
  //printf("NNN: phoff: %d, phnum: %d\n",interp_elfhdr->phoff,interp_elfhdr->phnum);
  for(uint i = 0, off = interp_elfhdr->phoff; i < interp_elfhdr->phnum; i++, off += sizeof(struct proghdr)){
    if(interpreter->fop->read(interpreter, 0, (uint64)&ph, off, sizeof(struct proghdr)) != sizeof(struct proghdr)){
      printf("[get_total_mapping_size] read failed\n");
      return -1;
    }
    if(ph.type == ELF_PROG_LOAD){
      low_bound = min(low_bound, PGROUNDDOWN(ph.vaddr)); //读取虚拟地址大小
      upper_bound = max(upper_bound, ph.vaddr + ph.memsz);
      valid = 1;
    }
  }
  return valid ? (upper_bound - low_bound) : 0;
}

