int execve(char *path, char **argv, char **envp)
{
	__debug_info("exeve", "path = %s\n", path);
	//printf("NNN:In execve, path = %s\n", path);
	int ret;
	struct inode *ip = NULL;
	pagetable_t pagetable = NULL;
	struct seg *seghead = NULL, *seg;
	struct proc *p = myproc();
	// 
	int dynamic_need = 0;
	struct proghdr ph_store;
	ph_store.vaddr = 0; // to avoid warning
	int already_store = 0;

	__debug_info("execve", "in\n");
	//printf("NNN In execve start parsing!\n");
	if ((ip = namei(path)) == NULL) {
		__debug_warn("execve", "can't open %s\n", path);
		//printf("NNN execve can't open %s\n", path);
		ret = -ENOENT;
		goto bad;
	}

	// Make a copy of p->pagetable without old user space, 
	// but with the same kstack we are using now, which can't be changed.
	if ((pagetable = (pagetable_t)allocpage()) == NULL) {
		// 在这里为新进程分配页表
		ret = -ENOMEM;
		goto bad;
	}
	memmove(pagetable, p->pagetable, PGSIZE); // understand this and below
	// Remove old u-map from the new pt, but don't free since later op might fail.
	for (int i = 0; i < PX(2, MAXUVA); i++) {
		pagetable[i] = 0;
	}

	__debug_info("execve", "get elf\n");
	// Check ELF header
	//printf("NNN: exe lock elf_ip\n");
	ilock(ip);
	struct elfhdr elf;
	if (ip->fop->read(ip, 0, (uint64) &elf, 0, sizeof(elf)) != sizeof(elf) || elf.magic != ELF_MAGIC) { // check if the bytes read were right
		iunlock(ip);
		ret = -ENOEXEC;
		goto bad;
	}

	//printf("NNN:IN exe_p1 %ip->ref = %d\n",ip->ref);

	__debug_info("execve", "load from elf\n");
	//printf("NNN execve load from elf\n");
	// Load program (elf file) into memory. ----could be packed in a function
	struct proghdr ph;
	// the usage of elfaddr was replaced by ph_store
	// uint64 elfaddr = 0;
	int flags;
	for (int i = 0, off = elf.phoff; i < elf.phnum; i++, off += sizeof(ph)) {
		if (ip->fop->read(ip, 0, (uint64)&ph, off, sizeof(ph)) != sizeof(ph)) {
			__debug_warn("execve", "fail to read ELF file\n");
			iunlock(ip);
			ret = -EIO;
			goto bad;
		}
		if (ph.type == ELF_PROG_LOAD){ // 写错条件了, 导致直接没有load, 从而触发了各种访存异常
			// goto normal1; -------- now we reorganize the layout of the code, thus solved
			// if (ph.vaddr % PGSIZE != 0 || ph.memsz < ph.filesz || ph.vaddr + ph.memsz < ph.vaddr) {
			if (ph.memsz < ph.filesz || ph.vaddr + ph.memsz < ph.vaddr) {
				__debug_warn("execve", "funny ELF file: va=%p msz=0x%x fsz=0x%x\n", ph.vaddr, ph.memsz, ph.filesz);
					iunlock(ip);
				ret = -ENOEXEC;
				goto bad;
			}

			// turn ELF flags to PTE flags
			flags = 0;
			flags |= (ph.flags & ELF_PROG_FLAG_EXEC) ? PTE_X : 0;
			flags |= (ph.flags & ELF_PROG_FLAG_WRITE) ? PTE_W : 0;
			flags |= (ph.flags & ELF_PROG_FLAG_READ) ? PTE_R : 0;
			seg = newseg(pagetable, seghead, LOAD, ph.vaddr, ph.memsz, flags);//-------------A1!!!!!!!!!!
			if(seg == NULL) {
				__debug_warn("execve", "newseg fail: vaddr=%p, memsz=%d\n", ph.vaddr, ph.memsz);
				iunlock(ip);
				ret = -ENOMEM;
				goto bad;
			}
			seghead = seg;

			if (ph.off == 0){
				// the usage of elfaddr was replaced by ph_store
				// elfaddr = ph.vaddr;
				if(!already_store){
					// see the documents to know the meaning of the field in the struct
					ph_store.vaddr = elf.phoff + ph.vaddr;
				}
			}


			seg = locateseg(seghead, ph.vaddr); // 在locate之前请看A1!!!
			seg->f_off = ph.off;
			seg->f_sz = ph.filesz;
			if (ph.vaddr <= elf.entry && elf.entry < ph.vaddr + ph.filesz) {
				__debug_info("execve", "meet entry segment: entry=0x%x, va=0x%x, sz=0x%x\n", elf.entry, ph.vaddr, ph.filesz);
				if ((ret = loadseg(pagetable, elf.entry, seg, ip)) < 0) {
					__debug_warn("execve", "load segment\n");
					iunlock(ip);
					goto bad;
				}
			}
		}
		else if(ph.type == ELF_PROG_PHDR){
			ph_store = ph;
			already_store = 1;
		}else if(ph.type == ELF_PROG_INTERP){
			dynamic_need = 1;
		}else{
			//printf("ph.type: %d ph.type != ELF_PROG_LOAD\n", ph.type);
		}
// normal1:
	}
	//printf("NNN execve load finished!\n");
	// NOTE!!!  since MMAP is in the higher address than HEAP, we should firstly alloc HEAP, and then using mmap to do dynamic link
	// Heap
	flags = PTE_R | PTE_W;
	for (seg = seghead; seg->next != NULL; seg = seg->next); // reach the end of the list
	uint64 brk = PGROUNDUP(seg->addr + seg->sz) + PGSIZE;
	__debug_info("execve", "making heap, start=%p\n", brk);
	seg = newseg(pagetable, seghead, HEAP, brk, 0, flags);
	if(seg == NULL) {
		__debug_warn("execve", "new heap fail\n");
		ret = -ENOMEM;
		goto bad;
	}
	seghead = seg;
	//printf("NNN execve HEAP done!\n");

	// when dynamic linking is needed
	struct inode *intprtr;
	struct elfhdr intprtr_hdr;

	uint64 prog_entry, intprtr_sta_loc;
	// Ques
	// iunlockput(ip);
	// //printf("NNN:IN exe_p1 %ip->ref = %d\n",ip->ref);
	iunlock(ip); // IMP: when to put?
	// ip = NULL; // to tell bad about whether is has already been put and unlocked
	//printf("NNN:IN exe_p1.5 %ip->ref = %d\n",ip->ref);

	__debug_info("execve", "making stack\n");
	// Stack
	uint64 sp = VUSTACK;
	#define STACK_PAGES	35
	// STACK位于MMAP的下方,与之错开, 两者以0x7000_0000为分界线
	uint64 stackbase = VUSTACK - PGSIZE * STACK_PAGES;
	seg = newseg(pagetable, seghead, STACK, stackbase, sp - stackbase, flags);
	stackbase += PGSIZE * (STACK_PAGES - 1);
	if(seg == NULL || uvmalloc(pagetable, stackbase, sp, flags) == 0) {
		__debug_warn("execve", "new stack fail\n");
		ret = -ENOMEM;
		goto bad;
	}
	seghead = seg;
	//printf("NNN execve STACk done!\n");

	// prepare a NULL on the bottom of stack
	sp -= sizeof(uint64);

	__debug_info("execve", "pushing argv/envp\n");
	//printf("NNN execve pushing argv/envp start!\n");
	// arguments to user main(argc, argv, envp)
	// argc is returned via the system call return
	// value, which goes in a0.
	int64 argc, envc;
	uint64 uargv[MAXARG + 1], uenvp[MAXENV + 1];
	// Problem occurrs here!!!
	if ((envc = pushstack(pagetable, uenvp, envp, MAXENV, &sp)) < 0 ||
		(argc = pushstack(pagetable, uargv, argv, MAXARG, &sp)) < 0) {
		__debug_warn("execve", "fail to push argv or envp into user stack\n");
		//printf("NNN execve fail to push argv or envp into user stack\n");
		ret = envc < 0 ? envc : argc;
		goto bad;
	}
	//printf("NNN In execve, write random copy start\n");

	uint64 random[2] = { 0xcde142a16cb93072, 0x128a39c127d8bbf2 };
	sp -= 16;
	if (sp < stackbase || copyout(pagetable, sp, (char *)random, 16) < 0) {
		ret = -EINVAL;
		//printf("NNN In execve, write random copy bad\n");
		goto bad;
	}
	// 注意stack的分配应该在dynamic映射之前
	// note before and after
	struct seg *oldseg = p->segment;
	p->segment = seghead;
	pagetable_t oldpagetable = p->pagetable; // 类似于中断的暂存保护
	p->pagetable = pagetable;

	if(dynamic_need){ // bugs could be anywhere...
		if((intprtr = namei("/libc.so")) == NULL){
			printf("interpreter not found\n");
			goto bad;
		}
		//printf("NNN: exe lock interpr_ip\n");
		ilock(intprtr);
		// 我把变量名写错啦!!!
		// if(intprtr->fop->read(intprtr, 0, (uint64) &elf, 0, sizeof(intprtr_hdr)) != sizeof(intprtr_hdr) ){
		if(intprtr->fop->read(intprtr, 0, (uint64) &intprtr_hdr, 0, sizeof(intprtr_hdr)) != sizeof(intprtr_hdr) ){
			printf("read interpreter_hdr failed\n");
      		goto bad;
		}
		// todo:
		// page table 和seghead都应该是新进程的
		intprtr_sta_loc = load_elf_interp(pagetable,seghead, &intprtr_hdr, intprtr);
		// intprtr_sta_loc = load_elf_interp_2(pagetable,seghead, &intprtr_hdr, intprtr, brk);
		printf("NNN: Interpreter load done!!!\n");
		// 使用相对定位
		prog_entry = intprtr_sta_loc + intprtr_hdr.entry; 
		//printf("interp_start_addr:%p program_entry:%p\n", interp_start_addr, program_entry);

		iunlockput(intprtr);
		intprtr = NULL;
	}
	else{
		prog_entry = elf.entry;
		intprtr_sta_loc = 0;
	}
	// p->segment = oldseg;

	uint64 auxvec[][2] = {
		// {AT_HWCAP, 0x112d},
		{AT_HWCAP, 0},
		{AT_PAGESZ, PGSIZE},
		{AT_PHDR, ph_store.vaddr},
		{AT_PHENT, elf.phentsize},
		{AT_PHNUM, elf.phnum},
		{AT_BASE, intprtr_sta_loc}, // 在这里传递动态链接的信息
		{AT_ENTRY, elf.entry},
		{AT_UID, 0},
		{AT_EUID, 0},
		{AT_GID, 0},
		{AT_EGID, 0},
		{AT_SECURE, 0},
		{AT_RANDOM, sp},
		{AT_NULL, 0}
	};

	sp -= 16 + sizeof(auxvec);
	sp -= (envc + 1) * sizeof(uint64); // 注意补0
	uint64 a2 = sp;
	sp -= (argc + 1) * sizeof(uint64);
	uint64 a1 = sp;
	sp -= sizeof(uint64); // argc
	flags = sp % 16;      // on risc-v, sp should be 16-byte aligned
	sp -= flags;
	a1 -= flags;
	a2 -= flags;

	__debug_info("execve", "pushing argv/envp table\n");
	//printf("NNN In execve, pushing argv/envp table\n");

	if (sp < stackbase || 
		copyout(pagetable, a2 + (envc + 1) * sizeof(uint64), (char *)auxvec, sizeof(auxvec)) < 0 ||
		copyout(pagetable, a2, (char *)uenvp, (envc + 1) * sizeof(uint64)) < 0 ||
		copyout(pagetable, a1, (char *)uargv, (argc + 1) * sizeof(uint64)) < 0 ||
		copyout(pagetable, sp, (char *)&argc, sizeof(uint64)) < 0)
	{
		__debug_warn("execve", "fail to copy argv/envp table into user stack\n");
		ret = -EINVAL;
		goto bad;
	}
	p->trapframe->a1 = a1;
	p->trapframe->a2 = a2;

	// Save program name for debugging.
	//printf("NNN:IN exe_p1.6 %ip->ref = %d\n",ip->ref);
	safestrcpy(p->name, ip->entry->filename, sizeof(p->name));
	//printf("NNN:IN exe_p1.7 %ip->ref = %d\n",ip->ref);

	// Commit to the user image.
	// seg = p->segment;
	p->pagetable = pagetable;
	p->segment = seghead;
	p->pbrk = brk;
	p->trapframe->epc = prog_entry;  // initial program counter = main
	p->trapframe->sp = sp; // initial stack pointer
	//printf("NNN:IN exe_p1.8 %ip->ref = %d\n",ip->ref);
	// if (p->elf)
	if (p->elf&&ip!=p->elf)
		iput(p->elf);
	p->elf = ip;
	//printf("NNN:IN exe_p2 %ip->ref = %d\n",ip->ref);
	// p->elf = idup(ip);

	__debug_info("execve", "sp=%p, stackbase=%p, entry=%p\n", sp, stackbase, elf.entry);
	fdcloexec(&p->fds);
	w_satp(MAKE_SATP(p->pagetable));
	sfence_vma();
	w_sstatus_fs(SSTATUS_FS_CLEAN);

	// delsegs(oldpagetable, seg);
	delsegs(oldpagetable, oldseg);
	uvmfree(oldpagetable);
	freepage(oldpagetable);
	/*
	if(!p->killed){
		delsegs(oldpagetable, seg);
		uvmfree(oldpagetable);
		freepage(oldpagetable);
	}*/
	//printf("NNN: execve done\n");
	return 0;
	// return argc; // this ends up in a0, the first argument to main(argc, argv)

	bad:
	__debug_warn("execve", "reach bad: seg=%p, pt=%p, ip=%p\n", seghead, pagetable, ip);
	if (seghead) {
		delsegs(pagetable, seghead);
	}
	if (pagetable) {
		uvmfree(pagetable);
		freepage(pagetable);
	}
	if (ip) {
		iput(ip);
	}
	return ret;
}

void
push_off(void)
{
	int old = intr_get();

	intr_off();
	struct cpu *c = mycpu();
	//printf("\e[32mpush_off()\e[0m: cpuid(): %d\n", cpuid());
	if (c->noff == 0)
		c->intena = old;
	c->noff += 1;
}

void
pop_off(void)
{
	struct cpu *c = mycpu();

	//printf("\e[31mpop_off()\e[0m: cpuid(): %d\n", cpuid());
	if(intr_get())
		panic("pop_off - interruptible");
	if(c->noff < 1) {
		//printf("c->noff = %d\n", c->noff);
		panic("pop_off");
	}
	//printf("c->noff: %d\n", c->noff);
	//printf("c: %x\n", c);
	c->noff -= 1;
	if(c->noff == 0 && c->intena)
		intr_on();
}

