void
main(unsigned long hartid, unsigned long dtb_pa)
{
	inithartid(hartid);

	if (hartid == 0) {
		started = 0;
		cpuinit();
		floatinithart();
		consoleinit();
		printfinit();   // init a lock for printf 
		print_logo();
		kpminit();       // physical page allocator
		kvminit();       // create kernel page table
		kvminithart();   // turn on paging
		kmallocinit();   // small physical memory allocator
		// timerinit();     // init a lock for timer
		trapinithart();  // install kernel trap vector, including interrupt handler
		procinit();
		plicinit();
		plicinithart();
		#ifndef QEMU
		fpioa_pin_init();
		dmac_init();
		#endif 
		disk_init();
		binit();         // buffer cache
		// fileinit();      // file table
		printf("hart 0 init done\n");

		delay(100000000); 
		userinit();      // first user process


		// we need IPI to wake up other hart(s)
		for (int i = 1; i < NCPU; i ++) {
			unsigned long mask = 1 << i;
			struct sbiret res = sbi_send_ipi(mask, 0);
			sbi_send_ipi(mask, 0);
			__debug_assert("main", SBI_SUCCESS == res.error, "sbi_send_ipi failed");
		}
		__sync_synchronize();
		started = 1;
	}
	else
	{
		// hart 1
		while (started == 0)
			;
		__sync_synchronize();
		floatinithart();
		kvminithart();
		trapinithart();
		plicinithart();  // ask PLIC for device interrupts
		printf("hart 1 init done\n");
	}
	__debug_info("main", "hart %d enter main()...\n", hartid);

	// shrink the boot stack
	extern char boot_stack[];
	uint64 kstack = (uint64)boot_stack + hartid * 4 * PGSIZE;
	freepage_n(kstack, 3);

	scheduler();
}

