void
binit(void)
{
	initlock(&bcachelock, "bcache");
	dlist_init(&lru_head);
	nwait = 0;
	for (int i = 0; i < BCACHE_TABLE_SIZE; i++)
		bcache[i] = NULL;

	for (struct buf *b = bufs; b < bufs + BNUM; b++) {
		b->refcnt = 0;
		b->hash.pprev = NULL;
		b->hash.next = NULL;
		b->dirty = 0;
		b->disk = 0;

		dlist_add_before(&lru_head, &b->list);
		initsleeplock(&b->lock, "buffer");
	}
}

struct buf*
bget(uint dev, uint sectorno)
{
	struct buf *b;
	int idx = __hash_idx(sectorno);

	acquire(&bcachelock);

	/**
	 * Is the block already cached? Look up in the hash list at first.
	 * No matter which list the target buf stays now, we can always get
	 * it from the hash list (as long as it is cached).
	 */
rescan:
	for (list_node_t *l = bcache[idx]; l != NULL; l = l->next) {
		b = container_of(l, struct buf, hash);
		if (b->dev == dev && b->sectorno == sectorno) {
			if (l != bcache[idx]) {		// not the first node
				_list_remove(l);		// move it to the head (also lru)
				_list_push_front(&bcache[idx], l);
			}
			if (b->refcnt++ == 0) {
				/**
				 * We are the first visitor.
				 * This indicates that this buf is in the @lru_head list.
				 * We need to move it out in case of being evicted.
				 * The last one who keep the buf will push it back.
				 */
				dlist_del(&b->list);
			}
			release(&bcachelock);
			acquiresleep(&b->lock);
			return b;
		}
	}

	/**
	 * We are here due to cache miss.
	 * Just get one from the tail of @lru_head list.
	 * This may cause an eviction, but it is safe.
	 */
	struct d_list *dl = lru_head.prev;
	if (dl != &lru_head) {
		b = container_of(dl, struct buf, list);
		b->dev = dev;
		b->sectorno = sectorno;
		b->refcnt = 1;

		if (b->hash.pprev) {		// if we were in a hash list
			_list_remove(&b->hash);
		}
		_list_push_front(&bcache[idx], &b->hash);
		dlist_del(&b->list);

		acquiresleep(&b->lock);		// this should not block
		b->valid = 0;
		release(&bcachelock);		// or we will sched() with this spinlock
		return b;
	}

	/**
	 * We are here because the @lru_head list is
	 * empty, we have to go to sleep and wait.
	 * When we wake up, we need to re-scan both hash
	 * and lru list, in case of some procs who need
	 * the identical buf and wake up before us,
	 * taking a buf then insert into the hash list.
	 */
	nwait++;
	// printf("\n"__INFO("bget")" sleep\n");
	sleep(&nwait, &bcachelock);
	nwait--;
	goto rescan;
}

struct buf* 
bread(uint dev, uint sectorno)
{
	struct buf *b;
	b = bget(dev, sectorno);
	if (!b->valid) {
		disk_read(b);
		b->valid = 1;
	}
	return b;
}

void 
bwrite(struct buf *b)
{
	/**
	 * This function doesn't behave the same as the old one
	 * any more. In our case, we only commit the buf to the
	 * disk driver and directly come back without waiting.
	 * Most importantly, we release the buf in this function
	 * instead of brelse(). For two reasons:
	 * 1. bread() and brelse() make a pair for read cases,
	 * while bread() (or bget() if we'll write cover the buf)
	 * and bwrite() make the other pair for write cases.
	 * 2. We need different operations.
	 */

	int res;
	/**
	 * Submit a write request to disk driver. If get positive
	 * result, it means the buf it new in driver's queue, so
	 * we need to keep a ref for the driver.
	 */
	res = disk_submit(b);
	b->valid = 1;
	releasesleep(&b->lock);
	if ((res & 0x1) == 0)
		bput(b);
	if ((res & 0x2) == 0)
		disk_write_start();
}

void
brelse(struct buf *b)
{
	releasesleep(&b->lock);
	bput(b);
}

void bsync(void)
{
	disk_write_start();
}

int breads(struct buf *bufs[], int nbuf)
{
	int i = 0, j, ret = 0;

	// find consecutive sectors
	while (i < nbuf) {
		if (!bufs[i]->valid) {
			for (j = i + 1;
				j < nbuf && !bufs[j]->valid &&
				bufs[j]->sectorno == bufs[j - 1]->sectorno + 1;
				j++);
			j--;
			if (i == j)
				ret = disk_read(bufs[i]);
			else
				ret = disk_multiple_read(&bufs[i], j - i + 1);
			if (ret < 0)
				break;
			while (i <= j)
				bufs[i++]->valid = 1;
		} else {
			i++;
		}
	}

	return ret;
}

void bput(struct buf *b)
{
	acquire(&bcachelock);
	b->refcnt--;
	if (b->refcnt == 0) {
		// no one is waiting for it.
		dlist_add_after(&lru_head, &b->list);

		// available buf for someone who's in sleep-wait
		if (nwait > 0)
			wakeup(&nwait);
	}
	release(&bcachelock);
}

void bprint()
{
	acquire(&bcachelock);
	printf("\nbuf cache:\n");
	for (int i = 0; i < BCACHE_TABLE_SIZE; i++) {
		list_node_t *l = bcache[i];
		if (l == NULL) { continue; }
		printf(__INFO("%d")" ", i);
		for (; l != NULL; l = l->next) {
			struct buf *b = container_of(l, struct buf, hash);
			printf("%d ", b->sectorno);
		}
		printf("\n");
	}
	release(&bcachelock);
}

static int img_write_block(struct superblock *sb, int usr, char *src, uint64 sectorno, uint64 off, uint64 len)
{
	__debug_info("imgfs_write", "sec:%d off:%d len:%d\n", sectorno, off, len);

	struct inode *img = sb->dev;

	ilock(img);
	int ret = img->fop->write(img, usr, (uint64)src, sb->blocksz * sectorno + off, len);
	iunlock(img);

	return ret;
}

static int img_read_block(struct superblock *sb, int usr, char *dst, uint64 sectorno, uint64 off, uint64 len)
{
	__debug_info("imgfs_read", "sec:%d off:%d len:%d\n", sectorno, off, len);

	struct inode *img = sb->dev;

	ilock(img);
	int ret = img->fop->read(img, usr, (uint64)dst, sb->blocksz * sectorno + off, len);
	iunlock(img);

	return ret;
}

static int img_clear_block(struct superblock *sb, uint64 sectorno, uint64 sectorcnt)
{
	struct inode *img = sb->dev;
	int ret = 0;
	uint64 const blksz = sb->blocksz;

	char *buf = kmalloc(blksz);
	if (buf == NULL) 
		return -1;
	memset(buf, 0, blksz);

	uint64 pos = sectorno * blksz;
	ilock(img);
	for (; sectorcnt--; pos += blksz) {
		if (img->fop->write(img, 0, (uint64)buf, pos, blksz) != blksz) {
			ret = -1;
			break;
		}
	}
	iunlock(img);

	kfree(buf);
	return ret;
}

int disk_write_block(struct superblock *sb, int usr, char *src, uint64 sectorno, uint64 off, uint64 len)
{
	if (off + len > BSIZE)
		panic("diskfs_write");

	// __debug_info("diskfs_write", "sec:%d off:%d len:%d\n", sectorno, off, len);
	struct buf *b;

	if (off == 0 && len == BSIZE)
		/**
		 * It hints that the coming write totally
		 * covers the sector. So the original data
		 * will be overwritten, and we don't need
		 * to read the disk.
		 */
		b = bget(sb->devnum, sectorno);
	else
		b = bread(sb->devnum, sectorno);

	int ret = either_copyin_nocheck(b->data + off, usr, (uint64)src, len);

	if (ret == 0)
		ret = len;
	bwrite(b);

	return ret;
}

int disk_read_block(struct superblock *sb, int usr, char *dst, uint64 sectorno, uint64 off, uint64 len)
{
	// if (off + len > BSIZE)
	// 	panic("diskfs_read");
	int ret;
	if (off + len <= BSIZE) {
		// __debug_info("diskfs_read", "sec:%d off:%d len:%d\n", sectorno, off, len);
		struct buf *b = bread(sb->devnum, sectorno);
		ret = either_copyout_nocheck(usr, (uint64)dst, b->data + off, len);
		brelse(b);
	} else {	// over sectors
		int const cnt = (off + len + BSIZE - 1) / BSIZE;
		int i;
		uint32 m, tot = 0;
		struct buf *bufs[cnt];
		// gathering buffers
		for (i = 0; i < cnt; i++)
			bufs[i] = bget(sb->devnum, sectorno++);

		ret = breads(bufs, cnt);
		if (ret >= 0) {
			m = BSIZE - off;
			ret = either_copyout_nocheck(usr, (uint64)dst, bufs[0]->data + off, m);
			tot += m;
		}
		for (i = 1, m = BSIZE; ret >= 0 && i < cnt; i++) {
			if (len - tot < BSIZE)
				m = len - tot;
			ret = either_copyout_nocheck(usr, (uint64)dst + tot, bufs[i]->data, m);
			tot += m;
		}
		for (i = 0; i < cnt; i++)
			brelse(bufs[i]);
	}
	return ret < 0 ? ret : len;
}

int disk_clear_block(struct superblock *sb, uint64 sectorno, uint64 sectorcnt)
{
	struct buf *b;
	while (sectorcnt--) {
		b = bget(sb->devnum, sectorno++);	// we don't care about the original data
		memset(b->data, 0, BSIZE);
		bwrite(b);
	}
	return 0;
}

struct superblock *fs_install(struct inode *dev)
{
	int isdev;

	__debug_info("fs_install", "enter check\n");
	if (dev->mode & S_IFBLK) {
		if (dev->sb != &devfs)
			return NULL;
		isdev = 1;
	} else if (dev->mode & S_IFREG)
		isdev = 0;
	else
		return NULL;

	__debug_info("fs_install", "begin\n");

	struct inode *iroot = NULL;
	struct superblock *sb = fat32_get_sb();

	if (sb == NULL)
		return NULL;

	sb->op.alloc_inode = fat_alloc_inode;
	sb->op.destroy_inode = fat_destroy_inode;
	sb->op.statfs = fat_stat_fs;
	sb->op.sync = fat32_sync_sb;
	if (isdev) {
		sb->op.read = disk_read_block;
		sb->op.write = disk_write_block;
		sb->op.clear = disk_clear_block;
	} else {
		sb->op.read = img_read_block;
		sb->op.write = img_write_block;
		sb->op.clear = img_clear_block;
	}

	initsleeplock(&sb->sb_lock, "fs_sb");
	initlock(&sb->cache_lock, "fs_dcache");

	sb->dev = idup(dev);
	sb->devnum = dev->dev;
	sb->next = NULL;
	sb->ref = 0;

	__debug_info("fs_install", "read superblock\n");
	iroot = fat32_init(sb);
	if (iroot == NULL)
		goto fail;

	if (isdev && sb->blocksz != BSIZE)
		goto fail;

	__debug_info("fs_install", "stub 1\n");
	sb->root = kmalloc(sizeof(struct dentry));
	if (sb->root == NULL)
		goto fail;

	__debug_info("fs_install", "stub 2\n");
	iroot->entry = sb->root;

	// Initialize in-mem dentry struct for root.
	memset(sb->root, 0, sizeof(struct dentry));
	sb->root->inode = iroot;
	sb->root->op = &generic_dop;
	__debug_info("fs_install", "done\n");

	return sb;

fail:
	__debug_warn("fs_install", "fail\n");
	iput(dev);
	if (iroot)
		fat_destroy_inode(iroot);
	if (sb)
		fat32_kill_sb(sb);
	return NULL;
}

static void fs_clean_dentry(struct superblock *sb, struct dentry *de)
{
	sb->op.destroy_inode(de->inode);
	for (struct dentry *child = de->child; child != NULL;) {
		struct dentry *temp = child->next;
		fs_clean_dentry(sb, child);
		child = temp;
	}
	kfree(de);
}

void fs_uninstall(struct superblock *sb)
{
	iput(sb->dev);
	if (sb->op.sync)
		sb->op.sync(sb);
	fs_clean_dentry(sb, sb->root);
	fat32_kill_sb(sb);
}

struct file*
filealloc(void)
{
	struct file *f;
	f = (struct file *)kmalloc(sizeof(struct file));
	if (f == NULL) {
		return NULL;
	}
	initlock(&f->lock, "f->lock");
	f->type = FD_NONE;
	f->ref = 1;
	f->poll = NULL;
	return f;
}

struct file*
filedup(struct file *f)
{
	acquire(&f->lock);
	if(f->ref < 1)
		panic("filedup");
	f->ref++;
	release(&f->lock);
	return f;
}

void
fileclose(struct file *f)
{
	// struct file ff;

	acquire(&f->lock);
	if(f->ref < 1)
		panic("fileclose");
	if(--f->ref > 0){
		release(&f->lock);
		return;
	}
	// ff = *f;
	// f->ref = 0;
	// f->type = FD_NONE;
	// release(&ftable.lock);

	// NOT SURE HERE!
	release(&f->lock);
	if(f->type == FD_PIPE){
		pipeclose(f->pipe, f->writable);
	} else if (f->type == FD_INODE || f->type == FD_DEVICE) {
		iput(f->ip);
	}
	// else if () {

	// }
	kfree(f);
}

int
filestat(struct file *f, uint64 addr)
{
	// struct proc *p = myproc();
	struct kstat st;

	if(f->type == FD_INODE){
		ilock(f->ip);
		f->ip->op->getattr(f->ip, &st);
		iunlock(f->ip);
	} else if (f->type == FD_DEVICE) {
		f->ip->op->getattr(f->ip, &st);
	} else {
		return -1;
	}
	// if(copyout(p->pagetable, addr, (char *)&st, sizeof(st)) < 0)
	if(copyout2(addr, (char *)&st, sizeof(st)) < 0)
		return -1;
	return 0;
}

int
fileread(struct file *f, uint64 addr, int n)
{
	int r = 0;
	struct inode *ip = f->ip;

	if (f->readable == 0)
		return -EPERM;
	if (!rangeinseg(addr, addr + n))
		return -EFAULT;
	if (n == 0)
		return 0;

	switch (f->type) {
		case FD_PIPE:
				r = piperead(f->pipe, addr, n);
				break;
		case FD_DEVICE:
				// if(f->major < 0 || f->major >= NDEV || !devsw[f->major].read)
				//   return -1;
				// r = devsw[f->major].read(1, addr, n);
				ilock(ip);
				r = ip->fop->read(ip, 1, addr, 0, n);
				iunlock(ip);
				break;
		case FD_INODE:
				ilock(ip);
				r = ip->fop->read(ip, 1, addr, f->off, n);
				if (r > 0) {
					acquire(&f->lock);
					f->off += r;
					release(&f->lock);
				}
				iunlock(ip);
				break;
		default:
			panic("fileread");
	}

	return r;
}

int copy_file_range(struct file *fp_in,int off_in,struct file *fp_out, int off_out, int real_len, int flags)
{
	char buf[PGSIZE];
	struct inode *InNode = fp_in->ip;
	struct inode *OutNode = fp_out->ip;
	int cnt = 0, toget = 0;
	for(;cnt<real_len; cnt+= toget){
		toget = real_len - cnt;
		if(toget > PGSIZE){
			toget = PGSIZE;
		}
		InNode->fop->read(InNode,0,buf,off_in,toget);
		OutNode->fop->write(OutNode,0,buf,off_out,toget);
		off_in += toget;
		off_out += toget;
	}
	return cnt;
	//InNode->fop->read(InNode,0,buf,off_in,real_len);
}

int
filewrite(struct file *f, uint64 addr, int n)
{
	int ret = 0;

	if (f->writable == 0)
		return -EPERM;
	if (!rangeinseg(addr, addr + n))
		return -EFAULT;

	//if(f->ip == ) //AAA1

	struct inode *ip = f->ip;
	// __debug_info("filewrite", "addr=%p, n=%d\n", addr, n);
	if (f->type == FD_PIPE) {
		ret = pipewrite(f->pipe, addr, n);
	} else if (f->type == FD_DEVICE) {
		ret = ip->fop->write(ip, 1, addr, 0, n);
	} else if (f->type == FD_INODE) {
		ilock(ip);
		ret = ip->fop->write(ip, 1, addr, f->off, n);
		if (ret == n) {
			acquire(&f->lock);
			f->off += n;
			release(&f->lock);
		} else {
			ret = -1;
		}
		iunlock(ip);
	} else {
		panic("filewrite");
	}

	// __debug_info("filewrite", "ret=%d\n", ret);
	return ret;
}

int
filereaddir(struct file *f, uint64 addr, uint64 n)
{
	__debug_info("filereaddir", "f->type=%d, f->readable=%d\n", f->type, f->readable);
	if (f->type != FD_INODE || f->readable == 0)
		return -1;

	struct dirent dent;
	struct inode *ip = f->ip;

	if (!S_ISDIR(ip->mode))
		return -ENOTDIR;
	if (!rangeinseg(addr, addr + n))
		return -EFAULT;

	int ret;
	uint off = f->off;
	uint64 old = addr;
	ilock(ip);
	for (;;) {
		ret = ip->fop->readdir(ip, &dent, off);
		if (ret <= 0 || dent.reclen > n) // 0 is end, -1 is err
			break;

		if (copyout_nocheck(addr, (char *)&dent, dent.reclen) < 0) {
			ret = -EFAULT;
			break;	
		}

		off += ret;
		addr += dent.reclen;
		n -= dent.reclen;

	}
	acquire(&f->lock);
	f->off = off;
	release(&f->lock);
	iunlock(ip);

	if (ret < 0)
		return -ret;
	return addr - old;
}

int filereadv(struct file *f, struct iovec ioarr[], int count)
{
	int r = 0;
	struct inode *ip = f->ip;

	if (!f->readable)
		return -1;

	switch (f->type) {
		case FD_PIPE:
			r = pipereadv(f->pipe, ioarr, count);
			break;
		case FD_DEVICE:
			ilock(ip);
			r = ip->fop->readv(ip, ioarr, count, 0);
			iunlock(ip);
			break;
		case FD_INODE:
			// if (!ip->fop->readv)
			// 	return -EPERM;
			ilock(ip);
			r = ip->fop->readv(ip, ioarr, count, f->off);
			if (r > 0) {
				acquire(&f->lock);
				f->off += r;
				release(&f->lock);
			}
			iunlock(ip);
			break;
		default:
			panic("filereadv");
	}
	return r;
}

int filewritev(struct file *f, struct iovec ioarr[], int count)
{
	int ret = 0;
	struct inode *ip = f->ip;

	if (!f->writable)
		return -1;

	switch (f->type) {
		case FD_PIPE:
			ret = pipewritev(f->pipe, ioarr, count);
			break;
		case FD_DEVICE:
			ret = ip->fop->writev(ip, ioarr, count, 0);
			break;
		case FD_INODE:
			// if (!ip->fop->writev)
			// 	return -EPERM;
			ilock(ip);
			ret = ip->fop->writev(ip, ioarr, count, f->off);
			if (ret > 0) {
				acquire(&f->lock);
				f->off += ret;
				release(&f->lock);
			}
			iunlock(ip);
			break;
		default:
			panic("filewritev");
	}
	return ret;
}

int copyfdtable(struct fdtable *fdt1, struct fdtable *fdt2)
{
	struct fdtable *fd = fdt2;

	for (;;) {
		fd->basefd = fdt1->basefd;
		fd->nextfd = fdt1->nextfd;
		fd->used = fdt1->used;
		fd->exec_close = fdt1->exec_close;
		for (int i = 0; i < NOFILE; i++) {
			if (fdt1->arr[i]) {
				fd->arr[i] = filedup(fdt1->arr[i]);
			} else {
				fd->arr[i] = NULL;
			}
		}
		fdt1 = fdt1->next;
		if (fdt1) {
			if ((fd->next = kmalloc(sizeof(struct fdtable))) == NULL) {
				goto bad;
			}
			__debug_info("copyfdtable", "alloc\n");
			fd = fd->next;
		} else {
			fd->next = NULL;
			break;
		}
	}
	return 0;
bad:
	dropfdtable(fdt2);
	return -1;
}

void dropfdtable(struct fdtable *fdt)
{
	for (int i = 0; i < NOFILE; i++) {
		if (fdt->arr[i]) {
			fileclose(fdt->arr[i]);
		}
	}
	if (fdt->next) {
		dropfdtable(fdt->next);
		kfree(fdt->next);
			__debug_info("dropfdtable", "free\n");
	}
}

struct file *fd2file(int fd, int free)
{
	if (fd < 0)
		panic("fd2file");

	struct proc *p = myproc();
	struct fdtable *head = &p->fds, *prev = NULL;
	struct file *f = NULL;

	while (head && fd >= head->basefd + NOFILE) {
		prev = head;
		head = head->next;
	}
	if (!head || fd < head->basefd) // not found
		return NULL;

	fd %= NOFILE;
	f = head->arr[fd];
	if (free) {
		head->arr[fd] = NULL; // the file should be closed by caller
		head->exec_close &= ~(1 << fd);
		if (fd < head->nextfd) {  // make nextfd the smallest
			head->nextfd = fd;
		}
		if (--head->used == 0 && prev) {  // if table is empty and is not the head, free it
			prev->next = head->next;
			kfree(head);
			__debug_info("fd2file", "free %p\n", head);
		}
	}
	return f;
}

static struct fdtable *newfdtable(int basefd, struct fdtable *next)
{
	struct fdtable *fdnew = kmalloc(sizeof(struct fdtable));
	if (fdnew == NULL) {
		return NULL;
	}
	fdnew->basefd = basefd;
	fdnew->exec_close = 0;
	fdnew->nextfd = 0;
	fdnew->used = 0;
	memset(fdnew->arr, 0, sizeof(fdnew->arr));
	fdnew->next = next;
	return fdnew;
}

int fdalloc(struct file *f, int flag)
{
	int fd = 0;
	struct proc *p = myproc();
	struct fdtable *fdt = &p->fds;

	while (fdt->nextfd == NOFILE) { // table full
		if (!fdt->next ||                               // no next table
				fdt->basefd + NOFILE != fdt->next->basefd)  // or next table is not continuous
		{
			struct fdtable *fdnew = newfdtable(fdt->basefd + NOFILE, fdt->next);
			if (fdnew == NULL) {
				return -1;
			}
			__debug_info("fdalloc", "alloc %p\n", fdnew);
			fdt->next = fdnew;
		}
		fdt = fdt->next;
	}

	fd = fdt->nextfd;
	fdt->arr[fd] = f;
	fdt->used++;
	if (flag)
		fdt->exec_close |= 1 << fd;

	// locate the next smallest free fd
	// if not found, nextfd will stop at NOFILE, which means this table is full
	while (++fdt->nextfd < NOFILE) {
		if (fdt->arr[fdt->nextfd] == NULL) {
			break;
		}
	}

	return fd + fdt->basefd;
}

int fdalloc3(struct file *f, int fd, int flag)
{
	if (fd < 0)
		panic("fdalloc3");

	__debug_info("fdalloc3", "in fd=%d flag=%d\n", fd, flag);
	struct proc *p = myproc();
	struct fdtable *fdt = &p->fds, *prev = NULL;

	while (fdt && fdt->basefd + NOFILE <= fd) {
		prev = fdt;
		fdt = fdt->next;
	}
	if (!fdt || fdt->basefd > fd) {  // no next table, or next table is not continuous
		struct fdtable *fdnew = newfdtable(fd - fd % NOFILE, fdt);
		if (fdnew == NULL) {
			return -1;
		}
		prev->next = fdnew;
		fdt = fdnew;
		__debug_info("fdalloc3", "alloc %p base=%d\n",
									fdnew, fdnew->basefd);
	}

	int fd2 = fd % NOFILE;
	if (fdt->arr[fd2] != NULL) {
		fdt->exec_close &= ~(1 << fd2);
		fileclose(fdt->arr[fd2]);
		fdt->arr[fd2] = f;
	} else {
		fdt->arr[fd2] = f;
		fdt->used++;
		if (fd2 == fdt->nextfd) { // unfortunately, we need to update nextfd
			while (++fdt->nextfd < NOFILE) {
				if (fdt->arr[fdt->nextfd] == NULL) {
					break;
				}
			}
		}
	}
	__debug_info("fdalloc3", "table %p base=%d, nextfd=%d, fd2=%d, fd=%d\n",
								fdt, fdt->basefd, fdt->nextfd, fd2, fd);

	if (flag)
		fdt->exec_close |= (1 << fd2);

	return fd;
}

void fdcloexec(struct fdtable *fdt)
{
	struct fdtable *prev = NULL;

	while (fdt) {
		if (fdt->exec_close) { // quick peek
			__debug_info("fdcloexec", "cloexec flag: 0x%x\n", fdt->exec_close);
			for (int i = 0; i < NOFILE; i++) {
				if (fdt->exec_close & (1 << i)) {
					fileclose(fdt->arr[i]);
					if (--fdt->used == 0) { // no need to loop
						break;
					}
					fdt->arr[i] = NULL;
					if (i < fdt->nextfd) {
						fdt->nextfd = i;
					}
				}
			}
			fdt->exec_close = 0;
		}
		// we don't free the first table because it's in a proc
		if (fdt->used == 0 && prev) {
			prev->next = fdt->next;
			kfree(fdt);
			fdt = prev->next;
		} else {
			prev = fdt;
			fdt = fdt->next;
		}
	}
}

int fcntldup(struct file *f, int fd, int cloexec)
{
	if (fd < 0)
		panic("fcntldup");

	struct proc *p = myproc();
	struct fdtable *fdt = &p->fds, *prev = NULL;

	while (fdt && fdt->basefd + NOFILE <= fd) {
		prev = fdt;
		fdt = fdt->next;
	}

	int base = fd - fd % NOFILE;
	fd %= NOFILE;
	for (;;) {
		if (!fdt || fdt->basefd > base) {  // no next table, or next table is not continuous
			struct fdtable *fdnew = newfdtable(base, fdt);
			if (fdnew == NULL) {
				return -1;
			}
			prev->next = fdnew;
			fdt = fdnew;
		}

		while (fd < NOFILE && fdt->arr[fd] != NULL) {
			fd++;
		}

		if (fd == NOFILE) {
			fd = 0;
			base += NOFILE;
			fdt = fdt->next;
		} else {
			fdt->arr[fd] = f;
			fdt->used++;
			if (fd == fdt->nextfd) { // unfortunately, we need to update nextfd
				while (++fdt->nextfd < NOFILE) {
					if (fdt->arr[fdt->nextfd] == NULL) {
						break;
					}
				}
			}
			break;
		}
	}
	// __debug_info("fcntldup", "table %p base=%d, nextfd=%d, fd2=%d, fd=%d\n",
	// 							fdt, fdt->basefd, fdt->nextfd, fd2, fd);

	if (cloexec)
		fdt->exec_close |= (1 << fd);

	return base + fd;
}

struct inode *create(struct inode *dp, char *path, int mode)
{
	struct inode *ip;
	char name[MAXNAME + 1];
	struct dentry *de;

	if (dp != NULL && !S_ISDIR(dp->mode)) {
		__debug_warn("create", "create on file\n");
		return NULL;
	}

	if ((dp = nameiparentfrom(dp, path, name)) == NULL) {
		__debug_warn("create", "%s doesn't exist\n", path);
		// root doesn't have parent
		if (strncmp(path, "/", MAXPATH) != 0 || !S_ISDIR(mode))
			return NULL;
		dp = namei("/");
		ilock(dp);
		return dp;
	}

	ilock(dp);
	if (dp->state & I_STATE_FREE) {
		__debug_warn("create", "%s doesn't exist\n", path);
		iunlockput(dp);
		return NULL;
	}

	struct superblock *sb = dp->sb;
	acquire(&sb->cache_lock);
	de = dp->entry->op->cache(dp->entry, name);
	release(&sb->cache_lock);
	if (de != NULL) {
		iunlockput(dp);
		ip = idup(de->inode);
		if ((mode ^ ip->mode) & S_IFMT) { // unmatch file type
			iput(ip);
			__debug_warn("create", "%s exists in cache but type is wrong\n", path);
			ip = NULL;
		} else {
			ilock(ip);
		}
		return ip;
	}

	if ((de = kmalloc(sizeof(struct dentry))) == NULL) {
		iunlockput(dp);
		return NULL;
	}

	if ((ip = dp->op->create(dp, name, mode)) == NULL) {
		__debug_warn("create", "%s create fail\n", path);
		iunlockput(dp);
		kfree(de);
		return NULL;
	}

	idup(ip);
	ip->state = I_STATE_VALID;
	ip->entry = de;

	safestrcpy(de->filename, name, MAXNAME + 1);
	de->child = NULL;
	de->mount = NULL;
	de->inode = ip;
	de->op = dp->entry->op;

	acquire(&sb->cache_lock);
	de->parent = dp->entry;
	de->next = dp->entry->child;
	dp->entry->child = de;
	release(&sb->cache_lock);

	if ((mode ^ ip->mode) & S_IFMT) {
		iunlockput(dp);
		iput(ip);
		__debug_warn("create", "%s exists but type is wrong\n", path);
		return NULL;
	}

	iunlockput(dp);
	ilock(ip);

	return ip;
}

int unlink(struct inode *ip)
{
	struct superblock *sb;
	struct dentry *de = ip->entry;

	__debug_info("unlink", "unlink %s\n", de->filename);
	for (sb = &rootfs; sb != NULL; sb = sb->next) {
		if (sb->dev == ip) {
			__debug_warn("unlink", "%s is busy\n", de->filename);
			return -EBUSY;
		}
	}

	sb = ip->sb;
	if (de == sb->root) {
		__debug_warn("unlink", "try to unlink root\n");
		return -EACCES;
	}

	int ret = ip->op->unlink(ip);
	if (ret < 0) {
		__debug_warn("unlink", "fail\n");
		return ret;
	}

	acquire(&sb->cache_lock);
	// if (ip->nlink == 0) {
		// No other files link to ip
		ip->state |= I_STATE_FREE;
		// Remove the dentry from cache, but do not free it.
		de->op->delete(de);
	// }
	release(&sb->cache_lock);

	return ret;
}

struct inode *idup(struct inode *ip)
{
	acquire(&ip->sb->cache_lock);
	ip->sb->ref++;
	ip->ref++;
	release(&ip->sb->cache_lock);
	return ip;
}

void iput(struct inode *ip)
{
	// Lock the cache so that no one can get ip.
	struct superblock *sb = ip->sb;
	acquire(&sb->cache_lock);
	sb->ref--;
	if (ip->ref == 1) {
		// ref == 1 means no other process can have ip locked,
		// so this acquiresleep() won't block (or deadlock).
		acquiresleep(&ip->lock);
		release(&sb->cache_lock);

		// This file is removed, so its dentry should have been
		// deleted from the dentry tree.
		// This inode is invisible, just free it.
		if (ip->state & I_STATE_FREE) {
			if (ip->nlink == 0)
				ip->op->truncate(ip);
			kfree(ip->entry);
			sb->op.destroy_inode(ip);
			return;
		}
		else if (ip->state & I_STATE_DIRTY) {
			ip->op->update(ip);
		}
		releasesleep(&ip->lock);
		acquire(&sb->cache_lock);
	}
	ip->ref--;
	release(&sb->cache_lock);
}

void ilock(struct inode *ip)
{
	if (ip == 0 || ip->ref < 1)
		panic("ilock");
	acquiresleep(&ip->lock);
}

void iunlock(struct inode *ip)
{
	if (ip == 0 || !holdingsleep(&ip->lock) || ip->ref < 1)
		panic("iunlock");
	releasesleep(&ip->lock);
}

struct dentry *de_check_cache(struct dentry *parent, char *name)
{
	struct dentry *pde = NULL;
	struct dentry *de = parent->child;
	for (; de != NULL; pde = de, de = de->next) {          // LRU algo
		if (strncmp(de->filename, name, MAXNAME) == 0) {
			if (de != parent->child) {
				pde->next = de->next;
				de->next = parent->child;
				parent->child = de;
			}
			return de_mnt_in(de);
		}
	}
	return NULL;
}

int de_delete(struct dentry *de)
{
	// if (de->child != NULL)
	// 	panic("de_delete: has children");

	struct dentry **pde;
	for (pde = &de->parent->child; *pde != NULL; pde = &(*pde)->next) {
		if (*pde == de) {
			*pde = de->next;
			return 0;
		}
	}

	panic("de_delete: not in cache delete");
	return -1;
}

static void do_de_print(struct dentry *de, int level)
{
	struct dentry *child;
	for (child = de->child; child != NULL; child = child->next) {
		for (int i = 0; i < level; i++) {
			printf("\t");
		}
		printf(__INFO("%d")" %s\n", child->inode->ref, child->filename);
		do_de_print(child, level + 1);
		if (child->mount) {
			release(&child->inode->sb->cache_lock);
			de_print(child->mount, level);
			acquire(&child->inode->sb->cache_lock);
		}
	}
}

void de_print(struct superblock *sb, int level)
{
	acquire(&sb->cache_lock);

	struct dentry *root = sb->root;
	for (int i = 0; i < level; i++) {
		printf("\t");
	}
	if (sb->dev) {
		printf(__INFO("%d/%d")" %s mounted at %s\n",
			sb->ref, root->inode->ref, sb->dev->entry->filename, root->parent->filename);
	} else {
		printf(__INFO("%d/%d")" %s\n", sb->ref, root->inode->ref, root->filename);
	}
	do_de_print(root, level + 1);

	release(&sb->cache_lock);
}

void rootfs_print()
{
	printf("\n"__INFO("file tree")":\n");
	de_print(&rootfs, 0);
	if (rootfs.root->mount)
		de_print(rootfs.root->mount, 0);
}

struct inode *dirlookup(struct inode *dir, char *filename, uint *poff)
{
	if (!S_ISDIR(dir->mode))
		panic("dirlookup");

	__debug_info("dirlookup", "start searching %s\n", filename);
	struct superblock *sb = dir->sb;
	struct dentry *de, *parent;
	if (strncmp(filename, ".", MAXNAME) == 0) {
		de = de_mnt_in(dir->entry);
		return idup(de->inode);
	}
	else if (strncmp(filename, "..", MAXNAME) == 0) {
		de = dir->entry;
		while (de == sb->root) { // It indicates that de is a root and may be a mount point.
			de = de->parent;
			if (de == NULL) { // Meet root of rootfs.
				de = sb->root;
				break;
			}
			sb = de->inode->sb;
		}
		de = de_mnt_in(de->parent == NULL ? de : de->parent); // Now we found the real parent.
		return idup(de->inode);
	}

	__debug_info("dirlookup", "checking cache\n");
	acquire(&sb->cache_lock);
	de = dir->entry->op->cache(dir->entry, filename);
	release(&sb->cache_lock);
	if (de != NULL) {
		__debug_info("dirlookup", "cache hit: %s\n", filename);
		return idup(de->inode);
	}

	__debug_info("dirlookup", "look up on disk: %s\n", filename);
	if ((de = kmalloc(sizeof(struct dentry))) == NULL) {
		return NULL;
	}

	struct inode *ip = dir->op->lookup(dir, filename, poff);
	if (ip == NULL) {
		__debug_warn("dirlookup", "file not found: %s\n", filename);
		kfree(de);
		return NULL;
	}
	__debug_info("dirlookup", "found: %s\n", filename);

	idup(ip);
	ip->entry = de;
	ip->state = I_STATE_VALID;

	safestrcpy(de->filename, filename, MAXNAME + 1);
	de->child = NULL;
	de->mount = NULL;
	de->inode = ip;
	de->op = dir->entry->op;

	acquire(&sb->cache_lock);
	parent = dir->entry;
	de->parent = parent;
	de->next = parent->child;
	parent->child = de;
	release(&sb->cache_lock);

	return ip;
}

static char *skipelem(char *path, char *name, int max)
{
	while (*path == '/') {
		path++;
	}
	if (*path == 0) { return NULL; }
	char *s = path;
	while (*path != '/' && *path != 0) {
		path++;
	}
	int len = path - s;
	if (len > max) {
		len = max;
	}
	name[len] = 0;
	memmove(name, s, len);
	while (*path == '/') {
		path++;
	}
	return path;
}

static struct inode *lookup_path(struct inode *ip, char *path, int parent, char *name)
{
	struct inode *next;
	if (*path == '/') {
		if (strncmp(path, "/proc/self/exe", 15) == 0) {
			struct proc *p = myproc();
			if (p->elf) return idup(p->elf);
			return NULL;
		}
		ip = de_mnt_in(rootfs.root)->inode;
		ip = idup(ip);
	} else if (*path != '\0') {
		if (ip != NULL)
			ip = idup(ip);
		else {
			ip = idup(myproc()->cwd);
		}
	} else {
		__debug_warn("lookup_path", "path invalid\n");
		return NULL;
	}

	while ((path = skipelem(path, name, MAXNAME)) != 0) {
		__debug_info("lookup_path", "lookup: %s\n", name);
		ilock(ip);
		if (!S_ISDIR(ip->mode)) {
			iunlockput(ip);
			return NULL;
		}
		if (parent && *path == '\0') {
			iunlock(ip);
			return ip;
		}
		if ((next = dirlookup(ip, name, 0)) == NULL) {
			iunlockput(ip);
			__debug_warn("lookup_path", "dirlookup returns a NULL\n");
			return NULL;
		}
		__debug_info("lookup_path", "found: %s\n", next->entry->filename);
		iunlockput(ip);
		ip = next;
	}
	if (parent) {
		iput(ip);
		return NULL;
	}
	__debug_info("lookup_path", "finally: %s\n", ip->entry->filename);
	return ip;
}

struct inode *namei(char *path)
{
	char name[MAXNAME + 1];
	return lookup_path(NULL, path, 0, name);
}

struct inode *nameiparent(char *path, char *name)
{
	return lookup_path(NULL, path, 1, name);
}

struct inode *nameifrom(struct inode *ip, char *path)
{
	char name[MAXNAME + 1];
	return lookup_path(ip, path, 0, name);
}

struct inode *nameiparentfrom(struct inode *ip, char *path, char *name)
{
	return lookup_path(ip, path, 1, name);
}

int namepath(struct inode *ip, char *path, int max)
{
	// if (max < 2)
	// 	panic("namepath: what do you want from me by a max less than 2");

	struct superblock *sb = ip->sb;
	struct dentry *de = ip->entry;

	int len;
	char *p = path + max - 1;
	*p = '\0';

	acquire(&sb->cache_lock);

	while (de == sb->root) {	// test mount
		release(&sb->cache_lock);
		if (sb == &rootfs) {	// Meet root of rootfs.
			safestrcpy(path, rootfs.root->filename, max);	
			return strlen(rootfs.root->filename) + 1;
		}
		de = de->parent;
		sb = de->inode->sb;
		acquire(&sb->cache_lock);
	}

	for (;;) {
		while (de == sb->root) { // It indicates that de is a root and may be a mount point.
			if ((de = de->parent) == NULL) { // Meet root of rootfs.
				break;
			}
			release(&sb->cache_lock);
			sb = de->inode->sb;
			acquire(&sb->cache_lock);
		}
		if (de == NULL)
			break;
		len = strlen(de->filename);
		if ((p -= len) <= path) {
			release(&sb->cache_lock);
			return -1;
		}
		memmove(p, de->filename, len);
		*--p = '/';
		de = de->parent;
	}
	release(&sb->cache_lock);

	len = max - (p - path);
	memmove(path, p, len);		// memmove will handle overlap

	return len;
}

int isdirempty(struct inode *dp)
{
	if (dp->entry->child)
		return 0;

	struct dirent dent;
	int off = 0, ret;
	while (1) {
		ret = dp->fop->readdir(dp, &dent, off);
		if (ret < 0)
			return -1;
		else if (ret == 0)
			return 1;
		else if ((dent.name[0] == '.' && dent.name[1] == '\0') ||     // skip the "." and ".."
				 (dent.name[0] == '.' && dent.name[1] == '.' && dent.name[2] == '\0'))
		{
			off += ret;
		}
		else
			return 0;
	}
}

int do_rename(struct inode *iold, struct inode *dstdir, char *newname)
{
	if (iold->sb != dstdir->sb)
		return -EXDEV;
	if (!dstdir->op->rename)
		return -EACCES;

	int ret = 0;
	struct inode *inew = NULL;
	// lock dstdir to check newname and avoid creating
	ilock(dstdir);
	if (trysleeplock(&iold->lock) < 0) { // just try, in case of deadlock
		iunlock(dstdir);
		return -EBUSY;
	}

	// In what universe can we move a directory into its child?
	acquire(&iold->sb->cache_lock);
	for (struct dentry *de = dstdir->entry; de != NULL; de = de->parent)
		if (de == iold->entry) {
			release(&iold->sb->cache_lock);
			ret = -EINVAL;
			goto end;
		}
	release(&iold->sb->cache_lock);

	if ((inew = dirlookup(dstdir, newname, NULL)) != NULL) {	// new exists
		if (trysleeplock(&inew->lock) < 0) {
			iput(inew);
			inew = NULL;
			ret = -EBUSY;
			goto end;
		}
		if (S_ISDIR(inew->mode)) {			// it's ok to overwrite an empty dir
			if (!S_ISDIR(iold->mode)) {
				ret = -EISDIR;
				goto end;
			} else if (isdirempty(inew) != 1) {
				ret = -EEXIST;
				goto end;
			}
			if (unlink(inew) < 0) {
				ret = -EBUSY;
				goto end;
			}
			iunlockput(inew);
			inew = NULL;
		} else {
			ret = -EEXIST;
			goto end;
		}
	}

	ret = dstdir->op->rename(iold, dstdir, newname);
	if (ret < 0) {
		goto end;
	}

	struct dentry *oldent, *dstent;
	oldent = iold->entry;
	dstent = dstdir->entry;

	acquire(&iold->sb->cache_lock);
	de_delete(oldent);
	oldent->parent = dstent;
	oldent->next = dstent->child;
	dstent->child = oldent;
	release(&iold->sb->cache_lock);

end:
	iunlock(iold);
	iunlock(dstdir);
	if (inew)
		iunlockput(inew);
	return ret;
}

void syncfs(void)
{
	struct superblock *sb;
	acquire(&rootfs.cache_lock);
	for (sb = rootfs.next; sb != NULL; sb = sb->next) {
		if (sb->op.sync) {
			release(&rootfs.cache_lock);
			sb->op.sync(sb);
			acquire(&rootfs.cache_lock);
		}
	}
	release(&rootfs.cache_lock);
}

