int do_mount(struct inode *dev, struct inode *mntpoint, char *type, int flag, void *data)
{
	if (strncmp("vfat", type, 5) != 0 &&
		strncmp("fat32", type, 6) != 0)
	{
		__debug_warn("do_mount", "Unsupported fs type: %s\n", type);
		return -1;
	}
	// if (mntpoint->entry == rootfs.root) {
	// 	__debug_warn("do_mount", "can not mount at \"/\"\n");
	// 	return -1;
	// }

	__debug_info("do_mount", "dev:%s mntpnt:%s\n", dev->entry->filename, mntpoint->entry->filename);

	if (S_ISDIR(dev->mode) || !S_ISDIR(mntpoint->mode)) {
		__debug_warn("do_mount", "Error file type: dev:%x mntpoint:%x\n",
			dev->mode, mntpoint->mode);
		return -ENOTBLK;
	}

	struct dentry *dmnt = mntpoint->entry;
	// We planed only to support one mount at a time.
	// But in fact, if mntpoint is mounted, namei will get its mounting dev,
	// so this could be a root of a fs, at which can be mounted.
	if (dmnt->mount != NULL) {
		__debug_error("do_mount", "%s is already be mounted\n", dmnt->filename);
		panic("do_mount");
	}

	struct superblock *sb;
	sb = fs_install(dev);
	if (sb == NULL)
		return -1;

	acquire(&rootfs.cache_lock); // borrow this lock

	struct superblock *psb = &rootfs;
	while (psb->next != NULL)
		psb = psb->next;
	psb->next = sb;
	sb->root->parent = dmnt;
	safestrcpy(sb->root->filename, dmnt->filename, sizeof(dmnt->filename));
	safestrcpy(sb->type, type, sizeof(sb->type));
	dmnt->mount = sb;

	release(&rootfs.cache_lock);

	idup(mntpoint);

	return 0;
}

int do_umount(struct inode *mntpoint, int flag)
{
	if (!S_ISDIR(mntpoint->mode)) {
		__debug_warn("do_umount", "try to umount file: %s\n", mntpoint->entry->filename);
		return -ENOTDIR;
	}

	struct superblock *sb = mntpoint->sb;
	if (mntpoint->entry != sb->root || sb == &rootfs || sb == &devfs || sb == &procfs) {
		__debug_warn("do_umount", "%s is not a mount point\n", mntpoint->entry->filename);
		return -1;
	}

	struct dentry *de = mntpoint->entry;
	struct superblock *sb_prnt = NULL;
	do { // Look up parent of the mount point.
		de = de->parent;
		if (de == NULL) { // Meet root of rootfs.
			break;
		}
		sb_prnt = de->inode->sb;
	} while (de == sb_prnt->root);

	// Lock parent to block cache check.
	acquire(&sb_prnt->cache_lock);
	// Check whether only we hold this ref.
	if (sb->ref > 1) {
		__debug_warn("do_umount", "mount point is busy\n");
		release(&sb_prnt->cache_lock);
		return -EBUSY;
	}
	// Unmount from dentry tree.
	de = mntpoint->entry;
	de->parent->mount = NULL;
	release(&sb_prnt->cache_lock);

	// Put the inode it mounts at.
	iput(de->parent->inode);

	// Remove from superblock list.
	acquire(&rootfs.cache_lock);
	sb_prnt = &rootfs;
	while (sb_prnt->next != sb)
		sb_prnt = sb_prnt->next;
	sb_prnt->next = sb->next;
	release(&rootfs.cache_lock);

	fs_uninstall(sb);

	return 0;
}

int mountsysfs(struct superblock *sb, struct inode *mntpoint, char *type)
{
	if (!S_ISDIR(mntpoint->mode))
		return -1;

	acquire(&rootfs.cache_lock); // borrow this lock

	struct superblock *psb = &rootfs;
	while (psb->next != NULL)
		psb = psb->next;
	psb->next = sb;

	struct dentry *dmnt = mntpoint->entry;
	sb->root->parent = dmnt;
	safestrcpy(sb->root->filename, dmnt->filename, sizeof(dmnt->filename));
	safestrcpy(sb->type, type, sizeof(sb->type));
	dmnt->mount = sb;

	release(&rootfs.cache_lock);

	idup(mntpoint);
	return 0;
}

int
pipealloc(struct file **pf0, struct file **pf1)
{
	struct pipe *pi = NULL;
	struct file *f0, *f1 = NULL;

	if ((f0 = filealloc()) == NULL ||
		(f1 = filealloc()) == NULL ||
		(pi = kmalloc(sizeof(struct pipe))) == NULL)
	{
		goto bad;
	}

	pi->readopen = 1;
	pi->writeopen = 1;
	pi->nwrite = 0;
	pi->nread = 0;

	initlock(&pi->lock, "pipe");
	wait_queue_init(&pi->wqueue, "pipewritequeue");
	wait_queue_init(&pi->rqueue, "pipereadqueue");

	f0->type = FD_PIPE;
	f0->readable = 1;
	f0->writable = 0;
	f0->pipe = pi;
	f0->poll = pipepoll;

	f1->type = FD_PIPE;
	f1->readable = 0;
	f1->writable = 1;
	f1->pipe = pi;
	f1->poll = pipepoll;

	*pf0 = f0;
	*pf1 = f1;
	return 0;

 bad:
	if (pi)
		kfree(pi);
	if (f0)
		fileclose(f0);
	if (f1)
		fileclose(f1);
	*pf0 = *pf1 = NULL;
	return -ENOMEM;
}

static void pipelock(struct pipe *pi, struct wait_node *wait, int who)
{
	struct wait_queue *q;
	q = (who == PIPE_READER) ? &pi->rqueue : &pi->wqueue;

	acquire(&q->lock);
	wait_queue_add(q, wait);	// stay in line

	// whether we are the first arrival
	while (!wait_queue_is_first(q, wait)) {
		sleep(wait->chan, &q->lock);
	}
	release(&q->lock);
}

static void pipeunlock(struct pipe *pi, struct wait_node *wait, int who)
{
	struct wait_queue *q;
	q = (who == PIPE_READER) ? &pi->rqueue : &pi->wqueue;

	acquire(&q->lock);
	if (wait_queue_empty(q))
		panic("pipeunlock: empty queue");

	if (wait != wait_queue_next(q))
		panic("pipeunlock: not next");

	wait_queue_del(wait);			// walk out the queue
	if (!wait_queue_empty(q)) {		// wake up the next one
		wait = wait_queue_next(q);
		wakeup(wait->chan);
	}
	release(&q->lock);
}

static void pipewakeup(struct pipe *pi, int who)
{
	struct wait_queue *queue;

	queue = (who == PIPE_READER) ? &pi->rqueue : &pi->wqueue;
	acquire(&queue->lock);
	if (!wait_queue_empty(queue)) {
		struct wait_node *wno = wait_queue_next(queue);
		wakeup(wno->chan);
	}
	release(&queue->lock);
}

void
pipeclose(struct pipe *pi, int writable)
{
	acquire(&pi->lock);
	if (writable) {
		pi->writeopen = 0;
		pipewakeup(pi, PIPE_READER);
	} else {
		pi->readopen = 0;
		pipewakeup(pi, PIPE_WRITER);
	}
	if (pi->readopen == 0 && pi->writeopen == 0) {
		release(&pi->lock);
		kfree(pi);
	} else
		release(&pi->lock);
}

static int pipewritable(struct pipe *pi)
{
	struct proc *pr = myproc();
	struct wait_node *wait;
	int m;

	/**
	 * We are the first one in the queue, and that's why
	 * we can be in this function, so we are safe to read
	 * our wait_node without locking.
	 */
	wait = wait_queue_next(&pi->wqueue);

	/**
	 * It is not atomic visit that we hold this lock for.
	 * The writer and reader will not change the opposite
	 * fields, we don't worry about it.
	 * First, this lock helps us get through the sleep().
	 * Second, if it is the moment when we are on our way
	 * to sleep() that the other end is trying to wake us
	 * up, then we might miss this wakeup().
	 * In a word, when waking up the other end, hold pi->lock.
	 */
	acquire(&pi->lock);
	while ((m = pi->nwrite - pi->nread) == PIPESIZE) {		// pipe is full
		if (pi->readopen == 0 || pr->killed) {
			m = -1;
			break;
		}
		pipewakeup(pi, PIPE_READER);
		sleep(wait->chan, &pi->lock);
	}
	release(&pi->lock);
	return m;
}

static int pipereadable(struct pipe *pi)
{
	struct proc *pr = myproc();
	struct wait_node *wait;
	int m;

	// Need no lock here. See pipewritable().
	wait = wait_queue_next(&pi->rqueue);

	acquire(&pi->lock);
	while ((m = pi->nwrite - pi->nread) == 0 && pi->writeopen) {	// pipe is empty
		if (pr->killed) {
			m = -1;
			break;
		}
		sleep(wait->chan, &pi->lock);
	}
	release(&pi->lock);
	return m;
}

int
pipewrite(struct pipe *pi, uint64 addr, int n)
{
	int i, m;
	char *const pipebound = pi->data + PIPESIZE;
	struct wait_node wait;

	// pwait = waitinit(&wait);
	wait.chan = &wait;
	pipelock(pi, &wait, PIPE_WRITER);		// block other writers
	for (i = 0; i < n;) {
		if ((m = pipewritable(pi)) < 0) {
			i = -EPIPE;
			goto out;
		}
		m = (PIPESIZE - m < n - i) ?	// amount of bytes to write
			PIPESIZE - m : n - i;

		while (m > 0) {					// pipe is a loop in a buf
			char *paddr = pi->data + pi->nwrite % PIPESIZE;
			int count = (pipebound - paddr < m) ? pipebound - paddr : m;

			if (copyin_nocheck(paddr, addr + i, count) < 0)
				break;
			i += count;
			pi->nwrite += count;
			m -= count;
		}
		if (m > 0)
			break;
	}
	acquire(&pi->lock);		// see pipewritable()
	pipewakeup(pi, PIPE_READER);
	release(&pi->lock);
out:
	pipeunlock(pi, &wait, PIPE_WRITER);
	// __debug_info("pipewrite", "written %d/%d\n", i, n);
	return i;
}

int
piperead(struct pipe *pi, uint64 addr, int n)
{
	int i = -1, m;
	char *const pipebound = pi->data + PIPESIZE;
	struct wait_node wait;

	// pwait = waitinit(&wait);
	wait.chan = &wait;
	pipelock(pi, &wait, PIPE_READER);	// block other readers

	if ((m = pipereadable(pi)) < 0) {
		goto out;
	}
	if (m > n)
		m = n;
	for (i = 0; i < m;) {
		char *paddr = pi->data + pi->nread % PIPESIZE;
		int count = (pipebound - paddr < m - i) ? pipebound - paddr : m - i;

		if (copyout_nocheck(addr + i, paddr, count) < 0)
			break;
		pi->nread += count;
		i += count;
	}
	acquire(&pi->lock);		// see pipewritable()
	pipewakeup(pi, PIPE_WRITER);
	release(&pi->lock);
out:
	pipeunlock(pi, &wait, PIPE_READER);
	// __debug_info("piperead", "read %d\n", i);
	return i;
}

int pipewritev(struct pipe *pi, struct iovec ioarr[], int count)
{
	int ret = 0;
	char *const pipebound = pi->data + PIPESIZE;
	struct wait_node wait;

	// pwait = waitinit(&wait);
	wait.chan = &wait;
	pipelock(pi, &wait, PIPE_WRITER);	// block other writers

	for (int i = 0; i < count; i++) {
		uint64 addr = (uint64)ioarr[i].iov_base;
		uint64 n = ioarr[i].iov_len;
		int j;

		if (!rangeinseg(addr, addr + n))
			break;
		for (j = 0; j < n;) {
			int m = pipewritable(pi);
			if (m < 0) {
				ret = -EPIPE;
				goto out2;
			}
			m = (PIPESIZE - m < n - j) ? PIPESIZE - m : n - j;		// amount of bytes to write
			while (m > 0) {							// pipe is a loop in a buf
				char *paddr = pi->data + pi->nwrite % PIPESIZE;
				int cnt = (pipebound - paddr < m) ? pipebound - paddr : m;

				if (copyin_nocheck(paddr, addr + j, cnt) < 0)
					goto out1;
				m -= cnt;
				j += cnt;
				pi->nwrite += cnt;
				ret += cnt;
			}
		}
	}
out1:
	acquire(&pi->lock);		// see pipewritable()
	pipewakeup(pi, PIPE_READER);
	release(&pi->lock);
out2:
	pipeunlock(pi, &wait, PIPE_WRITER);
	return ret;
}

int pipereadv(struct pipe *pi, struct iovec ioarr[], int count)
{
	int ndata, ret = 0;
	char *const pipebound = pi->data + PIPESIZE;
	struct wait_node wait;

	// pwait = waitinit(&wait);
	wait.chan = &wait;
	pipelock(pi, &wait, PIPE_READER);	// block other readers

	if ((ndata = pipereadable(pi)) < 0) {
		ret = -EPIPE;
		goto out2;
	}
	for (int i = 0; i < count && ndata > 0; i++) {
		uint64 addr = (uint64)ioarr[i].iov_base;
		uint64 n = ioarr[i].iov_len;
		int m = n < ndata ? n : ndata;
		int j;

		if (!rangeinseg(addr, addr + n))
			break;
		for (j = 0; j < m;) {
			char *paddr = pi->data + pi->nread % PIPESIZE;
			int cnt = (pipebound - paddr < m - j) ? pipebound - paddr : m - j;

			if (copyout_nocheck(addr + j, paddr, cnt) < 0)
				goto out1;
			pi->nread += cnt;
			j += cnt;
			ret += cnt;
			ndata -= cnt;
		}
	}
out1:
	acquire(&pi->lock);		// see pipewritable()
	pipewakeup(pi, PIPE_WRITER);
	release(&pi->lock);
out2:
	pipeunlock(pi, &wait, PIPE_READER);
	return ret;
}

static
uint32 pipepoll(struct file *fp, struct poll_table *pt)
{
	uint32 mask = 0;
	struct pipe *pi = fp->pipe;

	__debug_info("pipepoll", "r/w=%d/%d | ro/wo=%d/%d | rq/wq=%d/%d rn/wn=%d/%d\n",
				fp->readable, fp->writable, pi->readopen, pi->writeopen,
				!wait_queue_empty(&pi->rqueue), !wait_queue_empty(&pi->wqueue),
				pi->nread, pi->nwrite);

	if (fp->readable)
		poll_wait(fp, &pi->rqueue, pt);
	if (fp->writable)
		poll_wait(fp, &pi->wqueue, pt);

	if (fp->readable) {
		if (pi->nwrite - pi->nread > 0)			// has something to read
			mask |= POLLIN;
		if (!pi->writeopen) {
			// if (pi->nwrite - pi->nread == 0)
			// 	mask |= POLLPRI;
			// else
				mask |= POLLHUP;
		}
	}

	if (fp->writable) {
		if (pi->nwrite - pi->nread < PIPESIZE)	// has room to write
			mask |= POLLOUT;
		if (!pi->readopen)
			mask |= POLLERR;
	}

	return mask;
}

static void __poll_func(struct file *f, struct wait_queue *wq, struct poll_table *pt)
{
	struct poll_wait_queue *pwq = container_of(pt, struct poll_wait_queue, pt);
	struct poll_wait_node *pwn;
	if (pwq->index >= ON_STACK_PWN_NUM)	// we can allocate pages
		return;

	pwn = &pwq->nodes[pwq->index++];
	pwn->node.chan = pwq;
	pwn->queue = wq;
	wait_queue_add_locked(wq, &pwn->node);
}

static void poll_init(struct poll_wait_queue *pwq)
{
	pwq->pt.func = __poll_func;
	pwq->pt.key = 0;
	pwq->error = 0;
	pwq->index = 0;
}

static void poll_end(struct poll_wait_queue *pwq)
{
	for (int i = 0; i < pwq->index; i++) {
		struct poll_wait_node *pwn = pwq->nodes + i;
		struct wait_queue *wq = pwn->queue;
		acquire(&wq->lock);
		wait_queue_del(&pwn->node);
		if (!wait_queue_empty(wq)) {
			struct wait_node *node = wait_queue_next(wq);
			wakeup(node->chan);
		}
		release(&wq->lock);
	}
}

static uint32 file_poll(struct file *fp, struct poll_table *pt)
{
	if (!fp->poll)
		return POLLIN|POLLOUT;
	return fp->poll(fp, pt);
}

static int poll_sched_timeout(struct poll_wait_queue *pwq, uint64 expire)
{
	struct proc *p = myproc();
	struct proc *volatile vp = p;
	int ret = 0;

	acquire(&p->lk);	// Hold this for sleep().

	p->sleep_expire = expire;
	sleep(pwq, &p->lk);

	// Check whether we are waken up by timeout.
	// If so, this field will be set to zero.
	if (vp->sleep_expire == 0)
		ret = 1;
	else
		p->sleep_expire = 0;
	release(&p->lk);

	__debug_info("poll_sched_timeout", "pwq=%p, ret=%d\n", pwq, ret);

	return ret;
}

int ppoll(struct pollfd *pfds, int nfds, struct timespec *timeout, __sigset_t *sigmask)
{
	// uint64 now = readtime();
