static inline void fdset_work_init(struct fdset *rfds, struct fdset *wfds, struct fdset *exfds,
							struct fdset *rarg, struct fdset *warg, struct fdset *exarg)
{
	if (rarg)
		memmove(rfds, rarg, sizeof(struct fdset));
	else
		memset(rfds, 0, sizeof(struct fdset));

	if (warg)
		memmove(wfds, warg, sizeof(struct fdset));
	else
		memset(wfds, 0, sizeof(struct fdset));

	if (exarg)
		memmove(exfds, exarg, sizeof(struct fdset));
	else
		memset(exfds, 0, sizeof(struct fdset));
}

int pselect(int nfds, struct fdset *readfds, struct fdset *writefds, struct fdset *exceptfds,
			struct timespec *timeout, __sigset_t *sigmask)
{
	struct fdset rfds, wfds, exfds;
	uint64 expire;
	struct poll_wait_queue wait;
	// struct poll_wait_queue *pwait;
	int immediate = 0;


	__debug_info("pselect", "timeout={%ds, %dns}\n", 
				timeout ? timeout->sec : -1, timeout ? timeout->nsec : -1);

	if (timeout) {
		expire = convert_from_timespec(timeout);
		if (expire == 0)
			immediate = 1;			// don't sleep
		else 
			expire += readtime();	// overflow?
	} else
		expire = 0;					// infinity

	fdset_work_init(&rfds, &wfds, &exfds, readfds, writefds, exceptfds);

	// Since the node is on stack, if we want other process to get us, we should use pa.
	// pwait = (struct poll_wait_queue *)kwalkaddr(myproc()->pagetable, (uint64)&wait);
	// pwait = &wait;
	poll_init(&wait);
	if (immediate)
		wait.pt.func = NULL;		// we won't be inserted into any queue in later poll()s

	int ret = 0;
	for (;;)
	{
		int i = 0;	// fd iterator
		for (int idx = 0; idx <= (nfds - 1) / NFDBIT; idx++)
		{
			uint64 r, w, ex, all;
			uint64 rres = 0, wres = 0, exres = 0;

			r = rfds.fd_bits[idx];		// extract fd bits
			w = wfds.fd_bits[idx];
			ex = exfds.fd_bits[idx];
			all = r | w | ex;
			if (all == 0) {				// no fd in this part
				i += NFDBIT;
				continue;
			}

			for (int b = 0; b < NFDBIT; b++, i++) {
				if (i >= nfds)			// reach end
					break;
				uint64 bit = 1L << b;
				if (!(bit & all))		// no fd in this bit
					continue;

				struct file *fp = fd2file(i, 0);
				if (!fp)				// bad fd
					continue;

				__debug_info("pselect", "fd=%d\n", i);

				wait.pt.key = POLLEX_SET;
				if (r & bit)
					wait.pt.key |= POLLIN_SET;
				if (w & bit)
					wait.pt.key |= POLLOUT_SET;

				uint32 mask = file_poll(fp, &wait.pt);
				__debug_info("pselect", "mask=%d\n", mask);

				if ((mask & POLLIN_SET) && (r & bit)) {
					rres |= bit;
					ret++;
					wait.pt.func = NULL;
				}
				if ((mask & POLLOUT_SET) && (w & bit)) {
					wres |= bit;
					ret++;
					wait.pt.func = NULL;
				}
				if ((mask & POLLEX_SET) && (ex & bit)) {
					exres |= bit;
					ret++;
					wait.pt.func = NULL;
				}
			}
			if (readfds)
				readfds->fd_bits[idx] = rres;
			if (writefds)
				writefds->fd_bits[idx] = wres;
			if (exceptfds)
				exceptfds->fd_bits[idx] = exres;
		}
		wait.pt.func = NULL;		// only need to be called once for each file

		if (ret > 0 || immediate)	// got results or don't sleep-wait
			break;
		if (wait.error) {
			ret = wait.error;
			break;
		}

		// at this point, maybe we are already waken up by some
		if (poll_sched_timeout(&wait, expire))
			immediate = 1;
		if (myproc()->killed) {
			immediate = 1;
			wait.error = -EINTR;
		}
	}

	poll_end(&wait);

	__debug_info("pselect", "return %d\n", ret);
	return ret;
}

static int rootfs_getattr(struct inode *ip, struct kstat *st)
{
	memset(st, 0, sizeof(struct kstat));
	st->blksize = ip->sb->blocksz;
	st->size = ip->size;
	st->blocks = (st->size + st->blksize - 1) / st->blksize;
	st->dev = ip->sb->devnum;
	st->rdev = ip->dev;
	st->ino = ip->inum;
	st->mode = ip->mode;
	st->nlink = ip->nlink;
	return 0;
}

int root_file_readdir(struct inode *dp, struct dirent *dent, uint off)
{
	struct dentry *entry = dp->entry;
	if (!S_ISDIR(dp->mode))
		return -1;

	int childnum = off >> 5;
	acquire(&rootfs.cache_lock);
	struct dentry *child;
	for (child = entry->child; child != NULL && childnum > 0; child = child->next)
	{
		childnum--;
	}
	release(&rootfs.cache_lock);

	if (!child)
		return 0;

	struct inode *ip = child->inode;
	safestrcpy(dent->name, child->filename, 128);
	int size = sizeof(struct dirent) - sizeof(dent->name) + strlen(dent->name) + 1;
	size += (sizeof(uint64) - (size % sizeof(uint64))) % sizeof(uint64); // Align to 8.
	dent->ino = ip->inum;
	dent->off = off;
	dent->reclen = size;
	dent->type = S_ISDIR(ip->mode) ? T_DIR : (ip->dev ? T_DEVICE : T_FILE);
	return 32;
}

int zero_read(struct inode *ip, int usr, uint64 dst, uint off, uint n)
{
#define ZBUFSZ		128
#define ZBIGBUFSZ	512

	uint bufsz = ZBUFSZ;
	char sbuf[ZBUFSZ];
	char *buf = sbuf;

	if (n > ZBUFSZ * 8) {
		buf = kmalloc(ZBIGBUFSZ);
		if (buf == NULL)
			buf = sbuf;
		else
			bufsz = ZBIGBUFSZ;
	}

	memset(buf, 0, bufsz);

	uint tot, m = bufsz;
	for (tot = 0; tot < n; tot += m, dst += m) {
		if (n - tot < m)
			m = n - tot;
		if (either_copyout_nocheck(usr, dst, buf, m) < 0)
			break;
	}

	if (bufsz == ZBIGBUFSZ)
		kfree(buf);

	return tot;
}

