static struct dentry *de_rootfs_cache(struct dentry *parent, char *name)
{
	struct dentry *de;
	for (de = parent->child; de != NULL; de = de->next) {
		if (strncmp(de->filename, name, MAXNAME) == 0) {
			return de_mnt_in(de);
		}
	}
	return NULL;
}

static struct dentry *de_root_generate(struct superblock *sb,
							struct dentry *parent, char *name,
							int inum, int mode, int devnum)
{
	struct dentry *de;
	struct inode *ip;
	if ((de = kmalloc(sizeof(struct dentry))) == NULL ||
		(ip = kmalloc(sizeof(struct inode))) == NULL)
	{
		__debug_warn("de_root_generate", "fail\n");
		if (de)
			kfree(de);
		return NULL;
	}
	memset(de, 0, sizeof(struct dentry));
	memset(ip, 0, sizeof(struct inode));

	// insert those files into root's dentry tree
	de->inode = ip;
	de->op = &rootfs_dentry_op;
	ip->entry = de;
	ip->sb = sb;

	if (parent) {
		de->next = parent->child;
		parent->child = de;
		de->parent = parent;
	}

	ip->inum = inum;
	ip->dev = devnum;
	ip->op = &rootfs_inode_op;
	ip->fop = &rootfs_file_op;
	ip->state = I_STATE_VALID;	// not necessary
	ip->mode = mode;
	ip->nlink = 1;

	initsleeplock(&ip->lock, "inode");
	initlock(&ip->ilock, "inode2");
	safestrcpy(de->filename, name, MAXNAME);
	__debug_info("de_root_generate", "done\n");

	return de;
}

void rootfs_init()
{
	__debug_info("rootfs_init", "enter\n");

	int inum = 0;

	// init rootfs
	memset(&rootfs, 0, sizeof(struct superblock));
	initsleeplock(&rootfs.sb_lock, "rootfs_sb");
	initlock(&rootfs.cache_lock, "rootfs_dcache");

	if ((rootfs.root = de_root_generate(&rootfs, NULL, "/", inum++, S_IFDIR, 0)) == NULL)
		panic("rootfs_init: /");

	// init devfs
	struct dentry *con, *vda, *zero, *null;
	memset(&devfs, 0, sizeof(struct superblock));
	initsleeplock(&devfs.sb_lock, "devfs_sb");
	initlock(&devfs.cache_lock, "devfs_dcache");
	if ((devfs.root = de_root_generate(&devfs, NULL, "/", inum++, S_IFDIR, 0)) == NULL)
		panic("rootfs_init: devfs /");
	if ((con = de_root_generate(&devfs, devfs.root, "console", inum++, S_IFCHR, 2)) == NULL)
		panic("rootfs_init: devfs console");
	if ((vda = de_root_generate(&devfs, devfs.root, "vda2", inum++, S_IFBLK, ROOTDEV)) == NULL)
		panic("rootfs_init: devfs vda2");
	if ((zero = de_root_generate(&devfs, devfs.root, "zero", inum++, S_IFCHR, 3)) == NULL)
		panic("rootfs_init: devfs zero");
	if ((null = de_root_generate(&devfs, devfs.root, "null", inum++, S_IFCHR, 4)) == NULL)
		panic("rootfs_init: devfs null");

	extern struct file_op console_op;
	con->inode->fop = &console_op;

	zero->inode->fop = &zero_op;
	null->inode->fop = &null_op;

	// init procfs
	struct dentry *mount;
	memset(&procfs, 0, sizeof(struct superblock));
	initsleeplock(&procfs.sb_lock, "procfs_sb");
	initlock(&procfs.cache_lock, "procfs_dcache");
	if ((procfs.root = de_root_generate(&procfs, NULL, "/", inum++, S_IFDIR, 0)) == NULL)
		panic("rootfs_init: procfs /");
	if ((mount = de_root_generate(&procfs, procfs.root, "mounts", inum++, S_IFREG, 0)) == NULL)
		panic("rootfs_init: procfs mounts");
	if (de_root_generate(&procfs, procfs.root, "meminfo", inum++, S_IFREG, 0) == NULL)
		panic("rootfs_init: procfs meminfo");

	// AAA1 solution2
	if ((entry_INT = de_root_generate(&procfs, procfs.root, "interrupts", inum++, S_IFREG, 0)) == NULL)
		panic("rootfs_init: procfs meminfo");
	proc_INT = entry_INT->inode;
	proc_INT->fop = &intr_file_op;
	// AAA


	extern struct file_op mountinfo_fop;
	mount->inode->fop = &mountinfo_fop;

	// mount disk
	if (do_mount(vda->inode, rootfs.root->inode, "fat32", 0, 0) < 0)
		panic("rootfs_init: mount disk");

	// make directories and mount
	struct inode *dir;

	if ((dir = create(NULL, "/dev", S_IFDIR)) == NULL)
		panic("rootfs_init: on disk /dev");
	if (mountsysfs(&devfs, dir, "devfs") < 0)
		panic("rootfs_init: mount devfs");
	iunlockput(dir);

	if ((dir = create(NULL, "/proc", S_IFDIR)) == NULL)
		panic("rootfs_init: on disk /proc");
	if (mountsysfs(&procfs, dir, "procfs") < 0)
		panic("rootfs_init: mount procfs");

	struct inode *store = dir;

	/* // solution1
	if ((dir = create(NULL, "/proc/interrupts", S_IFREG)) != NULL){
		proc_INT = dir;
	}
	else{
		panic("rootfs_init: on disk /proc/interrupts");
	}*/
	//iunlockput(dir);
	iunlockput(store);

	__debug_info("rootfs_init", "done\n");
}

uint32 alloc_clus(struct superblock *sb)
{
	struct fat32_sb *fat = sb2fat(sb);
	uint32 newclus;

	acquiresleep(&sb->sb_lock);
	newclus = fat->next_free;
	if (newclus == 0) {
		if (fat->free_count == 0) {
			releasesleep(&sb->sb_lock);
			return 0;
		}
		__alert_fs_err("alloc_clus");
		panic("alloc_clus: no next free but free count is not zero");
	}
	if (fat->free_count == 0) {
		__alert_fs_err("alloc_clus");
		panic("alloc_clus: got next free but free count is zero");
	}

	fat_update_next_free(sb);
	releasesleep(&sb->sb_lock);

	sb->op.clear(sb, first_sec_of_clus(fat, newclus), fat->bpb.sec_per_clus);
	return newclus;
}

int free_clus(struct superblock *sb, uint32 cluster)
{
	return write_fat(sb, cluster, 0);
}

struct clus_table {
	struct rb_node rb;	
	uint32 base;
	uint32 num;
	uint32 clus[CLUS_TABLE_SIZE];
}

static inline struct clus_table *rb_clus_table(struct rb_node *node)
{
	return rb_entry(node, struct clus_table, rb);
}

static int fill_clus_table(struct superblock *sb, struct clus_table *table, uint32 preclus, int alloc_end_idx)
{
	uint32 clus;
	int i;
	if ((i = table->num) > 0) {		// If table is not empty...
		preclus = table->clus[i - 1];
	} else if (preclus == 0) {		// or take the arg preclus
		panic("fill_clus_table: bad pre-clus");
	}

	for (; i < CLUS_TABLE_SIZE; i++) {
		clus = read_fat(sb, preclus);	// get next cluster number
		// __debug_info("fill_clus_table", "read: i=%d, clus=0x%x, base=%d\n", i, clus, table->base);
		if (clus >= FAT32_EOC) {
			while (i <= alloc_end_idx) {
				if ((clus = alloc_clus(sb)) == 0 || write_fat(sb, preclus, clus) < 0) {
					if (clus)
						write_fat(sb, clus, 0);
					table->num = i;
					return -1;
				}
				preclus = table->clus[i] = clus;
				// __debug_info("fill_clus_table", "write: i=%d, clus=0x%x\n", i, clus);
				i++;
			}
			break;
		} else {
			table->clus[i] = clus;
		}
		preclus = clus;
	}

	// __debug_info("fill_clus_table", "end: i=%d, alloc_end_idx=%d\n", i, alloc_end_idx);
	table->num = i;
	return i;
}

static struct clus_table *expand_rb_clus(struct inode *ip, uint off, int alloc)
{
	struct fat32_entry *entry = i2fat(ip);
	struct fat32_sb *fat = sb2fat(ip->sb);
	struct rb_node *parent = rb_last(&entry->rb_clus);

	uint const clus_cnt = off / fat->byts_per_clus;
	uint const dst_key = clus_cnt / CLUS_TABLE_SIZE;
	int const dst_idx = clus_cnt % CLUS_TABLE_SIZE;

	// __debug_info("expand_rb_clus", "clus_cnt=%d, dstkey=%d, dstidx=%d, parent=%p\n",
	// 			clus_cnt, dst_key, dst_idx, parent);

	struct clus_table *table;
	struct rb_node **p;
	uint base_key;
	uint32 clus;
	int idx;

	// First, locate the last clus-table to get last base and index
	if (parent == NULL) { // no nodes in rb_tree
		table = kmalloc(sizeof(struct clus_table));
		if (table == NULL)
			goto fail;

		memset(table->clus, 0, sizeof(table->clus));
		table->base = 0;
		table->num = 1;
		table->clus[0] = entry->first_clus;
		__debug_info("expand_rb_clus", "first: clus=%d\n", entry->first_clus);
		parent = &table->rb;
		rb_link_node(parent, NULL, &entry->rb_clus.rb_node);
		rb_insert_color(parent, &entry->rb_clus);
	} else {
		table = rb_clus_table(parent);
	}

	if (table->num < CLUS_TABLE_SIZE) {	// step 1: fill the last table
		idx = alloc ? 
				(table->base == dst_key ? dst_idx : CLUS_TABLE_SIZE - 1) : -1;

		idx = fill_clus_table(ip->sb, table, 0, idx);
		if (idx < 0)						// case: allocation fail
			goto fail;
		else if (idx < CLUS_TABLE_SIZE)		// case: meet end of fat chain
			return table;
	}

	base_key = table->base + 1;
	clus = table->clus[CLUS_TABLE_SIZE - 1];
	p = &parent->rb_right;

	while (base_key <= dst_key) {	// allocate new table
		table = kmalloc(sizeof(struct clus_table));
		if (table == NULL)
			goto fail;

		table->base = base_key;
		memset(table->clus, 0, sizeof(table->clus));
		table->num = 0;

		// __debug_info("expand_rb_clus", "newtable: base=%d, pre-clus=0x%x\n", base_key, clus);
		idx = alloc ? 
				(table->base == dst_key ? dst_idx : CLUS_TABLE_SIZE - 1) : -1;
		idx = fill_clus_table(ip->sb, table, clus, idx);
		if (idx < 0) {						// case: allocation fail
			if (table->num == 0)
				kfree(table);
			goto fail;
		} else if (idx == 0) {				// case: meet end of fat chain
			kfree(table);					// don't keep empty table
			return rb_clus_table(parent);
		}

		rb_link_node(&table->rb, parent, p);
		rb_insert_color(&table->rb, &entry->rb_clus);

		if (table->num < CLUS_TABLE_SIZE)	// not full, meet end of fat chain
			break;

		base_key++;
		clus = table->clus[CLUS_TABLE_SIZE - 1];
		parent = &table->rb;		// table is now the right-most node
		p = &table->rb.rb_right;	// the next node is the next right-most one
	}

	return table;

fail: // If fail, no need to free tables that have been allocated (for future use).
	__debug_warn("expand_rb_clus", "fail\n");
	return NULL;
}

uint32 reloc_clus(struct inode *ip, uint off, int alloc)
{
	struct fat32_entry *entry = i2fat(ip);
	struct fat32_sb *fat = sb2fat(ip->sb);
	uint const clus_cnt = off / fat->byts_per_clus;
	uint const rb_key = clus_cnt / CLUS_TABLE_SIZE;

	struct rb_node *node = entry->rb_clus.rb_node;
	struct clus_table *table = entry->cur_clus;

	// __debug_info("reloc_clus", "begin: node=%p\n", node);
	if (!table || table->base != rb_key) {
		while (node) {
			// __debug_info("reloc_clus", "search: node=%p\n", node);
			table = rb_clus_table(node);
			if (rb_key < table->base)
				node = node->rb_left;
			else if (rb_key > table->base)
				node = node->rb_right;
			else
				break;
		}
	}

	int const idx = clus_cnt % CLUS_TABLE_SIZE;
	if (!node) {
		table = expand_rb_clus(ip, off, alloc);
		// __debug_info("reloc_clus", "get expand, base=%d, off=%p\n", table ? table->base : -1, off);
		if (table == NULL || table->base != rb_key)
			goto fail;
	} else if (!table->clus[idx]) {
		// __debug_info("reloc_clus", "get table, base=%d, off=%p\n", table->base, off);
		if (!alloc)
			goto fail;
		if (fill_clus_table(ip->sb, table, 0, idx) < 0)
			goto fail;
	}

	// __debug_info("reloc_clus", "end: clus=%d, off=%d\n", entry->cur_clus, off);
	entry->cur_clus = table;
	return table->clus[idx];

fail:
	return 0;
}

void free_clus_cache(struct fat32_entry *entry)
{
	struct rb_node *node = entry->rb_clus.rb_node;
	struct rb_node *parent = NULL;
	struct clus_table *table;

	while (node != NULL) {
		if (node->rb_left)
			node = node->rb_left;
		else if (node->rb_right)
			node = node->rb_right;
		else {
			parent = rb_parent(node);
			if (parent) {
				if (node == parent->rb_left)
					parent->rb_left = NULL;
				else
					parent->rb_right = NULL;
			}

			table = rb_clus_table(node);
			__debug_info("free_clus_cache", "base=%d, num=%d\n", table->base, table->num);
			kfree(table);
			node = parent;
		}
	}

	entry->rb_clus.rb_node = NULL;
}

struct short_name_entry {
	char        name[CHAR_SHORT_NAME];
	uint8       attr;
	uint8       _nt_res;
	uint8       crt_time_tenth;
	uint16      crt_time;
	uint16      crt_date;
	uint16      lst_acce_date;
	uint16      fst_clus_hi;
	uint16      lst_wrt_time;
	uint16      lst_wrt_date;
	uint16      fst_clus_lo;
	uint32      file_size;
} __attribute__((packed, aligned(4)))

struct long_name_entry {
	uint8       order;
	wchar       name1[5];
	uint8       attr;
	uint8       _type;
	uint8       checksum;
	wchar       name2[6];
	uint16      _fst_clus_lo;
	wchar       name3[2];
} __attribute__((packed, aligned(4)))

static void generate_shortname(char *shortname, char *name)
{
	static char illegal[] = { '+', ',', ';', '=', '[', ']', 0 };   // these are legal in l-n-e but not s-n-e
	int i = 0;
	char c, *p = name;
	for (int j = strlen(name) - 1; j >= 0; j--) {
		if (name[j] == '.') {
			p = name + j;
			break;
		}
	}
	while (i < CHAR_SHORT_NAME && (c = *name++)) {
		if (i == 8 && p) {
			if (p + 1 < name) { break; }            // no '.'
			else {
				name = p + 1, p = 0;
				continue;
			}
		}
		if (c == ' ') { continue; }
		if (c == '.') {
			if (name > p) {                    // last '.'
				memset(shortname + i, ' ', 8 - i);
				i = 8, p = 0;
			}
			continue;
		}
		if (c >= 'a' && c <= 'z') {
			c += 'A' - 'a';
		} else {
			if (strchr(illegal, c) != NULL) {
				c = '_';
			}
		}
		shortname[i++] = c;
	}
	while (i < CHAR_SHORT_NAME) {
		shortname[i++] = ' ';
	}
}

static uint8 cal_checksum(uchar* shortname)
{
	uint8 sum = 0;
	for (int i = CHAR_SHORT_NAME; i != 0; i--) {
		sum = ((sum & 1) ? 0x80 : 0) + (sum >> 1) + *shortname++;
	}
	return sum;
}

int fat_make_entry(struct inode *dir, struct fat32_entry *ep, char *filename, uint off, int islong)
{
	struct fat32_entry *dp = i2fat(dir);
	if (!(dp->attribute & ATTR_DIRECTORY))
		panic("fat_make_entry: not dir");
	if (off % sizeof(union fat_disk_entry))
		panic("fat_make_entry: not aligned");

	uint32 const bpc = sb2fat(dir->sb)->byts_per_clus;
	uint32 clus;
	union fat_disk_entry de;
	memset(&de, 0, sizeof(de));
	if (!islong) {
		strncpy(de.sne.name, filename, sizeof(de.sne.name));
	}
    else {
		char shortname[CHAR_SHORT_NAME + 1];
		memset(shortname, 0, sizeof(shortname));
		generate_shortname(shortname, filename);
		de.lne.checksum = cal_checksum((uchar *)shortname);
		de.lne.attr = ATTR_LONG_NAME;

		for (int i = ep->ent_cnt - 1; i > 0; i--) {
			if ((de.lne.order = i) == ep->ent_cnt - 1) {
				de.lne.order |= LAST_LONG_ENTRY;
			}
			char *p = filename + (i - 1) * CHAR_LONG_NAME;
			uint8 *w = (uint8 *)de.lne.name1;
			int end = 0;
			for (int j = 1; j <= CHAR_LONG_NAME; j++) {
				if (end) {
					*w++ = 0xff;            // on k210, unaligned reading is illegal
					*w++ = 0xff;
				} else { 
					if ((*w++ = *p++) == 0) {
						end = 1;
					}
					*w++ = 0;
				}
				switch (j) {
					case 5:     w = (uint8 *)de.lne.name2; break;
					case 11:    w = (uint8 *)de.lne.name3; break;
				}
			}
			clus = reloc_clus(dir, off, 1);
			// __debug_info("fat_make_entry", "name:%s clus:%d off:%d\n", ep->filename, dp->cur_clus, off2);
			if (!clus || fat_rw_clus(dir->sb, clus, 1, 0, (uint64)&de, off % bpc, sizeof(de)) != sizeof(de))
				return -1;
			off += sizeof(de);
		}
		memset(&de, 0, sizeof(de));
		strncpy(de.sne.name, shortname, sizeof(de.sne.name));
	}
	de.sne.attr = ep->attribute;
	de.sne.fst_clus_hi = (uint16)(ep->first_clus >> 16);      // first clus high 16 bits
	de.sne.fst_clus_lo = (uint16)(ep->first_clus & 0xffff);     // low 16 bits
	de.sne.file_size = ep->file_size;                         // filesize is updated in eupdate()
	clus = reloc_clus(dir, off, 1);
	// __debug_info("fat_make_entry", "name:%s clus:%d off:%d\n", ep->filename, dp->cur_clus, off2);
	if (!clus || fat_rw_clus(dir->sb, clus, 1, 0, (uint64)&de, off % bpc, sizeof(de)) != sizeof(de))
		return -1;
	return 0;
}

static char *formatname(char *name)
{
	static char illegal[] = { '\"', '*', '/', ':', '<', '>', '?', '\\', '|', 0 };
	char *p;
	while (*name == ' ' || *name == '.') { name++; }
	if (*name == '\0')
		return NULL;
	for (p = name; *p; p++) {
		char c = *p;
		if (c < 0x20 || strchr(illegal, c)) {
			return 0;
		}
	}
	while (p-- > name) {
		if (*p != ' ') {
			p[1] = '\0';
			break;
		}
	}
	if (p - name + 1 > FAT32_MAX_FILENAME)
		return NULL;
	return name;
}

struct inode *fat_alloc_entry(struct inode *dir, char *name, int mode)
{
	__debug_info("fat_alloc_entry", "allocating %s\n", name);
	if (dir->state & I_STATE_FREE || !(name = formatname(name))) {        // detect illegal character
		return NULL;
	}
	struct fat32_entry *dp = i2fat(dir);
	if (!(dp->attribute & ATTR_DIRECTORY))
		panic("ealloc not dir");

	struct superblock *sb = dir->sb;
	struct inode *ip;
	uint off = 0;
	/* If the file exists on disk. */
	if ((ip = fat_lookup_dir(dir, name, &off)) != NULL) {      // entry exists
		return ip;
	}
	if ((ip = fat_alloc_inode(sb)) == NULL) {
		__debug_warn("fat_alloc_entry", "2\n");
		return NULL;
	}
	ip->op = dir->op;
	ip->fop = dir->fop;
	ip->mode = mode | 0x1ff;

	struct fat32_entry *ep = i2fat(ip);
	ep->attribute = S_ISDIR(mode) ? ATTR_DIRECTORY : 0;
	ep->ent_cnt = (strlen(name) + CHAR_LONG_NAME - 1) / CHAR_LONG_NAME + 1;

	if (S_ISDIR(mode)) {    // generate "." and ".." for ep
		if ((ep->first_clus = alloc_clus(sb)) == 0 ||
			fat_make_entry(ip, ep, ".          ", 0, 0) < 0 ||
			fat_make_entry(ip, dp, "..         ", 32, 0) < 0)
		{
			if (ep->first_clus > 0)
				free_clus(sb, ep->first_clus);
			goto fail;
		}
	}
	else {  // what is this for?
		ep->attribute |= ATTR_ARCHIVE;
	}

	if (fat_make_entry(dir, ep, name, off, 1) < 0)
		goto fail;

	ip->inum = ((uint64)reloc_clus(dir, off, 0) << 32) | (off % sb2fat(sb)->byts_per_clus);
	return ip;

fail:
	__debug_warn("fat_alloc_entry", "fail\n");
	__alert_fs_err("fat_alloc_entry");
	fat_destroy_inode(ip);
	return NULL;
}

int fat_remove_entry(struct inode *ip)
{
	if (ip->state & I_STATE_FREE)
		return -ENOENT;
	if (ip->nlink == 0)
		return -ENOENT;
	ip->nlink--;

	struct fat32_sb *fat = sb2fat(ip->sb);
	struct fat32_entry *entry = i2fat(ip);
	uint32 clus = ip->inum >> 32;
	uint32 off = ip->inum & 0xffffffff;

	__debug_info("fat_remove_entry", "clus:%d off:%d entcnt:%d\n", clus, off, entry->ent_cnt);
	uint8 flag = EMPTY_ENTRY;
	for (int i = 0; i < entry->ent_cnt; i++) {
		__debug_info("fat_remove_entry", "name:%s clus:%d off:%d i:%d\n", ip->entry->filename, clus, off, i);
		if (fat_rw_clus(ip->sb, clus, 1, 0, (uint64)&flag, off, 1) != 1)
			goto fail;
		if ((off += 32) >= fat->byts_per_clus && i + 1 < entry->ent_cnt) {
			if ((clus = read_fat(ip->sb, clus)) == 0 || clus >= FAT32_EOC) {
				__debug_info("fat_remove_entry", "read_fat fail! clus=%d\n", clus);
				goto fail;
			}
			off %= fat->byts_per_clus;
			__debug_info("fat_remove_entry", "entries over clus! new_clus:%d new_off:%d\n", clus, off);
		}
	}

	return 0;

fail:
	__alert_fs_err("fat_remove_entry");
	return -EIO;
}

int fat_update_entry(struct inode *ip)
{
	if (!(ip->state & I_STATE_DIRTY))
		return 0;
	if (ip->state & I_STATE_FREE)
		return -1;

	struct fat32_sb *fat = sb2fat(ip->sb);
	struct fat32_entry *entry = i2fat(ip);
	uint32 clus = ip->inum >> 32;
	uint32 off = (ip->inum & 0xffffffff) + ((entry->ent_cnt - 1) << 5);

	union fat_disk_entry de;

	// The short entry steps over the cluster.
	if (off >= fat->byts_per_clus) {
		clus = read_fat(ip->sb, clus);
		if (clus == 0) { goto fail; }
		off %= fat->byts_per_clus;
	}

	// Read from disk.
	if (fat_rw_clus(ip->sb, clus, 0, 0, (uint64)&de, off, sizeof(de)) != sizeof(de))
		goto fail;
	de.sne.fst_clus_hi = (uint16)(entry->first_clus >> 16);
	de.sne.fst_clus_lo = (uint16)(entry->first_clus & 0xffff);
	de.sne.file_size = entry->file_size;
	// Wirte back.
	if (fat_rw_clus(ip->sb, clus, 1, 0, (uint64)&de, off, sizeof(de)) != sizeof(de))
		goto fail;
	ip->state &= ~I_STATE_DIRTY;

	return 0;

fail:
	__alert_fs_err("fat_update_entry");
	return -1;
}

static void read_entry_name(char *buffer, union fat_disk_entry *d)
{
	if (d->lne.attr == ATTR_LONG_NAME) {                       // long entry branch
		wchar temp[NELEM(d->lne.name1)];
		memmove(temp, d->lne.name1, sizeof(temp));
		snstr(buffer, temp, NELEM(d->lne.name1));
		buffer += NELEM(d->lne.name1);
		snstr(buffer, d->lne.name2, NELEM(d->lne.name2));
		buffer += NELEM(d->lne.name2);
		snstr(buffer, d->lne.name3, NELEM(d->lne.name3));
	} else {
		// assert: only "." and ".." will enter this branch
		memset(buffer, 0, CHAR_SHORT_NAME + 2); // plus '.' and '\0'
		int i;
		for (i = 0; d->sne.name[i] != ' ' && i < 8; i++) {
			buffer[i] = d->sne.name[i];
		}
		if (d->sne.name[8] != ' ') {
			buffer[i++] = '.';
		}
		for (int j = 8; j < CHAR_SHORT_NAME; j++, i++) {
			if (d->sne.name[j] == ' ') { break; }
			buffer[i] = d->sne.name[j];
		}
	}
}

static void read_entry_info(struct fat32_entry *entry, union fat_disk_entry *d)
{
	entry->attribute = d->sne.attr;
	entry->first_clus = ((uint32)d->sne.fst_clus_hi << 16) | d->sne.fst_clus_lo;

	entry->create_time_tenth = d->sne.crt_time_tenth;
	entry->create_time = d->sne.crt_time;
	entry->create_date = d->sne.crt_date;
	entry->last_access_date = d->sne.lst_acce_date;
	entry->last_write_time = d->sne.lst_wrt_time;
	entry->last_write_date = d->sne.lst_wrt_date;

	entry->file_size = d->sne.file_size;
}

int fat_read_entry(struct inode *dir, struct fat32_entry *ep, char *namebuf, uint off, int *count)
{
	if (dir->state & I_STATE_FREE)
		return -1;

	struct fat32_entry *dp = i2fat(dir);
	if (!(dp->attribute & ATTR_DIRECTORY))
		panic("enext not dir");
	if (off % 32)
		panic("enext not align");

	union fat_disk_entry de;
	uint32 const bpc = sb2fat(dir->sb)->byts_per_clus;
	int empty = 0, cnt = 0;
	memset(namebuf, 0, FAT32_MAX_FILENAME + 1);
	for (uint32 clus; (clus = reloc_clus(dir, off, 0)) != 0; off += sizeof(de))
	{
		if (fat_rw_clus(dir->sb, clus, 0, 0, (uint64)&de, off % bpc, sizeof(de)) != sizeof(de)
			|| de.lne.order == END_OF_DIR) {
			return -1;
		}
		if (de.lne.order == EMPTY_ENTRY) {
			if (cnt) {      // We have met a l-n-e, but why we come across an empty one?
				goto excep; // Maybe the entry is being removed by its so-call inode.
			}
			empty++;
			continue;
		} else if (empty) {
			*count = empty;
			return 0;
		}
		if (de.lne.attr == ATTR_LONG_NAME) {
			if (de.lne.order & LAST_LONG_ENTRY) {
				cnt = (de.lne.order & ~LAST_LONG_ENTRY) + 1;   // plus the s-n-e;
				*count = cnt;
			} else if (cnt == 0) {    // Should not occur unless some inode is removing this entry
				goto excep;
			}
			read_entry_name(namebuf + (--cnt - 1) * CHAR_LONG_NAME, &de);
		} else {
			if (cnt == 0) {     // Without l-n-e
				*count = 1;
				read_entry_name(namebuf, &de);
			}
			read_entry_info(ep, &de);
			__debug_info("fat_dir_next", "get %s\n", namebuf);
			return 1;
		}
	}
	return -1;

excep:
	*count = 0;     // Caller will re-read
	__debug_warn("fat_dir_next", "??? from %d\n", off);
	return 0;
}

int fat_rename_entry(struct inode *ip, struct inode *dp, char *name)
{
	if ((name = formatname(name)) == NULL)
		return -EINVAL;

	uint off;
	struct fat32_entry *dst;
	dst = fat_lookup_dir_ent(dp, name, &off);
	if (dst != NULL) { // file exists
		kfree(dst);
		panic("fat_rename_entry"); // vfs should have checked this, what happened?
		return -EEXIST;
	}
	if (fat_make_entry(dp, i2fat(ip), name, off, 1) < 0) {
		return -ENOSPC;
	}
	int ret = fat_remove_entry(ip);
	if (ret < 0) {
		return ret;
	}

	safestrcpy(ip->entry->filename, name, FAT32_MAX_FILENAME + 1); // this is with no lock, dangerous
	ip->nlink++; // fat_remove_entry decreased this, add it back
	uint64 clus = reloc_clus(dp, off, 0);
	ip->inum = (clus << 32) | (off % sb2fat(dp->sb)->byts_per_clus);

	return 0;
}

static inline uint32 fat_sec_of_clus(struct fat32_sb *fat, uint32 cluster, uint8 fat_num)
{
	return fat->bpb.rsvd_sec_cnt + (cluster << 2) / fat->bpb.byts_per_sec + fat->bpb.fat_sz * (fat_num - 1);
}

static inline uint32 fat_offset_of_clus(struct fat32_sb *fat, uint32 cluster)
{
	return (cluster << 2) % fat->bpb.byts_per_sec;
}

int fat_cache_init(struct superblock *sb)
{
	struct fat32_sb *fat = sb2fat(sb); 
	if (fat->fatcache.page)
		panic("fat_cache_init: superblock is not clean");

	if ((fat->fatcache.page = allocpage()) == NULL)
		return -ENOMEM;

	char *afsec = fat->fatcache.page;
	uint32 alloc_fat_sec = (fat->next_free >= 2) ? 
							fat_sec_of_clus(fat, fat->next_free, 1) :
							fat->bpb.rsvd_sec_cnt;

	for (int i = 0; i < FAT_CACHE_NSEC; i++) {
		fat->fatcache.fatsec[i] = 0;
		fat->fatcache.lrucnt[i] = 0;
		fat->fatcache.dirty[i] = 0;
	}
	fat->fatcache.allocidx = 0;
	fat->fatcache.fatsec[0] = alloc_fat_sec;
	fat->next_free_fat = fat->bpb.rsvd_sec_cnt;

	acquiresleep(&sb->sb_lock);
	if (sb->op.read(sb, 0, afsec, alloc_fat_sec, 0, SECSZ) != SECSZ) {
		releasesleep(&sb->sb_lock);
		freepage(fat->fatcache.page);
		fat->fatcache.page = NULL;
		return -EIO;
	}

	// Check whether the 'next free' field lie to us.
	if (*(uint32 *)(afsec + fat_offset_of_clus(fat, fat->next_free)) != 0
		&& fat_update_next_free(sb) == 0)
		panic("fat_cache_init: no next free");

	releasesleep(&sb->sb_lock);
	return 0;
}

void fat_cache_free(struct superblock *sb)
{
	struct fat32_sb *fat = sb2fat(sb);
	if (fat->fatcache.page)
		freepage(fat->fatcache.page);
}

void fat_cache_sync(struct superblock *sb)
{
	struct fat32_sb *fat = sb2fat(sb);

	// sync the fat region
	for (int i = 0; i < FAT_CACHE_NSEC; i++) {
		if (fat->fatcache.dirty[i]) {
			if (sb->op.write(sb, 0, &fat->fatcache.page[i * SECSZ],
							fat->fatcache.fatsec[i], 0, SECSZ) == SECSZ)
			{
				fat->fatcache.dirty[i] = 0;
			}
		}
	}

	// sync the fs info sec
	sb->op.write(sb, 0, (char *)&fat->free_count, fat->fs_info,
				FAT_FREE_CNT_OFF, sizeof(fat->free_count));
	sb->op.write(sb, 0, (char *)&fat->next_free, fat->fs_info,
				FAT_NEXT_FREE_OFF, sizeof(fat->next_free));
}

static int get_cache_fat(struct superblock *sb, uint32 fatsec, int *pidx)
{
	struct fat32_sb *fat = sb2fat(sb);
	int aidx = fat->fatcache.allocidx;
	int victim = -1;
	uint32 max = 0;

	for (int i = 0; i < FAT_CACHE_NSEC; i++) {
		uint32 sec = fat->fatcache.fatsec[i];
		if (sec == fatsec) {	// cache hit
			*pidx = i;
			pidx = NULL;
			fat->fatcache.lrucnt[i] = 0;
		}
		else if (sec == 0) {	// find an empty slot
			/**
			 * We fill the cache page in an index-increasing way,
			 * so if we meet an empty slot, the next slots must be
			 * empty, too. We can finish our search.
			 * Since no fat region sector will be invalid, once the
			 * cache page becomes full, it will always be full.
			 * There is no case where there is an empty hole inside it.
			 */
			victim = i;
			break;
		}
		else if (i != aidx) {	// We don't evict the alloc sec.
			uint32 cnt = ++fat->fatcache.lrucnt[i];
			if (cnt > max) {
				max = cnt;
				victim = i;
			}
		}
	}
	if (pidx) {					// cache not hit
		*pidx = victim;
		return 0;
	}
	return 1;
}

static void fat_cache_load(struct superblock *sb, uint32 newsec, int idx)
{
	struct fat32_sb *fat = sb2fat(sb);
	char *secdata = &fat->fatcache.page[idx * SECSZ];

	if (fat->fatcache.dirty[idx]) {
		sb->op.write(sb, 0, secdata, fat->fatcache.fatsec[idx], 0, SECSZ);
		fat->fatcache.dirty[idx] = 0;
	}

	sb->op.read(sb, 0, secdata, newsec, 0, SECSZ);
	fat->fatcache.fatsec[idx] = newsec;
	fat->fatcache.lrucnt[idx] = 0;
}

uint32 fat_update_next_free(struct superblock *sb)
{
	struct fat32_sb *fat = sb2fat(sb);
	int aidx = fat->fatcache.allocidx;
	uint32 *asecdata = (uint32 *)&fat->fatcache.page[aidx * SECSZ];

	// It's OK if fat->next_free is an illegal value (when initializing).
	uint32 fatoff = fat_offset_of_clus(fat, fat->next_free) / sizeof(uint32);
	uint32 cnt = FAT_ENTRY_NUM;

	if (asecdata[fatoff] == 0) {
		asecdata[fatoff] = FAT32_EOC + 7;		// mark allocated
		fat->fatcache.dirty[aidx] = 1;
		fat->free_count--;
		cnt--;
		fatoff = (fatoff + 1) % FAT_ENTRY_NUM;
	}

	// Look up the new next_free
	fat->next_free = 0;
	int idx = aidx;
	for (;;) {
		for (; cnt > 0; cnt--, fatoff = (fatoff + 1) % FAT_ENTRY_NUM) {
			if (asecdata[fatoff] == 0) {		// found
				fat->fatcache.allocidx = aidx;
				fat->next_free = fatoff + FAT_ENTRY_NUM * 
									(fat->fatcache.fatsec[aidx] - fat->bpb.rsvd_sec_cnt);
				return fat->next_free;			// in most case we go out from here
			}
		}
		// Unluckily, the current alloc-sec has no cluster.
		do {
			// Switch to next cached fat sector.
			aidx = (aidx + 1) % FAT_CACHE_NSEC;
			// There is no available cluster in cached fat sec.
			if (aidx == idx)
				goto notfound;
		} while (fat->fatcache.fatsec[aidx] == 0);

		asecdata = (uint32 *)&fat->fatcache.page[aidx * SECSZ];
		fatoff = 0;
		cnt = FAT_ENTRY_NUM;
	}

notfound:
	// Unfortunately, all the cached fat sectors have no cluster.
	// We have to do more work -- look up to the disk.
	if (fat->free_count == 0)
		return 0;

	/**
	 * We are going to dig in the disk. But before we start, we
	 * need to do some preliminaries. That is, we must jump over
	 * the sectors that are cached, because we've checked all of
	 * them. More importantly, the identical sectors read from
	 * the disk are not the latest (the cached ones are).
	 */
	uint32 cachesec[FAT_CACHE_NSEC + 1];
	uint32 sec, max = 0;
	cnt = FAT_CACHE_NSEC;
	for (aidx = idx = 0; idx < FAT_CACHE_NSEC; idx++) {
		cachesec[idx] = fat->fatcache.fatsec[idx];
		if (cachesec[idx] == 0) {		// find empty cache slot
			aidx = idx;
			cnt = idx + 1;
			do cachesec[idx++] = 0;
			while (idx < FAT_CACHE_NSEC);
			break;
		}
		sec = fat->fatcache.lrucnt[idx];
		if (sec > max) {				// to determine the eviction victim
			max = sec;
			aidx = idx;
		}
	}

	for (idx = 0; idx < cnt - 1; idx++)	// small array, swap sort is enough
		for (sec = idx + 1; sec < cnt; sec++)
			if (cachesec[idx] > cachesec[sec]) {
				max = cachesec[idx];
				cachesec[idx] = cachesec[sec];
				cachesec[sec] = max;
			}

	asecdata = (uint32 *)&fat->fatcache.page[aidx * SECSZ];
	max = fat->bpb.rsvd_sec_cnt + fat->bpb.fat_sz;	// last sector of fat region
	sec = fat->next_free_fat;
	cachesec[FAT_CACHE_NSEC] = fat->bpb.rsvd_sec_cnt;	// place a sentry in tail

try:
	for (idx = 0; cachesec[idx] < sec && idx < cnt; idx++);
	for (; sec < max; sec++) {
		if (sec == cachesec[idx]) {		// meet one in the cache
			idx++;						// since we sorted, move to next value
			continue;
		}
		fat_cache_load(sb, sec, aidx);
		fatoff = (sec == cachesec[FAT_CACHE_NSEC]) ? 2 : 0;	// is the first fat sec?
		for (; fatoff < FAT_ENTRY_NUM; fatoff++) {
			if (asecdata[fatoff] == 0) {			// found
				fat->next_free_fat = sec + 1;
				fat->fatcache.allocidx = aidx;
				fat->next_free = fatoff + FAT_ENTRY_NUM * 
									(sec - fat->bpb.rsvd_sec_cnt);
				return fat->next_free;
			}
		}
	}
	if (max != fat->bpb.rsvd_sec_cnt + fat->bpb.fat_sz)		// the second try fail
		panic("fat_update_next_free: no next but free_count is not zero");

	// try again from the first fat region sector.
	max = fat->next_free_fat;
	sec = fat->bpb.rsvd_sec_cnt;
	goto try;
}

uint32 read_fat(struct superblock *sb, uint32 cluster)
{
	if (cluster >= FAT32_EOC)
		return cluster;

	struct fat32_sb *fat = sb2fat(sb);
	if (cluster > fat->data_clus_cnt + 1) {     // because cluster number starts at 2, not 0
		__alert_fs_err("read_fat");
		return 0;
	}

	uint32 fat_sec = fat_sec_of_clus(fat, cluster, 1);
	uint32 sec_off = fat_offset_of_clus(fat, cluster);
	uint32 next;
	int idx;

	acquiresleep(&sb->sb_lock);

	if (!get_cache_fat(sb, fat_sec, &idx))
		fat_cache_load(sb, fat_sec, idx);

	next = *(uint32 *)(fat->fatcache.page + idx * SECSZ + sec_off);

	releasesleep(&sb->sb_lock);
	return next;

