int fat_read_dir(struct inode *ip, struct dirent *dent, uint off)
{
	if (!(i2fat(ip)->attribute & ATTR_DIRECTORY))
		return -1;

	int count = 0;
	uint off2 = off - off % 32;

	struct fat32_entry entry;
	int ret;
	while ((ret = fat_read_entry(ip, &entry, dent->name, off2, &count)) == 0) {
		// Skip empty entries.
		off2 += count << 5;
	}

	// Meet end of dir
	if (ret < 0) {
		return 0;
	}
	off2 += (count << 5);
	ret = off2 - off;

	// Size of this dent, varies from length of filename.
	int size = sizeof(struct dirent) - sizeof(dent->name) + strlen(dent->name) + 1;
	size += (sizeof(uint64) - (size % sizeof(uint64))) % sizeof(uint64); // Align to 8.

	dent->ino = entry.first_clus;
	dent->off = off2;
	dent->reclen = size;
	dent->type = (entry.attribute & ATTR_DIRECTORY) ? T_DIR : T_FILE;

	return ret;
}

struct fat32_entry *fat_lookup_dir_ent(struct inode *dir, char *filename, uint *poff)
{
	if (!(i2fat(dir)->attribute & ATTR_DIRECTORY))
		panic("dirlookup not DIR");
	if (dir->state & I_STATE_FREE)
		return NULL;

	// __debug_info("fat_lookup_dir_ent", "in\n");
	struct inode *ip = fat_alloc_inode(dir->sb);
	if (ip == NULL)
		return NULL;
	struct fat32_entry *ep = i2fat(ip);

	int len = strlen(filename);
	int entcnt = (len + CHAR_LONG_NAME - 1) / CHAR_LONG_NAME + 1;   // count of l-n-entries, rounds up. plus s-n-e
	int count = 0;
	int type;
	uint off = 0;
	char namebuf[FAT32_MAX_FILENAME + 1];
	while ((type = fat_read_entry(dir, ep, namebuf, off, &count) != -1)) {
		if (type == 0) {
			if (poff && count >= entcnt) {
				*poff = off;
				poff = NULL;
			}
		} else if (strncmp(filename, namebuf, FAT32_MAX_FILENAME) == 0) {
			if (poff) {
				*poff = off;
			}
			ep->ent_cnt = count;
			return ep;
		}
		off += count << 5;
	}
	if (poff) {
		*poff = off;
	}
	kfree(ep);
	return NULL;
}

struct inode *fat_lookup_dir(struct inode *dir, char *filename, uint *poff)
{
	// struct superblock *sb = dir->sb;
	struct inode *ip = NULL;

	uint off = 0;    // Anyhow, we need this on FAT32
	struct fat32_entry *ep = fat_lookup_dir_ent(dir, filename, &off);
	if (ep == NULL)
		goto end;

	ip = &ep->vfs_inode;
	ip->op = dir->op;
	ip->fop = dir->fop;
	ip->size = ep->file_size;
	ip->mode = (ep->attribute & ATTR_DIRECTORY) ? S_IFDIR : S_IFREG;
	ip->mode |= 0x1ff;

	uint64 clus = reloc_clus(dir, off, 0);
	ip->inum = (clus << 32) | (off % sb2fat(dir->sb)->byts_per_clus);
	__debug_info("fat_lookup_dir", "name:%s ipos: clus=%d coff=%d inum=%p sizeof(uint64)=%d\n",
				filename, clus, off, ip->inum, sizeof(uint64));

end:
	if (poff) {
		*poff = off;
	}
	return ip;
}

struct fat32_sb {
	uint32		first_data_sec;
	uint32		data_sec_cnt;
	uint32		data_clus_cnt;
	uint32		byts_per_clus;
	uint32		free_count;		// of cluster
	uint32		next_free;		// clus
	uint16		fs_info;		// fs info sector
	uint32		next_free_fat;	// the next fat sec that has room
	struct {
		uint16	byts_per_sec;
		uint8	sec_per_clus;
		uint16	rsvd_sec_cnt;
		uint8	fat_cnt;		// count of FAT regions
		uint32	hidd_sec;		// count of hidden sectors
		uint32	tot_sec;		// total count of sectors including all regions
		uint32	fat_sz;			// count of sectors for a FAT region
		uint32	root_clus;
	} bpb;
	struct {
		char	*page;
		int		allocidx;
		uint32	fatsec[FAT_CACHE_NSEC];	// assume that sector size is 512 byte
		uint32	lrucnt[FAT_CACHE_NSEC];
		int8	dirty[FAT_CACHE_NSEC];	// whether the alloc sec dirty
	} fatcache;
	struct superblock vfs_sb;
}

struct fat32_entry {
	uint8	attribute;
	uint8	create_time_tenth;
	uint16	create_time;
	uint16	create_date;
	uint16	last_access_date;
	uint16	last_write_time;
	uint16	last_write_date;
	uint32	first_clus;
	uint32	file_size;

	uint32	ent_cnt;
	struct clus_table	*cur_clus;
	struct rb_root		rb_clus;
	struct inode 		vfs_inode;
}

static inline struct fat32_sb *sb2fat(struct superblock *sb)
{
	return container_of(sb, struct fat32_sb, vfs_sb);
}

static inline struct fat32_entry *i2fat(struct inode *ip)
{
	return container_of(ip, struct fat32_entry, vfs_inode);
}

static inline uint32 first_sec_of_clus(struct fat32_sb *fat, uint32 cluster)
{
	return ((cluster - 2) * fat->bpb.sec_per_clus) + fat->first_data_sec;
}

