	spi_receive_data_no_cmd_dma(DMAC_CHANNEL0, SPI_DEVICE_0, SPI_CHIP_SELECT_3, data_buff, length / 4);
}

static void sd_send_cmd(uint8 cmd, uint32 arg, uint8 crc) {
	uint8 frame[6];
	frame[0] = (cmd | 0x40);
	frame[1] = (uint8)(arg >> 24);
	frame[2] = (uint8)(arg >> 16);
	frame[3] = (uint8)(arg >> 8);
	frame[4] = (uint8)(arg);
	frame[5] = (crc);
	SD_CS_LOW();
	sd_write_data(frame, 6);
}

static void sd_end_cmd(void) {
	uint8 frame[1] = {0xFF};
	/*!< SD chip select high */
	SD_CS_HIGH();
	/*!< Send the Cmd bytes */
	sd_write_data(frame, 1);
}

static uint8 sd_get_response_R1(void) {
	uint8 result = 0xff;
	uint16 timeout = 0xff;

	while (timeout--) {
		sd_read_data(&result, 1);
		if (result != 0xff)
			return result;
	}

	// timeout!
	return 0xff;
}

static void sd_get_response_R3_rest(uint8 *frame) {
	sd_read_data(frame, 4);
}

static void sd_get_response_R7_rest(uint8 *frame) {
	sd_read_data(frame, 4);
}

static int switch_to_SPI_mode(void) {
	int timeout = 0xff;

	while (--timeout) {
		sd_send_cmd(SD_CMD0, 0, 0x95);
		uint64 result = sd_get_response_R1();
		sd_end_cmd();

		if (0x01 == result) break;
	}
	if (0 == timeout) {
		printf("SD_CMD0 failed\n");
		return 0xff;
	}

	return 0;
}

static int verify_operation_condition(void) {
	uint64 result = 0xff;

	// Stores the response reversely. 
	// That means 
	// frame[2] - VCA 
	// frame[3] - Check Pattern 
	uint8 frame[4];

	sd_send_cmd(SD_CMD8, 0x01aa, 0x87);
	result = sd_get_response_R1();
	sd_get_response_R7_rest(frame);
	sd_end_cmd();

	if (0x09 == result) {
		printf("invalid CRC for CMD8\n");
		return 0xff;
	}
	else if (0x01 == result && 0x01 == (frame[2] & 0x0f) && 0xaa == frame[3]) {
		return 0x00;
	}

	printf("verify_operation_condition() fail!\n");
	return 0xff;
}

static int read_OCR(void) {
	uint64 result = 0xff;
	uint8 ocr[4];

	int timeout = 0xffffff;
	while (--timeout) {
		sd_send_cmd(SD_CMD58, 0, 0);
		result = sd_get_response_R1();
		sd_get_response_R3_rest(ocr);
		sd_end_cmd();

		if (
			0x01 == result && // R1 response in idle status 
			(ocr[1] & 0x1f) && (ocr[2] & 0x80) 	// voltage range valid 
		) {
			return 0;
		}
	}

	// timeout!
	printf("read_OCR() timeout!\n");
	printf("result = %d\n", result);
	return 0xff;
}

static int set_SDXC_capacity(void) {
	uint8 result = 0xff;

	int timeout = 0xffffff;
	while (--timeout) {
		sd_send_cmd(SD_CMD55, 0, 0);
		result = sd_get_response_R1();
		sd_end_cmd();
		if (0x01 != result) {
			printf("SD_CMD55 fail! result = %d\n", result);
			return 0xff;
		}

		sd_send_cmd(SD_ACMD41, 0x40000000, 0);
		result = sd_get_response_R1();
		sd_end_cmd();
		if (0 == result) {
			return 0;
		}
	}

	// timeout! 
	printf("set_SDXC_capacity() timeout!\n");
	printf("result = %d\n", result);
	return 0xff;
}

static int check_block_size(void) {
	uint8 result = 0xff;
	uint8 ocr[4];

	int timeout = 0xffffff;
	while (timeout --) {
		sd_send_cmd(SD_CMD58, 0, 0);
		result = sd_get_response_R1();
		sd_get_response_R3_rest(ocr);
		sd_end_cmd();

		if (0 == result) {
			if (ocr[0] & 0x40) {
				printf("SDHC/SDXC detected\n");
				if (512 != BSIZE) {
					printf("BSIZE != 512\n");
					return 0xff;
				}

				is_standard_sd = 0;
			}
			else {
				printf("SDSC detected, setting block size\n");

				// setting SD card block size to BSIZE 
				int timeout = 0xff;
				int result = 0xff;
				while (--timeout) {
					sd_send_cmd(SD_CMD16, BSIZE, 0);
					result = sd_get_response_R1();
					sd_end_cmd();

					if (0 == result) break;
				}
				if (0 == timeout) {
					printf("check_OCR(): fail to set block size");
					return 0xff;
				}

				is_standard_sd = 1;
			}

			return 0;
		}
	}

	// timeout! 
	printf("check_OCR() timeout!\n");
	printf("result = %d\n", result);
	return 0xff;
}

static int sd_init(void) {
	uint8 frame[10];

	sd_lowlevel_init(0);
	//SD_CS_HIGH();
	SD_CS_LOW();

	// send dummy bytes for 80 clock cycles 
	for (int i = 0; i < 10; i ++) 
		frame[i] = 0xff;
	sd_write_data(frame, 10);

	if (0 != switch_to_SPI_mode()) 
		return 0xff;
	if (0 != verify_operation_condition()) 
		return 0xff;
	if (0 != read_OCR()) 
		return 0xff;
	if (0 != set_SDXC_capacity()) 
		return 0xff;
	if (0 != check_block_size()) 
		return 0xff;
	SD_HIGH_SPEED_ENABLE();
	return 0;
}

struct {
	int busy;
	int rpending;
	int wpending;
	int wcount;
}

void sdcard_init(void) {
	int result = sd_init();
	initsleeplock(&sdcard_lock, "sdcard");
	wait_queue_init(&sd_rqueue, "sdrq");
	wait_queue_init(&sd_wqueue, "sdwq");
	sd_status.busy = 0;
	sd_status.rpending = 0;
	sd_status.wpending = 0;
	sd_status.wcount = 0;

	if (0 != result) {
		panic("sdcard_init failed");
	}
	#ifdef DEBUG
	printf("sdcard_init\n");
	#endif
}

static void sdcard_read_wait(struct buf *b)
{
	acquire(&sd_rqueue.lock);
	// Register to read queue, add to tail.
	dlist_add_before(&sd_rqueue.head, &b->list);
	// whether we are the first one
	while (&b->list != sd_rqueue.head.next)
		// sleep on list to get wakened orderly, unlike sleeplock
		sleep(&b->list, &sd_rqueue.lock);

	// watch out the sequence
	acquire(&sdcard_lock.lk);
	release(&sd_rqueue.lock);

	// Check sdcard working status.
	while (sd_status.busy) {
		if (sd_status.busy != BUSY_WRITE)
			panic("sdcard_read_wait: status");
		// let writers see us
		sd_status.rpending = 1;
		sleep(&sd_status.rpending, &sdcard_lock.lk);
	}
	sd_status.rpending = 0;
	sd_status.busy = BUSY_READ;
	release(&sdcard_lock.lk);
}

static int sdcard_read_done(struct buf *b)
{
	acquire(&sd_rqueue.lock);
	if (&b->list != sd_rqueue.head.next)
		panic("sdcard_read_done: wrong order");

	dlist_del(&b->list);

	struct d_list *dl = sd_rqueue.head.next;
	int done = 0;
	// more readers?
	acquire(&sdcard_lock.lk);
	sd_status.busy = 0;
	if (dl != &sd_rqueue.head) {
		wakeup(dl);
		sd_status.rpending = 1;
	}
	else if (sd_status.wpending)
		done = 1;

	release(&sd_rqueue.lock);
	release(&sdcard_lock.lk);
	return done;
}

int sdcard_read(struct buf *b)
{
	int ret = -EIO;
	uint8 dummy_crc[2];
	uint8 result = 0xff;
	uint32 address = is_standard_sd ?
						b->sectorno << 9 :
						b->sectorno;

	// wait our turn
	sdcard_read_wait(b);

	sd_send_cmd(SD_CMD17, address, 0);
	if (sd_get_response_R1() != 0) {
		printf(__ERROR("sdcard")" CMD17 fail\n");	// we'd better print it
		goto end;
	}

	for (int timeout = 0xffff; timeout > 0 && result != 0xfe; timeout--)
		sd_read_data(&result, 1);

	if (result != 0xfe) {
		printf(__ERROR("sdcard")" CMD17 read fail\n");
		goto end;
	}

	sd_read_data_dma(b->data, BSIZE);
	sd_read_data(dummy_crc, 2);
	ret = 0;

end:
	sd_end_cmd();
	if (sdcard_read_done(b))
		sdcard_write_start();
	return ret;
}

int sdcard_read_sectors(struct buf * restrict bufs[], int nbuf)
{
	int ret = 0;
	uint32 address = is_standard_sd ?
						bufs[0]->sectorno << 9 :
						bufs[0]->sectorno;

	// wait our turn
	sdcard_read_wait(bufs[0]);

	sd_send_cmd(SD_CMD18, address, 0);
	if (sd_get_response_R1() != 0) {
		ret = -EIO;
		printf(__WARN("sdread")" response! sec %d\n", bufs[0]->sectorno);
		goto out;
	}

	for (int i = 0; i < nbuf; i++) {
		uint8 result = 0xff;
		int timeout = 0xffff;
		while (timeout-- > 0 && result != 0xfe)
			sd_read_data(&result, 1);

		if (result != 0xfe) {
			ret = -EIO;
			printf(__WARN("sdread")" %d\n", bufs[i]->sectorno);
			break;
		}

		sd_read_data_dma(bufs[i]->data, BSIZE);

		uint8 dummy_crc[2];
		sd_read_data(dummy_crc, 2);
	}
	sd_end_cmd();

	sd_send_cmd(SD_CMD12, 0, 0);
	sd_get_response_R1();
	sd_end_cmd();	// this is needed

out:
	sd_end_cmd();
	if (sdcard_read_done(bufs[0]))
		sdcard_write_start();
	return ret;
}

static void sdcard_write(struct buf *b)
{
	// uint8 start_token = 0xfe;
	uint8 start_token = 0xfc;
	sd_write_data(&start_token, 1);

	// we don't block inside
	sd_write_data_dma_no_wait(b->data, BSIZE);
}

static int sdcard_multiple_write(struct buf *b, int nbuf)
{
	uint32 address = is_standard_sd ?
						b->sectorno << 9 :
						b->sectorno;

	int ret;
	sd_send_cmd(SD_CMD55, 0, 0);
	ret = sd_get_response_R1();
	sd_end_cmd();
	if (ret != 0) {
		printf(__ERROR("CMD55")" error\n");
		return -EIO;
	}

	sd_send_cmd(SD_ACMD23, nbuf, 0);
	ret = sd_get_response_R1();
	sd_end_cmd();
	if (ret != 0) {
		printf(__ERROR("ACMD23")" error\n");
		return -EIO;
	}

	sd_send_cmd(SD_CMD25, address, 0);
	if (sd_get_response_R1() != 0) {
		sd_end_cmd();
		printf(__ERROR("CMD25")" error\n");
		return -EIO;
	}

	sd_status.wcount = nbuf;
	sdcard_write(b);

	// see you in the interrupt handler	
	return 0;
}

static void sdcard_multiple_write_wait(void)
{
	dmac_ch_clear_intr(DMAC_CHANNEL0, 0);
	spi_send_data_dma_clean_up(SPI_DEVICE_0);

	uint8 dummy_crc[2] = {0xff, 0xff};
	sd_write_data(dummy_crc, 2);

	// waiting sdcard programming, dma can't do this
	uint8 result = 0xff;
	int timeout;
	for (timeout = 0xfffff; timeout >= 0 && (result & 0x1f) != 0x5; timeout--)
		sd_read_data(&result, 1);
	if (timeout < 0)
		panic("sdcard_intr: response 1");	// really don't know what to do

	for (timeout = 0xfffff, result = 0; timeout >= 0 && result == 0; timeout--)
		sd_read_data(&result, 1);
	if (timeout < 0)
		panic("sdcard_intr: response 2");	// really don't know what to do
}

static void sdcard_multiple_write_stop(void)
{
	uint8 token = 0xfd;		// stop token
	sd_write_data(&token, 1);

	for (int timeout = 0xffff; timeout >= 0 && token != 0xff; timeout--)
		sd_read_data(&token, 1);

	sd_end_cmd();

	sd_send_cmd(SD_CMD12, 0, 0);
	sd_get_response_R1();
	sd_end_cmd();

	// check writing result
	sd_send_cmd(SD_CMD13, 0, 0);
	if (sd_get_response_R1() != 0)
		panic("sdcard_intr: CMD13 bad response");

	uint8 error = 0xff;
	sd_read_data(&error, 1);
	sd_end_cmd();
	if (error) {
		printf(__ERROR("sdcard_intr")" write error %x\n", error);
		panic("sdcard_intr");
	}
}

void sdcard_write_start(void)
{
	acquire(&sd_wqueue.lock);

	struct d_list *dl = sd_wqueue.head.next;
	// is the queue empty?
	if (dl == &sd_wqueue.head) {
		release(&sd_wqueue.lock);
		return;
	}

	acquire(&sdcard_lock.lk);
	// check sdcard status
	if (sd_status.busy || sd_status.rpending) {
		/**
		 * If we enter here where busy == 0 and rpending is non-zero,
		 * it means this rpending is set in sdcard_read_done(), where
		 * the proc there will waken the next reader. Thus, we don't
		 * need to do a wake up.
		 */
		sd_status.wpending = 1;
		release(&sdcard_lock.lk);
		release(&sd_wqueue.lock);
		return;
	}

	// we get the control now
	sd_status.busy = BUSY_WRITE;
	release(&sdcard_lock.lk);

	struct buf *b = container_of(dl, struct buf, list);
	int nbuf = 1;

	uint32 sec = b->sectorno;
	for (dl = dl->next; dl != &sd_wqueue.head; dl = dl->next) {
		struct buf *next = container_of(dl, struct buf, list);
		if (next->sectorno == ++sec)	// consecutive sector
			nbuf++;
		else
			break;
	}

	b->disk = 1;
	b->dirty = 0;
	release(&sd_wqueue.lock);

	if (sdcard_multiple_write(b, nbuf) < 0) {
		// unset status
		acquire(&sd_wqueue.lock);
		b->disk = 0;
		b->dirty = 1;

		acquire(&sdcard_lock.lk);
		release(&sd_wqueue.lock);

		sd_status.busy = 0;
		sd_status.wpending = 1;
		if (sd_status.rpending)
			/**
			 * We enter here because rpending is non-zero.
			 * But this case is different, since the busy
			 * flag was set by us. So this rpending is set
			 * in sdcard_read(), where there is a reader
			 * waiting for the control, and only us can
			 * wake him up.
			 */
			wakeup(&sd_status.rpending);
		release(&sdcard_lock.lk);
	}

}

int sdcard_submit(struct buf *b)
{
	int res = 0;
	acquire(&sd_wqueue.lock);

	if (b->dirty == 0 && b->disk == 0) {
		dlist_add_before(&sd_wqueue.head, &b->list);
		res = 0x1;
	}
	b->dirty = 1;

	acquire(&sdcard_lock.lk);
	release(&sd_wqueue.lock);
	sd_status.wpending = 1;
	if (sd_status.busy)	// tell the caller that transmission is on
		res |= 0x2;
	release(&sdcard_lock.lk);
	return res;
}

void sdcard_intr(void)
{
	// acquire(&sdcard_lock.lk);
	if (sd_status.busy == BUSY_READ) {
		// release(&sdcard_lock.lk);
		dmac_ch_clear_intr(DMAC_CHANNEL0, 1);
		// reader is waiting out there
		// him will do the clean work himself
		return;
	} else if (sd_status.busy != BUSY_WRITE)
		panic("sdcard_intr: unknown busy");

	// but writer doesn't wait, so we need to clean up for him
	// release(&sdcard_lock.lk);

	// waiting for programming
	sdcard_multiple_write_wait();

	acquire(&sd_wqueue.lock);
	struct d_list *dl = sd_wqueue.head.next;
	struct buf *b = container_of(dl, struct buf, list);
	struct buf *bnext;
	int redo = 0;

	dlist_del(dl);
	b->disk = 0;
	// whether some one wrote this buf when we transmitting it
	if (b->dirty) {
		redo = 1;
		dlist_add_before(&sd_wqueue.head, dl);
	}

	dl = sd_wqueue.head.next;
	bnext = (dl == &sd_wqueue.head) ? NULL :
			container_of(dl, struct buf, list);

	if (--sd_status.wcount > 0) {
		if (bnext == NULL || bnext->sectorno != b->sectorno + 1) {
			sdcard_multiple_write_stop();
			panic("sdcard_intr: bad sd_status.wcount");
		}
		bnext->dirty = 0;
		bnext->disk = 1;
		release(&sd_wqueue.lock);
		sdcard_write(bnext);
		goto out;
	}
	else if (sd_status.rpending || bnext == NULL) {	// race read
		release(&sd_wqueue.lock);
		sdcard_multiple_write_stop();
	}
	else {
		int nbuf = 1;
		uint32 sec = bnext->sectorno;

		// preview the consecutive count
		for (dl = dl->next; dl != &sd_wqueue.head; dl = dl->next) {
			struct buf *next = container_of(dl, struct buf, list);
			if (next->sectorno == ++sec)	// consecutive sector
				nbuf++;
			else
				break;
		}

		bnext->dirty = 0;
		bnext->disk = 1;
		release(&sd_wqueue.lock);
		// printf("nbuf = %d\n", nbuf);
		if (nbuf <= 2 && bnext->sectorno == b->sectorno + 1) {
			sd_status.wcount = nbuf;
			sdcard_write(bnext);
		} else {
			sdcard_multiple_write_stop();

			if (sdcard_multiple_write(bnext, nbuf) < 0) {
				// unset status
				acquire(&sd_wqueue.lock);
				bnext->dirty = 1;
				bnext->disk = 0;
				release(&sd_wqueue.lock);
				goto stop_out;
			}
		}
		goto out;
	}

stop_out:
	acquire(&sdcard_lock.lk);
	sd_status.busy = 0;
	if (sd_status.rpending)
		wakeup(&sd_status.rpending);
	if (bnext)
		sd_status.wpending = 1;
	release(&sdcard_lock.lk);

out:
	if (!redo)
		bput(b);
}

int sdcard_wqueue_empty(void)
{
	// race test
	return sd_wqueue.head.next == &sd_wqueue.head && 
			sd_wqueue.head.prev == &sd_wqueue.head;
}

void spi_init(spi_device_num_t spi_num, spi_work_mode_t work_mode, spi_frame_format_t frame_format,
			  uint64 data_bit_length, uint32 endian)
{
	// configASSERT(data_bit_length >= 4 && data_bit_length <= 32);
	// configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);
	// spi_clk_init(spi_num);

	// uint8 dfs_offset, frf_offset, work_mode_offset;
	uint8 dfs_offset = 0;
	uint8 frf_offset = 0;
	uint8 work_mode_offset = 0;
	switch(spi_num)
	{
		case 0:
		case 1:
			dfs_offset = 16;
			frf_offset = 21;
			work_mode_offset = 6;
			break;
		case 2:
			// configASSERT(!"Spi Bus 2 Not Support!");
			break;
		case 3:
		default:
			dfs_offset = 0;
			frf_offset = 22;
			work_mode_offset = 8;
			break;
	}

	switch(frame_format)
	{
		case SPI_FF_DUAL:
			// configASSERT(data_bit_length % 2 == 0);
			break;
		case SPI_FF_QUAD:
			// configASSERT(data_bit_length % 4 == 0);
			break;
		case SPI_FF_OCTAL:
			// configASSERT(data_bit_length % 8 == 0);
			break;
		default:
			break;
	}
	volatile spi_t *spi_adapter = spi[spi_num];
	if(spi_adapter->baudr == 0)
		spi_adapter->baudr = 0x14;
	spi_adapter->imr = 0x00;
	spi_adapter->dmacr = 0x00;
	spi_adapter->dmatdlr = 0x10;
	spi_adapter->dmardlr = 0x00;
	spi_adapter->ser = 0x00;
	spi_adapter->ssienr = 0x00;
	spi_adapter->ctrlr0 = (work_mode << work_mode_offset) | (frame_format << frf_offset) | ((data_bit_length - 1) << dfs_offset);
	spi_adapter->spi_ctrlr0 = 0;
	spi_adapter->endian = endian;
}

static void spi_set_tmod(uint8 spi_num, uint32 tmod)
{
	// configASSERT(spi_num < SPI_DEVICE_MAX);
	volatile spi_t *spi_handle = spi[spi_num];
	uint8 tmod_offset = 0;
	switch(spi_num)
	{
		case 0:
		case 1:
		case 2:
			tmod_offset = 8;
			break;
		case 3:
		default:
			tmod_offset = 10;
			break;
	}
	set_bit(&spi_handle->ctrlr0, 3 << tmod_offset, tmod << tmod_offset);
}

static spi_transfer_width_t spi_get_frame_size(uint64 data_bit_length)
{
	if(data_bit_length < 8)
		return SPI_TRANS_CHAR;
	else if(data_bit_length < 16)
		return SPI_TRANS_SHORT;
	return SPI_TRANS_INT;
}

void spi_send_data_normal(spi_device_num_t spi_num, spi_chip_select_t chip_select, const uint8 *tx_buff, uint64 tx_len)
{
	// configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);

	uint64 index, fifo_len;
	spi_set_tmod(spi_num, SPI_TMOD_TRANS);

	volatile spi_t *spi_handle = spi[spi_num];

	// uint8 dfs_offset;
	uint8 dfs_offset = 0;
	switch(spi_num)
	{
		case 0:
		case 1:
			dfs_offset = 16;
			break;
		case 2:
			// configASSERT(!"Spi Bus 2 Not Support!");
			break;
		case 3:
		default:
			dfs_offset = 0;
			break;
	}
	uint32 data_bit_length = (spi_handle->ctrlr0 >> dfs_offset) & 0x1F;
	spi_transfer_width_t frame_width = spi_get_frame_size(data_bit_length);

	uint8 v_misalign_flag = 0;
	uint32 v_send_data;
	if((uintptr_t)tx_buff % frame_width)
		v_misalign_flag = 1;

	spi_handle->ssienr = 0x01;
	spi_handle->ser = 1U << chip_select;
	uint32 i = 0;
	while(tx_len)
	{
		fifo_len = 32 - spi_handle->txflr;
		fifo_len = fifo_len < tx_len ? fifo_len : tx_len;
		switch(frame_width)
		{
			case SPI_TRANS_INT:
				fifo_len = fifo_len / 4 * 4;
				if(v_misalign_flag)
				{
					for(index = 0; index < fifo_len; index += 4)
					{
						// memcpy(&v_send_data, tx_buff + i, 4);
						memmove(&v_send_data, tx_buff + i, 4);
						spi_handle->dr[0] = v_send_data;
						i += 4;
					}
				} else
				{
					for(index = 0; index < fifo_len / 4; index++)
						spi_handle->dr[0] = ((uint32 *)tx_buff)[i++];
				}
				break;
			case SPI_TRANS_SHORT:
				fifo_len = fifo_len / 2 * 2;
				if(v_misalign_flag)
				{
					for(index = 0; index < fifo_len; index += 2)
					{
						// memcpy(&v_send_data, tx_buff + i, 2);
						memmove(&v_send_data, tx_buff + i, 2);
						spi_handle->dr[0] = v_send_data;
						i += 2;
					}
				} else
				{
					for(index = 0; index < fifo_len / 2; index++)
						spi_handle->dr[0] = ((uint16 *)tx_buff)[i++];
				}
				break;
			default:
				for(index = 0; index < fifo_len; index++)
					spi_handle->dr[0] = tx_buff[i++];
				break;
		}
		tx_len -= fifo_len;
	}
	while((spi_handle->sr & 0x05) != 0x04)
		;
	spi_handle->ser = 0x00;
	spi_handle->ssienr = 0x00;
}

void spi_send_data_standard(spi_device_num_t spi_num, spi_chip_select_t chip_select, const uint8 *cmd_buff,
							uint64 cmd_len, const uint8 *tx_buff, uint64 tx_len)
{
	// configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);
	// uint8 *v_buf = malloc(cmd_len + tx_len);
	if (SPI_BUF_SIZE < cmd_len + tx_len)
		panic("spi: spi_buf too small");
	uint8 *v_buf = spi_buf;
	uint64 i;
	for(i = 0; i < cmd_len; i++)
		v_buf[i] = cmd_buff[i];
	for(i = 0; i < tx_len; i++)
		v_buf[cmd_len + i] = tx_buff[i];

	spi_send_data_normal(spi_num, chip_select, v_buf, cmd_len + tx_len);
	// free((void *)v_buf);
	// freepage((void *)v_buf);
}

void spi_receive_data_standard(spi_device_num_t spi_num, spi_chip_select_t chip_select, const uint8 *cmd_buff,
							   uint64 cmd_len, uint8 *rx_buff, uint64 rx_len)
{
	// configASSERT(spi_num < SPI_DEVICE_MAX && spi_num != 2);
	uint64 index, fifo_len;
	if(cmd_len == 0)
		spi_set_tmod(spi_num, SPI_TMOD_RECV);
	else
		spi_set_tmod(spi_num, SPI_TMOD_EEROM);
	volatile spi_t *spi_handle = spi[spi_num];

	// uint8 dfs_offset;
	uint8 dfs_offset = 0;
	switch(spi_num)
	{
		case 0:
		case 1:
			dfs_offset = 16;
			break;
		case 2:
			// configASSERT(!"Spi Bus 2 Not Support!");
			break;
		case 3:
		default:
			dfs_offset = 0;
			break;
	}
	uint32 data_bit_length = (spi_handle->ctrlr0 >> dfs_offset) & 0x1F;
	spi_transfer_width_t frame_width = spi_get_frame_size(data_bit_length);

	uint32 i = 0;
	uint64 v_cmd_len = cmd_len / frame_width;
	uint32 v_rx_len = rx_len / frame_width;

	spi_handle->ctrlr1 = (uint32)(v_rx_len - 1);
	spi_handle->ssienr = 0x01;

	while(v_cmd_len)
	{
		fifo_len = 32 - spi_handle->txflr;
		fifo_len = fifo_len < v_cmd_len ? fifo_len : v_cmd_len;
		switch(frame_width)
		{
			case SPI_TRANS_INT:
				for(index = 0; index < fifo_len; index++)
					spi_handle->dr[0] = ((uint32 *)cmd_buff)[i++];
				break;
			case SPI_TRANS_SHORT:
				for(index = 0; index < fifo_len; index++)
					spi_handle->dr[0] = ((uint16 *)cmd_buff)[i++];
				break;
			default:
				for(index = 0; index < fifo_len; index++)
					spi_handle->dr[0] = cmd_buff[i++];
				break;
		}
		spi_handle->ser = 1U << chip_select;
		v_cmd_len -= fifo_len;
	}

	if(cmd_len == 0)
	{
		spi_handle->dr[0] = 0xffffffff;
		spi_handle->ser = 1U << chip_select;
	}

	i = 0;
	while(v_rx_len)
	{
		fifo_len = spi_handle->rxflr;
		fifo_len = fifo_len < v_rx_len ? fifo_len : v_rx_len;
		switch(frame_width)
		{
			case SPI_TRANS_INT:
				for(index = 0; index < fifo_len; index++)
					((uint32 *)rx_buff)[i++] = spi_handle->dr[0];
				break;
			case SPI_TRANS_SHORT:
				for(index = 0; index < fifo_len; index++)
					((uint16 *)rx_buff)[i++] = (uint16)spi_handle->dr[0];
				break;
			default:
				for(index = 0; index < fifo_len; index++)
					rx_buff[i++] = (uint8)spi_handle->dr[0];
				break;
		}

		v_rx_len -= fifo_len;
	}

	spi_handle->ser = 0x00;
	spi_handle->ssienr = 0x00;
}

static spi_frame_format_t spi_get_frame_format(spi_device_num_t spi_num)
{
	uint8 frf_offset = 0;
	switch(spi_num)
	{
		case 0:
		case 1:
			frf_offset = 21;
			break;
		case 2:
			// configASSERT(!"Spi Bus 2 Not Support!");
			break;
		case 3:
		default:
			frf_offset = 22;
			break;
	}
	volatile spi_t *spi_adapter = spi[spi_num];
	return ((spi_adapter->ctrlr0 >> frf_offset) & 0x3);
}

void spi_receive_data_no_cmd_dma(dmac_channel_number_t dma_receive_channel_num,
								spi_device_num_t spi_num, spi_chip_select_t chip_select,
								uint8 *rx_buff, uint64 rx_len)
{
	volatile spi_t *spi_handle = spi[spi_num];

	spi_set_tmod(spi_num, SPI_TMOD_RECV);

	spi_handle->ctrlr1 = (uint32)(rx_len - 1);
	spi_handle->dmacr = 0x3;
	spi_handle->ssienr = 0x01;

	sysctl_dma_select((sysctl_dma_channel_t)dma_receive_channel_num, SYSCTL_DMA_SELECT_SSI0_RX_REQ + spi_num * 2);

	dmac_set_single_mode(dma_receive_channel_num, (void *)(&spi_handle->dr[0]), rx_buff,
						DMAC_ADDR_NOCHANGE, DMAC_ADDR_INCREMENT,
						DMAC_MSIZE_1, DMAC_TRANS_WIDTH_32, rx_len);

	if (spi_get_frame_format(spi_num) == SPI_FF_STANDARD)
		spi[spi_num]->dr[0] = 0xffffffff;

	spi_handle->ser = 1U << chip_select;
	dmac_wait_done(dma_receive_channel_num);

	spi_handle->ser = 0x00;
	spi_handle->ssienr = 0x00;
}

void spi_send_data_no_cmd_dma(dmac_channel_number_t channel_num,
							spi_device_num_t spi_num, spi_chip_select_t chip_select,
							uint8 const *tx_buff, uint64 tx_len, int wait)
{
	volatile spi_t *spi_handle = spi[spi_num];

	spi_set_tmod(spi_num, SPI_TMOD_TRANS);
	spi_handle->dmacr = 0x2;
	spi_handle->ssienr = 0x01;

	sysctl_dma_select((sysctl_dma_channel_t)channel_num, SYSCTL_DMA_SELECT_SSI0_TX_REQ + spi_num * 2);
	dmac_set_single_mode(channel_num, tx_buff, (void *)(&spi_handle->dr[0]), DMAC_ADDR_INCREMENT, DMAC_ADDR_NOCHANGE,
						 DMAC_MSIZE_4, DMAC_TRANS_WIDTH_32, tx_len);
	spi_handle->ser = 1U << chip_select;

	if (wait) {
		dmac_wait_done(channel_num);

		while((spi_handle->sr & 0x05) != 0x04)
			;
		spi_handle->ser = 0x00;
		spi_handle->ssienr = 0x00;
	}
}

void spi_send_data_dma_clean_up(spi_device_num_t spi_num)
{
	volatile spi_t *spi_handle = spi[spi_num];
	while((spi_handle->sr & 0x05) != 0x04)
		;
	spi_handle->ser = 0x00;
	spi_handle->ssienr = 0x00;
}

void spi_set_baudr(spi_device_num_t spi_num, uint32 baudr)
{
	if (baudr < 2)
		baudr = 2;
	else if (baudr > 65534)
		baudr = 65534;
	volatile spi_t *spi_adapter = spi[spi_num];
	spi_adapter->baudr = baudr;
}

