static int sysctl_clock_bus_en(sysctl_clock_t clock, uint8 en)
{
	/*
	 * The timer is under APB0, to prevent apb0_clk_en1 and apb0_clk_en0
	 * on same register, we split it to peripheral and central two
	 * registers, to protect CPU close apb0 clock accidentally.
	 *
	 * The apb0_clk_en0 and apb0_clk_en1 have same function,
	 * one of them set, the APB0 clock enable.
	 */

	/* The APB clock should carefully disable */
	if(en)
	{
		switch(clock)
		{
			/*
			 * These peripheral devices are under APB0
			 * GPIO, UART1, UART2, UART3, SPI_SLAVE, I2S0, I2S1,
			 * I2S2, I2C0, I2C1, I2C2, FPIOA, SHA256, TIMER0,
			 * TIMER1, TIMER2
			 */
			case SYSCTL_CLOCK_GPIO:
			case SYSCTL_CLOCK_SPI2:
			case SYSCTL_CLOCK_I2S0:
			case SYSCTL_CLOCK_I2S1:
			case SYSCTL_CLOCK_I2S2:
			case SYSCTL_CLOCK_I2C0:
			case SYSCTL_CLOCK_I2C1:
			case SYSCTL_CLOCK_I2C2:
			case SYSCTL_CLOCK_UART1:
			case SYSCTL_CLOCK_UART2:
			case SYSCTL_CLOCK_UART3:
			case SYSCTL_CLOCK_FPIOA:
			case SYSCTL_CLOCK_TIMER0:
			case SYSCTL_CLOCK_TIMER1:
			case SYSCTL_CLOCK_TIMER2:
			case SYSCTL_CLOCK_SHA:
				sysctl->clk_en_cent.apb0_clk_en = en;
				break;

			/*
			 * These peripheral devices are under APB1
			 * WDT, AES, OTP, DVP, SYSCTL
			 */
			case SYSCTL_CLOCK_AES:
			case SYSCTL_CLOCK_WDT0:
			case SYSCTL_CLOCK_WDT1:
			case SYSCTL_CLOCK_OTP:
			case SYSCTL_CLOCK_RTC:
				sysctl->clk_en_cent.apb1_clk_en = en;
				break;

			/*
			 * These peripheral devices are under APB2
			 * SPI0, SPI1
			 */
			case SYSCTL_CLOCK_SPI0:
			case SYSCTL_CLOCK_SPI1:
				sysctl->clk_en_cent.apb2_clk_en = en;
				break;

			default:
				break;
		}
	}

	return 0;
}

static int sysctl_clock_device_en(sysctl_clock_t clock, uint8 en)
{
	switch(clock)
	{
		/*
		 * These devices are PLL
		 */
		case SYSCTL_CLOCK_PLL0:
			sysctl->pll0.pll_out_en0 = en;
			break;
		case SYSCTL_CLOCK_PLL1:
			sysctl->pll1.pll_out_en1 = en;
			break;
		case SYSCTL_CLOCK_PLL2:
			sysctl->pll2.pll_out_en2 = en;
			break;

		/*
		 * These devices are CPU, SRAM, APB bus, ROM, DMA, AI
		 */
		case SYSCTL_CLOCK_CPU:
			sysctl->clk_en_cent.cpu_clk_en = en;
			break;
		case SYSCTL_CLOCK_SRAM0:
			sysctl->clk_en_cent.sram0_clk_en = en;
			break;
		case SYSCTL_CLOCK_SRAM1:
			sysctl->clk_en_cent.sram1_clk_en = en;
			break;
		case SYSCTL_CLOCK_APB0:
			sysctl->clk_en_cent.apb0_clk_en = en;
			break;
		case SYSCTL_CLOCK_APB1:
			sysctl->clk_en_cent.apb1_clk_en = en;
			break;
		case SYSCTL_CLOCK_APB2:
			sysctl->clk_en_cent.apb2_clk_en = en;
			break;
		case SYSCTL_CLOCK_ROM:
			sysctl->clk_en_peri.rom_clk_en = en;
			break;
		case SYSCTL_CLOCK_DMA:
			sysctl->clk_en_peri.dma_clk_en = en;
			break;
		case SYSCTL_CLOCK_AI:
			sysctl->clk_en_peri.ai_clk_en = en;
			break;
		case SYSCTL_CLOCK_DVP:
			sysctl->clk_en_peri.dvp_clk_en = en;
			break;
		case SYSCTL_CLOCK_FFT:
			sysctl->clk_en_peri.fft_clk_en = en;
			break;
		case SYSCTL_CLOCK_SPI3:
			sysctl->clk_en_peri.spi3_clk_en = en;
			break;

		/*
		 * These peripheral devices are under APB0
		 * GPIO, UART1, UART2, UART3, SPI_SLAVE, I2S0, I2S1,
		 * I2S2, I2C0, I2C1, I2C2, FPIOA, SHA256, TIMER0,
		 * TIMER1, TIMER2
		 */
		case SYSCTL_CLOCK_GPIO:
			sysctl->clk_en_peri.gpio_clk_en = en;
			break;
		case SYSCTL_CLOCK_SPI2:
			sysctl->clk_en_peri.spi2_clk_en = en;
			break;
		case SYSCTL_CLOCK_I2S0:
			sysctl->clk_en_peri.i2s0_clk_en = en;
			break;
		case SYSCTL_CLOCK_I2S1:
			sysctl->clk_en_peri.i2s1_clk_en = en;
			break;
		case SYSCTL_CLOCK_I2S2:
			sysctl->clk_en_peri.i2s2_clk_en = en;
			break;
		case SYSCTL_CLOCK_I2C0:
			sysctl->clk_en_peri.i2c0_clk_en = en;
			break;
		case SYSCTL_CLOCK_I2C1:
			sysctl->clk_en_peri.i2c1_clk_en = en;
			break;
		case SYSCTL_CLOCK_I2C2:
			sysctl->clk_en_peri.i2c2_clk_en = en;
			break;
		case SYSCTL_CLOCK_UART1:
			sysctl->clk_en_peri.uart1_clk_en = en;
			break;
		case SYSCTL_CLOCK_UART2:
			sysctl->clk_en_peri.uart2_clk_en = en;
			break;
		case SYSCTL_CLOCK_UART3:
			sysctl->clk_en_peri.uart3_clk_en = en;
			break;
		case SYSCTL_CLOCK_FPIOA:
			sysctl->clk_en_peri.fpioa_clk_en = en;
			break;
		case SYSCTL_CLOCK_TIMER0:
			sysctl->clk_en_peri.timer0_clk_en = en;
			break;
		case SYSCTL_CLOCK_TIMER1:
			sysctl->clk_en_peri.timer1_clk_en = en;
			break;
		case SYSCTL_CLOCK_TIMER2:
			sysctl->clk_en_peri.timer2_clk_en = en;
			break;
		case SYSCTL_CLOCK_SHA:
			sysctl->clk_en_peri.sha_clk_en = en;
			break;

		/*
		 * These peripheral devices are under APB1
		 * WDT, AES, OTP, DVP, SYSCTL
		 */
		case SYSCTL_CLOCK_AES:
			sysctl->clk_en_peri.aes_clk_en = en;
			break;
		case SYSCTL_CLOCK_WDT0:
			sysctl->clk_en_peri.wdt0_clk_en = en;
			break;
		case SYSCTL_CLOCK_WDT1:
			sysctl->clk_en_peri.wdt1_clk_en = en;
			break;
		case SYSCTL_CLOCK_OTP:
			sysctl->clk_en_peri.otp_clk_en = en;
			break;
		case SYSCTL_CLOCK_RTC:
			sysctl->clk_en_peri.rtc_clk_en = en;
			break;

		/*
		 * These peripheral devices are under APB2
		 * SPI0, SPI1
		 */
		case SYSCTL_CLOCK_SPI0:
			sysctl->clk_en_peri.spi0_clk_en = en;
			break;
		case SYSCTL_CLOCK_SPI1:
			sysctl->clk_en_peri.spi1_clk_en = en;
			break;

		default:
			break;
	}

	return 0;
}

int sysctl_clock_enable(sysctl_clock_t clock)
{
	if(clock >= SYSCTL_CLOCK_MAX)
		return -1;
	sysctl_clock_bus_en(clock, 1);
	sysctl_clock_device_en(clock, 1);
	return 0;
}

int sysctl_dma_select(sysctl_dma_channel_t channel, sysctl_dma_select_t select)
{
	sysctl_dma_sel0_t dma_sel0;
	sysctl_dma_sel1_t dma_sel1;

	/* Read register from bus */
	dma_sel0 = sysctl->dma_sel0;
	dma_sel1 = sysctl->dma_sel1;
	switch(channel)
	{
		case SYSCTL_DMA_CHANNEL_0:
			dma_sel0.dma_sel0 = select;
			break;

		case SYSCTL_DMA_CHANNEL_1:
			dma_sel0.dma_sel1 = select;
			break;

		case SYSCTL_DMA_CHANNEL_2:
			dma_sel0.dma_sel2 = select;
			break;

		case SYSCTL_DMA_CHANNEL_3:
			dma_sel0.dma_sel3 = select;
			break;

		case SYSCTL_DMA_CHANNEL_4:
			dma_sel0.dma_sel4 = select;
			break;

		case SYSCTL_DMA_CHANNEL_5:
			dma_sel1.dma_sel5 = select;
			break;

		default:
			return -1;
	}

	/* Write register back to bus */
	sysctl->dma_sel0 = dma_sel0;
	sysctl->dma_sel1 = dma_sel1;

	return 0;
}

struct disk {
	// the virtio driver and device mostly communicate through a set of
	// structures in RAM. pages[] allocates that memory. pages[] is a
	// global (instead of calls to kalloc()) because it must consist of
	// two contiguous pages of page-aligned physical memory.
	char pages[2 * PGSIZE];

	// pages[] is divided into three regions (descriptors, avail, and
	// used), as explained in Section 2.6 of the virtio specification
	// for the legacy interface.
	// https://docs.oasis-open.org/virtio/virtio/v1.1/virtio-v1.1.pdf

	// the first region of pages[] is a set (not a ring) of DMA
	// descriptors, with which the driver tells the device where to read
	// and write individual disk operations. there are NUM descriptors.
	// most commands consist of a "chain" (a linked list) of a couple of
	// these descriptors.
	// points into pages[].
	struct virtq_desc *desc;

	// next is a ring in which the driver writes descriptor numbers
	// that the driver would like the device to process.  it only
	// includes the head descriptor of each chain. the ring has
	// NUM elements.
	// points into pages[].
	struct virtq_avail *avail;

	// finally a ring in which the device writes descriptor numbers that
	// the device has finished processing (just the head of each chain).
	// there are NUM used ring entries.
	// points into pages[].
	struct virtq_used *used;

	// our own book-keeping.
	char free[NUM];  // is a descriptor free?
	uint16 used_idx; // we've looked this far in used[2..NUM].
	uint16 nwait;

	// track info about in-flight operations,
	// for use when completion interrupt arrives.
	// indexed by first descriptor index of chain.
	struct {
		struct buf *b;
		char status;
		int idx1;	// first index of a chain
	} info[NUM];

	// queue of buf to write (read doesn't need)
	// buf::dirty is protected by this queue's lock
	struct wait_queue queue;
	int queue_running;

	// disk command headers.
	// one-for-one with descriptors, for convenience.
	struct virtio_blk_req ops[NUM];

	struct spinlock vdisk_lock;

} __attribute__ ((aligned (PGSIZE)))

void
virtio_disk_init(void)
{
	uint32 status = 0;

	initlock(&disk.vdisk_lock, "virtio_disk");
	wait_queue_init(&disk.queue, "vdisk_queue");
	disk.queue_running = 0;
	disk.nwait = 0;

	if (*R(VIRTIO_MMIO_MAGIC_VALUE) != 0x74726976 ||
		*R(VIRTIO_MMIO_VERSION) != 1 ||
		*R(VIRTIO_MMIO_DEVICE_ID) != 2 ||
		*R(VIRTIO_MMIO_VENDOR_ID) != 0x554d4551)
	{
		panic("could not find virtio disk");
	}

	status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
	*R(VIRTIO_MMIO_STATUS) = status;

	status |= VIRTIO_CONFIG_S_DRIVER;
	*R(VIRTIO_MMIO_STATUS) = status;

	// negotiate features
	uint64 features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
	features &= ~(1 << VIRTIO_BLK_F_RO);
	features &= ~(1 << VIRTIO_BLK_F_SCSI);
	features &= ~(1 << VIRTIO_BLK_F_CONFIG_WCE);
	features &= ~(1 << VIRTIO_BLK_F_MQ);
	features &= ~(1 << VIRTIO_F_ANY_LAYOUT);
	features &= ~(1 << VIRTIO_RING_F_EVENT_IDX);
	features &= ~(1 << VIRTIO_RING_F_INDIRECT_DESC);
	*R(VIRTIO_MMIO_DRIVER_FEATURES) = features;

	// tell device that feature negotiation is complete.
	status |= VIRTIO_CONFIG_S_FEATURES_OK;
	*R(VIRTIO_MMIO_STATUS) = status;

	// tell device we're completely ready.
	status |= VIRTIO_CONFIG_S_DRIVER_OK;
	*R(VIRTIO_MMIO_STATUS) = status;

	*R(VIRTIO_MMIO_GUEST_PAGE_SIZE) = PGSIZE;

	// initialize queue 0.
	*R(VIRTIO_MMIO_QUEUE_SEL) = 0;
	uint32 max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
	if (max == 0)
		panic("virtio disk has no queue 0");
	if (max < NUM)
		panic("virtio disk max queue too short");
	*R(VIRTIO_MMIO_QUEUE_NUM) = NUM;
	memset(disk.pages, 0, sizeof(disk.pages));
	*R(VIRTIO_MMIO_QUEUE_PFN) = ((uint64)disk.pages) >> PGSHIFT;

	// desc = pages -- num * virtq_desc
	// avail = pages + 0x40 -- 2 * uint16, then num * uint16
	// used = pages + 4096 -- 2 * uint16, then num * vRingUsedElem

	disk.desc = (struct virtq_desc *) disk.pages;
	disk.avail = (struct virtq_avail *)(disk.pages + NUM * sizeof(struct virtq_desc));
	disk.used = (struct virtq_used *) (disk.pages + PGSIZE);

	// all NUM descriptors start out unused.
	for (int i = 0; i < NUM; i++)
		disk.free[i] = 1;

	// plic.c and trap.c arrange for interrupts from VIRTIO0_IRQ.
}

static int
alloc_desc()
{
	for (int i = 0; i < NUM; i++) {
		if (disk.free[i]) {
			disk.free[i] = 0;
			return i;
		}
	}
	return -1;
}

static void
free_desc(int i)
{
	if (i >= NUM)
		panic("free_desc 1");
	if (disk.free[i])
		panic("free_desc 2");
	disk.desc[i].addr = 0;
	disk.desc[i].len = 0;
	disk.desc[i].flags = 0;
	disk.desc[i].next = 0;
	disk.free[i] = 1;
	if (disk.nwait > 0)
		wakeup(&disk.free[0]);
}

static void
free_chain(int i)
{
	while (1) {
		int flag = disk.desc[i].flags;
		int nxt = disk.desc[i].next;
		free_desc(i);
		if (flag & VRING_DESC_F_NEXT)
			i = nxt;
		else
			break;
	}
}

static int alloc_descs(int * restrict idx, int n)
{
	for (int i = 0; i < n; i++) {
		idx[i] = alloc_desc();
		if (idx[i] < 0) {
			for (int j = 0; j < i; j++)
				free_desc(idx[j]);
			return -1;
		}
	}
	return 0;
}

static int
virtio_disk_rw(struct buf * restrict bufs[], int nbuf, int write)
{
	int ndesc = nbuf + 2;
	if (ndesc > NUM)
		return -1;

	acquire(&disk.vdisk_lock);
	// the spec's Section 5.2 says that legacy block operations use
	// three descriptors: one for type/reserved/sector, one for the
	// data, one for a 1-byte status result.

	// allocate the three descriptors.
	int idx[NUM];
	while (1) {
		if (alloc_descs(idx, ndesc) == 0)
			break;
		if (write) {	// write don't wait
			release(&disk.vdisk_lock);
			return -1;
		}
		disk.nwait++;
		sleep(&disk.free[0], &disk.vdisk_lock);
		disk.nwait--;
	}

	// format the three descriptors.
	// qemu's virtio-blk.c reads them.

	struct virtio_blk_req *buf0 = &disk.ops[idx[0]];
	struct virtq_desc *desc;

	buf0->type = write ? VIRTIO_BLK_T_OUT :	// write the disk
						VIRTIO_BLK_T_IN;	// read the disk
	buf0->reserved = 0;
	buf0->sector = bufs[0]->sectorno;

	// first
	desc = &disk.desc[idx[0]];
	desc->addr = (uint64) buf0;
	desc->len = sizeof(struct virtio_blk_req);
	desc->flags = VRING_DESC_F_NEXT;
	desc->next = idx[1];

	for (int i = 1; i <= nbuf; i++) {
		desc = &disk.desc[idx[i]];
		desc->addr = (uint64) bufs[i - 1]->data;
		desc->len = BSIZE;
		desc->flags = write ? 0 :				// device reads b->data
							VRING_DESC_F_WRITE;	// device writes b->data
		desc->flags |= VRING_DESC_F_NEXT;
		desc->next = idx[i + 1];
	}

	// last
	desc = &disk.desc[idx[ndesc - 1]];
	desc->addr = (uint64) &disk.info[idx[0]].status;
	desc->len = 1;
	desc->flags = VRING_DESC_F_WRITE;		// device writes the status
	desc->next = 0;

	/**
	 * Record struct buf for virtio_disk_intr().
	 * If we are committing a wirte, we are not going to wait here.
	 * After the write is done, the interrupt handler will use idx1
	 * to free the desc chain that we allocated. In other way, this
	 * is also a hint that this is a write buf, the handler needs to
	 * do something about it.
	 */
	disk.info[idx[0]].idx1 = write ? idx[0] : -1;
	disk.info[idx[0]].status = 0xff;		// device writes 0 on success
	disk.info[idx[0]].b = bufs[0];

	// tell the device the first index in our chain of descriptors.
	disk.avail->ring[disk.avail->idx % NUM] = idx[0];

	__sync_synchronize();

	// tell the device another avail ring entry is available.
	disk.avail->idx += 1; // not % NUM ...

	__sync_synchronize();

	*R(VIRTIO_MMIO_QUEUE_NOTIFY) = 0; // value is queue number

	int res = 0;
	if (!write) {
		bufs[0]->disk = 1;
		// Wait for virtio_disk_intr() to say request has finished.
		while (bufs[0]->disk == 1) {
			// printf(__INFO("virtio_disk_rw")" sleep on %d\n", b->sectorno);
			sleep(bufs[0], &disk.vdisk_lock);
		}
		res = -(disk.info[idx[0]].status != 0);
		free_chain(idx[0]);
	}

	release(&disk.vdisk_lock);
	return res;
}

void
virtio_disk_intr()
{
	struct buf *b;
	struct buf *bufs[NUM];	// bufs that finished writing
	int cnt = 0, i;

	acquire(&disk.vdisk_lock);

	// the device won't raise another interrupt until we tell it
	// we've seen this interrupt, which the following line does.
	// this may race with the device writing new entries to
	// the "used" ring, in which case we may process the new
	// completion entries in this interrupt, and have nothing to do
	// in the next interrupt, which is harmless.
	*R(VIRTIO_MMIO_INTERRUPT_ACK) = *R(VIRTIO_MMIO_INTERRUPT_STATUS) & 0x3;

	__sync_synchronize();

	// the device increments disk.used->idx when it
	// adds an entry to the used ring.
	while (disk.used_idx != disk.used->idx) {
		__sync_synchronize();
		int id = disk.used->ring[disk.used_idx % NUM].id;
		disk.used_idx += 1;

		if (disk.info[id].status != 0)
			panic("virtio_disk_intr status");

		b = disk.info[id].b;
		// disk.info[id].b = 0;
		if (disk.info[id].idx1 < 0) {	// read interrupt
			b->disk = 0;   				// disk is done with buf
			wakeup(b);
		} else {						// write interrupt
			free_chain(disk.info[id].idx1);
			bufs[cnt++] = b;			// collect for convenience
		}
	}
	release(&disk.vdisk_lock);

	if (cnt > 0) {
		acquire(&disk.queue.lock);
		for (i = 0; i < cnt; i++) {			// clean write bufs
			bufs[i]->disk = 0;				// disk is done with buf
			disk.queue_running--;
			if (bufs[i]->dirty)				// some one has touched it again
				bufs[i] = NULL;				// we have to keep it and write again
			else
				dlist_del(&bufs[i]->list);	// done, let go
		}
		release(&disk.queue.lock);

		for (i = 0; i < cnt; i++) {
			if (bufs[i])
				bput(bufs[i]);
		}
	}

	acquire(&disk.queue.lock);
	struct d_list *l = disk.queue.head.next;
	if (l == &disk.queue.head) {			// nothing to write
		release(&disk.queue.lock);
		return;
	}

	for (; l != &disk.queue.head; l = l->next) {
		b = container_of(l, struct buf, list);
		if (!b->disk) {
			b->disk = 1;
			b->dirty = 0;
			disk.queue_running++;
			release(&disk.queue.lock);
			bufs[0] = b;
			if (virtio_disk_rw(bufs, 1, 1) < 0) {
				acquire(&disk.queue.lock);
				b->disk = 0;
				b->dirty = 1;
				disk.queue_running--;
				release(&disk.queue.lock);
			}
			return;
		}
	}
	release(&disk.queue.lock);
}

void virtio_disk_write_start(void)
{
	acquire(&disk.queue.lock);
	if (disk.queue_running > 0) {
		release(&disk.queue.lock);
		return;
	} else if (disk.queue_running < 0)
		panic("virtio_disk_write_start: bad counter");

	struct d_list *l = disk.queue.head.next;
	if (l == &disk.queue.head) {
		release(&disk.queue.lock);
		return;
	}

	struct buf *b[1];
	b[0] = container_of(l, struct buf, list);
	if (b[0]->disk)
		panic("virtio_disk_write_start: on-flight buf");

	b[0]->disk = 1;
	b[0]->dirty = 0;
	disk.queue_running = 1;
	release(&disk.queue.lock);

	if (virtio_disk_rw(b, 1, 1) < 0) {
		/**
		 * This happens when lacking of descs,
		 * but don't worry, since lacking of
		 * descs means some one is reading disk,
		 * so when its interrupt comes, it will
		 * start us.
		 */
		acquire(&disk.queue.lock);
		b[0]->disk = 0;
		b[0]->dirty = 1;
		disk.queue_running--;
		release(&disk.queue.lock);
	}

}

int virtio_disk_submit(struct buf *b)
{
	int res = 0;
	acquire(&disk.queue.lock);

	/**
	 * Test whether this is a new coming member.
	 * When carrying the buf to disk, b->disk
	 * will be set and b->dirty will be cleared.
	 * One of them is non-zero means that this
	 * buf is already in queue.
	 */
	if (b->dirty == 0 && b->disk == 0) {
		dlist_add_before(&disk.queue.head, &b->list);
		res = 0x1;
	}
	b->dirty = 1;
	if (disk.queue_running > 0)	// inform that the queue is on
		res |= 0x2;
	release(&disk.queue.lock);
	return res;
}

int virtio_disk_read(struct buf *b)
{
	struct buf *bufs[1];
	bufs[0] = b;
	return virtio_disk_rw(bufs, 1, 0);
}

int virtio_disk_multiple_read(struct buf *bufs[], int nbuf)
{
	return virtio_disk_rw(bufs, nbuf, 0);
}

struct kmem_node {
	// `config` is meant to keep const after kmem_node init 
	struct kmem_node *next;
	struct {
		//uint64 obj_capa;			// the capacity of each object 
		uint64 obj_size;			// the size of each object 
		uint64 obj_addr;			// the start addr of first avail object 
	} config;
	uint8 avail;		// current available obj num 
	uint8 cnt;		// current allocated count of obj 
	// size of `next` is not fixed according to config.obj_size
	uint8 table[KMEM_OBJ_MAX_COUNT];	// linked list table,  
}

struct kmem_allocator {
	struct spinlock lock;		// the lock to protect this allocator 
	uint obj_size;				// the obj size that allocator allocates 
	uint16 npages;
	uint16 nobjs;
	struct kmem_node *list;		// point to first kmem_node 
	struct kmem_allocator *next;	// point to next kmem_allocator 

}

void kmallocinit(void) {
	// init adam 
	initlock(&(kmem_adam.lock), "kmem_adam");
	kmem_adam.list = NULL;
	kmem_adam.next = NULL;
	kmem_adam.npages = 0;
	kmem_adam.nobjs = 0;
	kmem_adam.obj_size = 
			ROUNDUP16(sizeof(struct kmem_allocator));

	// init kmem_table 
	for (uint8 i = 0; i < KMEM_TABLE_SIZE; i++) {
		kmem_table[i] = NULL;
	}
	int hash = _hash(kmem_adam.obj_size);
	kmem_table[hash] = &kmem_adam;
	initlock(&kmem_table_lock, "kmem_table");

	__debug_info("kmallocinit", "KMEM_NODE_FIX: %d\n", KMEM_NODE_FIX);
	__debug_info("kmallocinit", "init\n");
}

static struct kmem_allocator *get_allocator(uint64 raw_size) {
	uint64 roundup_size = ROUNDUP16(raw_size);
	uint64 hash = _hash(roundup_size);

	// search if allocator already in table 
	// if allocator exists, then kem_table_lock wouldn't be acquired 
	for (struct kmem_allocator *tmp = kmem_table[hash]; 
			NULL != tmp; tmp = tmp->next) {
		if (roundup_size == tmp->obj_size) {
			return tmp;
		}
	}

	// enter critical section 
	acquire(&kmem_table_lock);
	// if the previous update have created the allocator 
	// needed here
	if (NULL != kmem_table[hash] && 
			kmem_table[hash]->obj_size == roundup_size) {
		release(&kmem_table_lock);
		return kmem_table[hash];
	}

	// if not found, then create 

	// as sizeof(struct kmem_allocator) is guaranteed an 
	// allocator at init time, `_malloc_allocator()` should 
	// not enter `critical section` when calling `get_allocator()`
	struct kmem_allocator *tmp = _malloc_allocator();
	if (NULL != tmp) {
		initlock(&(tmp->lock), "kmem_alloc");
		tmp->list = NULL;
		tmp->obj_size = roundup_size;
		tmp->npages = 0;
		tmp->nobjs = 0;
		tmp->next = kmem_table[hash];
		kmem_table[hash] = tmp;
	}

	release(&kmem_table_lock);
	// leave critical section 

	return tmp;
}

void *kmalloc(uint size) {
	// border check for `size`
	if (KMEM_OBJ_MIN_SIZE > size) {
		__debug_warn("kmalloc", "size %d too small, reset to %d\n", size, KMEM_OBJ_MIN_SIZE);
		size = KMEM_OBJ_MIN_SIZE;
	}
	else if (KMEM_OBJ_MAX_SIZE < size) {
		__debug_error("kmalloc", "size %d out of border\n", size);
		return NULL;
	}
	struct kmem_allocator *alloc = get_allocator(size);

	// if failed to alloc 
	if (NULL == alloc) {
		__debug_error("kmalloc", "fail to get allocator\n");
		return NULL;
	}

	// enter critical section `alloc`
	acquire(&(alloc->lock));

	// if no page available 
	if (NULL == alloc->list) {
		struct kmem_node *tmp = (struct kmem_node*)allocpage();
		if (NULL == tmp) {
			release(&(alloc->lock));
			__debug_warn("kmalloc", "fail to allocate a node\n");
			return NULL;
		}
		alloc->npages++;

		uint roundup_size = ROUNDUP16(size);
		uint8 capa = _calc_capa(roundup_size);
		tmp->next = NULL;
		tmp->config.obj_size = roundup_size;
		tmp->config.obj_addr = (uint64)tmp + ROUNDUP16(KMEM_NODE_FIX + capa);

		tmp->avail = 0;
		tmp->cnt = 0;
		for (uint8 i = 0; i < capa - 1; i ++) {
			tmp->table[i] = i + 1;
		}
		tmp->table[capa - 1] = TABLE_END;

		alloc->list = tmp;
	}

	alloc->nobjs++;

	// now the allocator should be ready 
	struct kmem_node *node = alloc->list;
	void *ret;		// the address to be returned 
	ret = (void*)(node->config.obj_addr + 
			((uint64)node->avail) * node->config.obj_size);
	// update `avail` and `cnt`
	node->cnt += 1;
	node->avail = node->table[node->avail];

	// if kmem_node is fully allocated 
	if (TABLE_END == node->avail) {
		alloc->list = node->next;
	}

	release(&(alloc->lock));
	// leave critical section `alloc`

	return ret;
}

void kfree(void *addr) {
	struct kmem_node *node = (struct kmem_node*)PGROUNDDOWN((uint64)addr);
	uint8 avail = ((uint64)addr - node->config.obj_addr) / node->config.obj_size;

	struct kmem_allocator *alloc = get_allocator(node->config.obj_size);

	__debug_info("kfree", "alloc: %p, addr: %p\n", alloc, addr);
	// enter critical section `alloc`
	acquire(&(alloc->lock));

	alloc->nobjs--;

	// if `node` used to be fully allocated, then re-link it to `alloc`
	if (TABLE_END == node->avail) {
		node->next = alloc->list;
		alloc->list = node;
		__debug_info("kfree", "pickup\n");
	}

	// node should be on alloc->list 
	node->table[avail] = node->avail;
	node->avail = avail;
	node->cnt -= 1;

	// if kmem_node has no allocated obj 
	if (0 == node->cnt) {
		__debug_info("kfree", "drop\n");
		struct kmem_node **pprev = &(alloc->list);
		struct kmem_node *tmp = alloc->list;

		while (NULL != tmp && node != tmp) {
			pprev = &(tmp->next);
			tmp = tmp->next;
		}
		if (NULL == tmp) {
			__debug_error("free", "NULL == tmp\n");
			panic("kfree(): linked list broken!\n");
		}

		#ifdef DEBUG 
		// display linked list of kmem_allocator 
		for (struct kmem_node *it = alloc->list; NULL != it; it = it->next) {
			printf("%p -> ", it);
		}
		printf("\n");
		#endif 

		*pprev = tmp->next;
		__debug_info("kfree", "alloc->list = %p\n", alloc->list);
		__debug_info("kfree", "tmp = %p\n", tmp);

		freepage(node);
		alloc->npages--;
	}

	release(&(alloc->lock));
	// leave critical section `alloc`
}

static void km_view_allocator(struct kmem_allocator *alloc) {
	// enter critical section 
	acquire(&(alloc->lock));

	printf("\n"__INFO("kmem_allocator")": size %d, addr: %p taken %d page(s), allocated %d obj(s)\n",
			alloc->obj_size, alloc, alloc->npages, alloc->nobjs);
	// __debug_info("kmem_allocator", "size %d, addr: %p\n", 
	// 		alloc->obj_size, alloc);
	for (struct kmem_node *node = alloc->list; NULL != node; node = node->next) {
		printf(
			"\t"__INFO("kmem_node")":\n"
			"\tconfig.obj_size: %d\n"
			"\tconfig.obj_addr: %p\n"
			"\tavail: %d\n"
			"\tcnt: %d\n", 
			node->config.obj_size, 
			node->config.obj_addr, 
			node->avail, 
			node->cnt
		);
		printf("\t[");
		for (uint8 i = node->avail; TABLE_END != i; i = node->table[i]) {
			printf("%d ", i);
		}
		printf("]\n");
	}

	release(&(alloc->lock));
	// leave critical section 
}

void kmview(void)
{
	// display all the content in kmem_table

	// enter critical section 
	acquire(&kmem_table_lock);

	for (int i = 0; i < KMEM_TABLE_SIZE; i ++) {
		struct kmem_allocator *alloc = kmem_table[i];

		while (NULL != alloc) {
			km_view_allocator(alloc);
			alloc = alloc->next;
		}
	}

	release(&kmem_table_lock);
	// leave critical section 
}

struct anonfile {
	struct spinlock	lock;
	struct rb_root	mapping;	// for mmap_page
	uint			ref;
}

static struct anonfile *alloc_anonfile(void)
{
	struct anonfile *f = kmalloc(sizeof(struct anonfile));
	if (!f)
		return NULL;

	__debug_info("alloc_anonfile", "allocate one: %p\n", f);
	initlock(&f->lock, "anonfile");
	f->mapping.rb_node = NULL;
	f->ref = 1;
	return f;
}

static struct anonfile *dup_anonfile(struct anonfile *fp)
{
	acquire(&fp->lock);
	fp->ref++;
	release(&fp->lock);
	return fp;
}

static void close_anonfile(struct anonfile *fp)
{
	acquire(&fp->lock);
	fp->ref--;
	if (fp->ref == 0) {
		if (fp->mapping.rb_node != NULL)
			panic("close_anonfile: rbtree not empty");
		release(&fp->lock);
		__debug_info("close_anonfile", "free one: %p\n", fp);
		kfree(fp);
		return;
	}
	release(&fp->lock);
}

static struct mmap_page *get_mmap_page(struct rb_root *root, uint64 off)
{
	struct rb_node *node = root->rb_node;

	while (node) {
		struct mmap_page *map = rb_entry(node, struct mmap_page, rb);
		if (off < map->f_off)
			node = node->rb_left;
		else if (off > map->f_off)
			node = node->rb_right;
		else
			return map;
	}

	return NULL;
}

static void put_mmap_page(struct mmap_page *map, struct rb_root *root)
{
	map->ref--;
	if (map->ref == 0) {
		rb_erase(&map->rb, root);
		if (map->pa && pageput((uint64)map->pa) == 0)
			freepage(map->pa);
		kfree(map);
	}
}

static struct mmap_page *get_mmap_with_parent(struct rb_root *root,
								uint64 off, struct rb_node **pparent,
								struct rb_node ***pplink)
{
	struct rb_node **p = &root->rb_node;
	struct rb_node *parent = NULL;

	while (*p) {
		parent = *p;
		struct mmap_page *map = rb_entry(parent, struct mmap_page, rb);
		if (off < map->f_off)
			p = &parent->rb_left;
		else if (off > map->f_off)
			p = &parent->rb_right;
		else
			return map;
	}

	*pparent = parent;
	*pplink = p;
	return NULL;
}

static struct mmap_page *get_adjacent_page(struct mmap_page *map, int prev)
{
	struct rb_node *node;
	node = prev ? rb_prev(&map->rb) : rb_next(&map->rb);
	if (!node)
		return NULL;

	return rb_entry(node, struct mmap_page, rb);
}

static void __anon_mmapdel(struct seg *seg)
{
	if (!MMAP_SHARE(seg->mmap))
		return;

	struct anonfile *fp = MMAP_FILE(seg->mmap);
	uint64 off = seg->f_off;
	uint64 end = off + seg->sz;

	acquire(&fp->lock);
	for (; off < end; off += PGSIZE) {
		struct mmap_page *map = get_mmap_page(&fp->mapping, off);
		if (map == NULL)
			panic("__anon_mmapdel: no map node\n");

		put_mmap_page(map, &fp->mapping);
	}
	release(&fp->lock);

	close_anonfile(fp);
	seg->mmap = NULL;
}

static void __file_mmapdel(struct seg *seg, int sync)
{
	__debug_info("__file_mmapdel", "enter seg=%p, sync=%d\n", seg, sync);

	struct file *fp = MMAP_FILE(seg->mmap);
	if (!MMAP_SHARE(seg->mmap))
		goto out;

	struct inode *ip = fp->ip;
	uint64 off = seg->f_off;
	uint64 end = off + seg->sz;

	acquire(&ip->ilock);
	for (; off < end; off += PGSIZE) {
		struct mmap_page *map = get_mmap_page(&ip->mapping, off);
		if (map == NULL)
			panic("__file_mmapdel: no map node\n");

		__debug_info("__file_mmapdel", "v=%d, off=%p, len=%d\n",
					map->valid, off, map->f_len);
		if (sync && (seg->flag & PTE_W) && map->pa && off < ip->size) {
			uint64 len = (ip->size - off < map->f_len) ?
							ip->size - off : map->f_len;
			release(&ip->ilock);
			ilock(ip);

			// This op may fail, but what can we do about it?
			if (map->valid) {
				__debug_info("__file_mmapdel", "writing: off=%p, len=%d\n", off, map->f_len);
				ip->fop->write(ip, 0, (uint64)map->pa, off, len);
			}
			iunlock(ip);
			acquire(&ip->ilock);
		}

		put_mmap_page(map, &ip->mapping);
	}
	release(&ip->ilock);

out:
	fileclose(fp);
}

void mmapdel(struct seg *seg, int sync)
{
	__debug_assert("mmapdel", seg->type == MMAP, "funny type %d\n", seg->type);
	__debug_info("mmapdel", "off=%p, sz=%d\n", seg->f_off, seg->sz);

	if (MMAP_ANONY(seg->mmap)) {
		__anon_mmapdel(seg);
	} else {
		__file_mmapdel(seg, sync);
	}
}

static void __anon_mmapdup(struct seg *seg)
{
	if (!MMAP_SHARE(seg->mmap))
		return;

	struct anonfile *fp = MMAP_FILE(seg->mmap);
	uint64 off = seg->f_off;
	uint64 end = off + seg->sz;

	acquire(&fp->lock);
	struct mmap_page *map = get_mmap_page(&fp->mapping, off);
	for (; off < end; off += PGSIZE) {
		if (map == NULL || map->f_off != off)
			panic("__anon_mmapdup: no map node\n");
		map->ref++;
		map = get_adjacent_page(map, 0);
	}
	release(&fp->lock);

	dup_anonfile(fp);
}

static void __file_mmapdup(struct seg *seg)
{
	struct file *fp = MMAP_FILE(seg->mmap);
	if (!MMAP_SHARE(seg->mmap))
		goto out;

	struct inode *ip = fp->ip;
	uint64 off = seg->f_off;
	uint64 end = off + seg->sz;

	acquire(&ip->ilock);
	struct mmap_page *map = get_mmap_page(&ip->mapping, off);
	for (; off < end; off += PGSIZE) {
		if (map == NULL || map->f_off != off)
			panic("__file_mmapdup: no map node\n");

		map->ref++;
		map = get_adjacent_page(map, 0);
	}
	release(&ip->ilock);

out:
	filedup(fp);
}

void mmapdup(struct seg *seg)
{
	__debug_assert("mmapdup", seg->type == MMAP,
				"bad type: %d\n", seg->type);
	__debug_info("mmapdup", "off=%p, sz=%d\n", seg->f_off, seg->sz);
	if (MMAP_ANONY(seg->mmap)) {
		__anon_mmapdup(seg);
	} else {
		__file_mmapdup(seg);
	}
}

static void __mmap_filedup(uint64 mmap)
{
	if (MMAP_ANONY(mmap)) {
		struct anonfile *fp = MMAP_FILE(mmap);
		if (fp)
			dup_anonfile(fp);
	} else {
		filedup(MMAP_FILE(mmap));
	}
}

static struct seg *split_segment(struct seg *s, uint64 start, uint64 end)
{
	uint64 segend = s->addr + s->sz;
	if (end < start || (start <= PGROUNDDOWN(s->addr) && end >= PGROUNDUP(segend))) {
		__debug_warn("split_segment", "range [0x%x, 0x%x] is cover seg:{addr=%p, size=0x%x}\n",
						start, end, s->addr, s->sz);
		return s;
	}

	struct seg *s1, *s2 = NULL;
	start = PGROUNDDOWN(start);
	end = PGROUNDUP(end);
	s1 = kmalloc(sizeof(struct seg));
	if (s1 == NULL)
		return NULL;

	// split into three part
	if (start > s->addr && end < segend) {
		if ((s2 = kmalloc(sizeof(struct seg))) == NULL) {
			kfree(s1);
			return NULL;
		}
	}

	*s1 = *s;
	if (!s2) {
		uint64 spliter;
		if (start <= s->addr) {
			spliter = end;
			s2 = s;
		} else if (end >= s->addr + s->sz) {
			spliter = start;
			s2 = s1;
		} else
			panic("split_segment: funny case");

		s1->addr = spliter;
		s1->sz = segend - spliter;
		s->sz -= s1->sz;

		if (s->type == MMAP) {
			__mmap_filedup(s->mmap);
			s1->f_off += spliter - s->addr;
		}

		s1->next = s->next;
		s->next = s1;
	}
	else {
		*s2 = *s;
		s2->addr = start;
		s2->sz = end - start;
		s1->addr = end;
		s1->sz = segend - end;
		s->sz = start - s->addr;

		if (s->type == MMAP) {
			__mmap_filedup(s->mmap);	// twice for two segs
			__mmap_filedup(s->mmap);
			s1->f_off += end - s->addr;
			s2->f_off += start - s->addr;
		}

		s1->next = s->next;
		s2->next = s1;
		s->next = s2;
	}

	return s2;
}

static int lookup_fixed_segment(uint64 start, uint64 end,
		struct seg **pprev, struct seg **pnew)
{
	if (end > MAXUVA) {
		__debug_warn("lookup_fixed_segment", "Not enough user space in mmap!\n");
		return -EINVAL;
	}
	if (end < start)
		return -EOVERFLOW;


	struct proc *p = myproc();
	struct seg *s, *s2;
	struct seg *prev = NULL;

	for (s = p->segment; s != NULL;)
	{
		if (start >= s->addr + s->sz) {
			prev = s;
			s = s->next;
		} else if (s->addr >= end) {
			break;
		}
		else {
			s2 = split_segment(s, start, end);
			if (s2 == NULL)
				return -ENOMEM;

			if (s2 != s) {
				/**
				 * After spliting, s2 is not the first part.
				 * Adjust prev and s. Once this happened,
				 * if we still have some segs to split,
				 * s2 should always be s, because we maintain
				 * seg list in order. In other words, prev is settled.
				 */
				for (prev = s; prev->next != s2; prev = prev->next);
				s = s2;
			}
			s = s -> next;
		}
	}

	*pprev = prev;

	s2 = kmalloc(sizeof(struct seg));
	if (s2 == NULL)
		return -ENOMEM;

	memset(s2, 0, sizeof(struct seg));
	s2->addr = start;
	s2->sz = end - start;
	s2->type = MMAP;
	s2->next = s;
	*pnew = s2;

	return 0;
}

static int lookup_segment(uint64 sz, struct seg **pprev, struct seg **pnewseg)
{
	struct proc *p = myproc();
	struct seg *s = getseg(p->segment, STACK);
	uint64 base = VUMMAP;
	if (base + sz > MAXUVA) {
		__debug_warn("lookup_segment", "Not enough user space in mmap!\n");
		return -EINVAL;
	}
	if (base + sz < base)
		return -EOVERFLOW;

	for (struct seg *ss = s->next; ss != NULL; ss = ss->next) {
		if (ss->addr >= base + sz)
			break;
		s = ss;
		base = PGROUNDUP(ss->addr + ss->sz);
	}
	if (base + sz > MAXUVA) {
		__debug_warn("lookup_segment", "Not enough user space in mmap!\n");
		return -EINVAL;
	}

	struct seg* newseg = kmalloc(sizeof(struct seg));
	if (newseg == NULL) {
		__debug_warn("lookup_segment", "newseg failed in mmap!\n");
		return -ENOMEM;
	}

	newseg->type = MMAP;
	newseg->addr = base;
	newseg->sz = sz;
	newseg->mmap = NULL;
	newseg->next = s->next;
	*pprev = s;
	*pnewseg = newseg;
	return 0;
}

static int mmap_file(struct seg *s, uint64 len, int flags, struct file *f, int64 off)
{
	struct inode *ip = f->ip;

	s->f_off = off;
	s->f_sz = 0;	// this is for elf, we don't care about it here
	s->mmap = (uint64) filedup(f);

	if (!(flags & MAP_SHARED))
		return 0;

	uint64 n;
	struct mmap_page *map;
	struct rb_node *parent;
	struct rb_node **plink;

	acquire(&ip->ilock);
	for (n = 0; n < len; n += PGSIZE) {
		map = get_mmap_with_parent(&ip->mapping, off + n, &parent, &plink);
		if (map) {
			map->ref++;
		} else {
			map = kmalloc(sizeof(struct mmap_page));
			if (map == NULL)
				goto fail;

			map->f_off = off + n;
			map->f_len = (PGSIZE < len - n) ? PGSIZE : len - n;
			map->pa = NULL;
			map->ref = 1;
			map->valid = 0;
			rb_link_node(&map->rb, parent, plink);
			rb_insert_color(&map->rb, &ip->mapping);
		}
	}
	release(&ip->ilock);

	s->mmap |= MMAP_SHARE_FLAG;
	return 0;

fail:
	for (n -= PGSIZE; n >= 0; n -= PGSIZE) {
		map = get_mmap_page(&ip->mapping, off + n);
		put_mmap_page(map, &ip->mapping);
	}
	release(&ip->ilock);
	fileclose(f);
	return -ENOMEM;
}

static int mmap_anonymous(struct seg *s, int flags)
{
	/**
	 * We can map the first page referring to locality.
	 * Other pages will be mapped in page fault handler.
	 * But there may be some original mappings in the pagetable,
	 * We'd better leave all the work for page fault handler.
	 */

	if (!(flags & MAP_SHARED)) {
		s->mmap = NULL;
		goto out;
	}

	struct anonfile *fp = alloc_anonfile();
	if (!fp)
		return -ENOMEM;

	uint64 off;
	struct mmap_page *map;
	struct rb_node *parent;
	struct rb_node **plink;

	/**
	 * Build a mmap pages tree at the beginning, the tree nodes
	 * will keep references of the pages (not now), in case of
	 * those shared mapping pages are free due to some processes
	 * exit(). There may be still other processes who are mapping
	 * with those pages, but haven't really mapped them into the
	 * pagetable yet.
	 */
	for (off = 0; off < s->sz; off += PGSIZE) {
		map = kmalloc(sizeof(struct mmap_page));
		if (map == NULL)
			goto fail;

		map->f_off = off;
		map->f_len = PGSIZE;
		map->pa = NULL;
		map->ref = 1;
		map->valid = 0;

		// shouldn't get result since we haven't put "off" into it
		if (get_mmap_with_parent(&fp->mapping, off, &parent, &plink))
			panic("mmap_anonymous: rbtree");
		rb_link_node(&map->rb, parent, plink);
		rb_insert_color(&map->rb, &fp->mapping);
	}

	s->mmap = MMAP_SHARE_FLAG | (uint64)fp;

out:
	s->mmap |= MMAP_ANONY_FLAG;
	s->f_off = 0;
	s->f_sz = 0;

	return 0;

fail:
	for (off -= PGSIZE; off >= 0; off -= PGSIZE) {
		map = get_mmap_page(&fp->mapping, off);
		put_mmap_page(map, &fp->mapping);
	}
	close_anonfile(fp);
	return -ENOMEM;
}

uint64 do_mmap(uint64 start, uint64 len, int prot, int flags, struct file *f, int64 off)
{
	if (f) {
		struct inode *ip = f->ip;
		if (off >= ip->size) {
			__debug_warn("mmap", "length overflows!\n");
			return -EINVAL;
		}
		if (S_ISDIR(ip->mode))
			return -EISDIR;
		if ((f->readable ^ (prot & PROT_READ)) || (f->writable ^ ((prot & PROT_WRITE) >> 1))) {
			__debug_warn("mmap", "unmatched priviledge: w/r=%d/%d, prot x/w/r=%d/%d/%d\n",
						f->writable, f->readable,
						!!(prot & PROT_EXEC), !!(prot & PROT_WRITE), !!(prot & PROT_READ));
			return -EPERM;
		}
	} else if (!(flags & MAP_ANONYMOUS))
		panic("do_mmap: bad file");	// sys_mmap should check this

	uint64 sz = PGROUNDUP(len);
	struct seg *prev, *new;
	int ret = 0;
	if (flags & MAP_FIXED)
		ret = lookup_fixed_segment(start, start + sz, &prev, &new);
	else
		ret = lookup_segment(sz, &prev, &new);

	if (ret < 0)
		return ret;

	new->flag = (prot << 1) & (PTE_X|PTE_W|PTE_R);

	if (f)
		ret = mmap_file(new, len, flags, f, off);
	else
		ret = mmap_anonymous(new, flags);

	if (ret < 0) {
		kfree(new);
		return ret;
	}

	/**
	 * Clean up existing mapping if it is fixed mapping.
	 * Otherwise, we have prev->next == new->next, so the
	 * deletion below won't be carried.
	 */
	struct proc *p = myproc();
	struct seg *del = prev ? prev->next : p->segment;
	while (del != new->next) {
		del = delseg(p->pagetable, del);
	}

	if (prev) {
		prev->next = new;
	} else {
		p->segment = new;
	}
	sfence_vma();
	return new->addr;
}

int do_munmap(uint64 start, uint64 len)
{
	uint64 sz = PGROUNDUP(len);
	uint64 end = start + sz;
	struct proc *p;
	struct seg *prev = NULL;
	struct seg *s, *del;
	int ret;

	if (end < start)
		return -EOVERFLOW;

	/**
	 * This function takes care of the seg-split problem,
	 * which allows us to take advantage of it: simply free
	 * the segs it returns to us. But it also returns a new
	 * seg we don't use at all, just free it at last.
	 */
	ret = lookup_fixed_segment(start, end, &prev, &s);
	if (ret < 0)
		return ret;

	p = myproc();
	del = prev ? prev->next : p->segment;
	ret = 0;
	if (del != s->next) {
		ret = 1;
		while (del != s->next) {
			del = delseg(p->pagetable, del);
		}
	}

	if (ret) {	// it did delete some segs
		if (prev) {
			prev->next = s->next;
		} else {
			p->segment = s->next;
		}
		sfence_vma();
	}

	kfree(s);
	return 0;
}

int do_msync(uint64 addr, uint64 len, int flags)
{
	struct proc *p = myproc();
	struct seg *s = partofseg(p->segment, addr, addr + len);
	if (s == NULL)
		return -EFAULT;

	// private mapping and anonymous mapping can not be synchronized
	if (s->type != MMAP || MMAP_ANONY(s->mmap) || !MMAP_SHARE(s->mmap))
		return 0;

	// MS_INVALIDATE does nothing on our system
	if (!(flags & (MS_ASYNC|MS_SYNC)))
		goto out;

	struct file *f = MMAP_FILE(s->mmap);
	struct inode *ip = f->ip;
	int ret = 0;

	uint64 foff = s->f_off + (addr - s->addr);
	uint64 sz = s->sz < len ? s->sz : len;
	uint64 end = foff + sz;

	acquire(&ip->ilock);
	for (; foff < end; foff += PGSIZE) {
		struct mmap_page *map = get_mmap_page(&ip->mapping, foff);
		if (map == NULL)
			panic("__file_mmapdel: no map node\n");

		if (map->pa && foff < ip->size) {
			uint64 flen = (ip->size - foff < map->f_len) ?
							ip->size - foff : map->f_len;
			release(&ip->ilock);
			ilock(ip);

			// This op may fail, but what can we do about it?
			if (map->valid) {
				ip->fop->write(ip, 0, (uint64)map->pa, foff, flen);
			}
			iunlock(ip);
			acquire(&ip->ilock);
		}
	}
	release(&ip->ilock);

out:
	return ret;
}

static int handle_anonymous_shared(uint64 badaddr, struct seg *s)
{
	struct anonfile *fp = MMAP_FILE(s->mmap);

	uint64 off = s->f_off + (PGROUNDDOWN(badaddr) - s->addr);
	struct mmap_page *map;

	acquire(&fp->lock);
	map = get_mmap_page(&fp->mapping, off);
	if (map == NULL)
		panic("handle_anonymous_shared: no map node");

	if (map->pa == NULL) {
		map->pa = allocpage();
		if (map->pa == NULL) {
			release(&fp->lock);
			return -ENOMEM;
		}
		memset(map->pa, 0, PGSIZE);
		pagereg((uint64)map->pa, 1);	// keep a reference on the page
	}
	release(&fp->lock);

	struct proc *p = myproc();
	if (mappages(p->pagetable, PGROUNDDOWN(badaddr), PGSIZE,
				(uint64)map->pa, s->flag|PTE_U) < 0)
		return -ENOMEM;

	sfence_vma();
	return 0;
}

static void *__page_file_swap(struct inode *ip, uint64 foff, uint64 badaddr)
{
	struct proc *p = myproc();
	struct seg *s = locateseg(p->segment, badaddr);
	uint64 start = s->f_off;	// start offset
	uint64 end = start + s->sz;	// end offset
	void *page = NULL;

	if (s->sz == PGSIZE)		// can't spare any page
		return NULL;

	acquire(&ip->ilock);

	uint64 off = (foff == start) ? end - PGSIZE : foff - PGSIZE;
	struct mmap_page *map = get_mmap_page(&ip->mapping, off);
	int miss = 0, free = 0;

	while (off != foff)
	{
		if (map->ref == 1 && map->pa) {	// only us
			void *victim = map->pa;
			map->pa = NULL;
			release(&ip->ilock);

			ilock(ip);
			if ((s->flag & PTE_W) && map->valid && off < ip->size) {
				uint64 len = (ip->size - off < map->f_len) ?
								ip->size - off : map->f_len;
				ip->fop->write(ip, 0, (uint64)victim, off, len);
			}
			map->valid = 0;
			iunlock(ip);

			unmappages(p->pagetable, s->addr + (off - s->f_off), 1, VM_USER|VM_FREE);

			if (pageput((uint64)victim) != 0)
				panic("__page_file_swap: bad page ref");
			if (!page)
				page = victim;
			else
				freepage(victim);

			free++;
			miss = 0;

			acquire(&ip->ilock);
		} else {
			miss++;
			if (free >= 10 && miss >= 5) {		// enough
				printf(__INFO("mmap file swap")" evict enough %d\n", free);
				break;
			}
		}
		if (off == start) {
			off = end - PGSIZE;
			map = get_mmap_page(&ip->mapping, off);
		} else {
			off -= PGSIZE;
			map = get_adjacent_page(map, 1);
		}
		// if (!map || map->f_off != off)
		// 	panic("__page_file_swap: bad map node");
	}
	release(&ip->ilock);

	return page;
}

static int __page_file_read(struct inode *ip, uint64 off, uint64 page)
{
	if (off >= ip->size) {	// offset out of file size
		return -EIO;				
	}
	uint64 len = (PGSIZE < ip->size - off) ? PGSIZE : ip->size - off;

	/**
	 * This read could meet some problem. If the result len is not
	 * equal to the expected len, should we sail that's a fault?
	 * or just ignore this? We choose the later at present.
	 */
	len = ip->fop->read(ip, 0, page, off, len);
	if (len < PGSIZE)
		memset((void *)(page + len), 0, PGSIZE - len);

	return 0;
}

static int handle_file_mmap(uint64 badaddr, struct seg *s)
{
	int share = MMAP_SHARE(s->mmap);
	struct file *fp = MMAP_FILE(s->mmap);
	struct inode *ip = fp->ip;
	uint64 off = s->f_off + (PGROUNDDOWN(badaddr) - s->addr);
	struct mmap_page *map;
	void *pa;

	acquire(&ip->ilock);
	map = get_mmap_page(&ip->mapping, off);

	if (share) {
		if (map == NULL)
			panic("handle_file_mmap: no map node");

		/**
		 * Here is another problem. The first fault allocates a page here,
		 * then releases the ilock to read the file. At this moment, the
		 * second fault (by other process) arrives, sees that the page is
		 * ready, then maps and leaves, which could totally happen before
		 * the first one finishing its reading.
		 * So we use a 'valid' field and the sleeplock to sync this.
		 */
		if (map->pa == NULL) {
			pa = allocpage();
			if (pa == NULL) {
				release(&ip->ilock);
				pa = __page_file_swap(ip, off, badaddr);
				if (pa == NULL)
					return -ENOMEM;

				acquire(&ip->ilock);
				if (map->pa == NULL) {
					pagereg((uint64)pa, 1);
					map->pa = pa;
				} else {
					freepage(pa);
					pa = map->pa;
				}
			} else {
				pagereg((uint64)pa, 1);		// keep refs on shared mappings
				map->pa = pa;
			}
		} else {
			pa = map->pa;
		}
		release(&ip->ilock);

		/**
		 * There is the page, but is it valid? That means the contents of the
		 * file may be still on disk. Or aren't they? That's hard to answer.
		 * The reading might fail due to the exceeding offset or other reasons,
		 * leaving an empty page without proper file contents.
		 * The 'valid' flag is to deal with this case. Besides, the sleeplock
		 * solves the problem we named above.
		 */
		ilock(ip);
		if (!map->valid) {
			if (__page_file_read(ip, off, (uint64)pa) < 0) {
				iunlock(ip);
				return -EIO;
			}
			map->valid = 1;
		}
		iunlock(ip);
	}
	else {
		pa = allocpage();
		if (!pa) {
			release(&ip->ilock);
			return -ENOMEM;
		}
		pagereg((uint64)pa, 0);				// don't keep refs on private mappings

		if (map && map->pa && map->valid) {	// copy from shared page if existing
			memmove(pa, map->pa, PGSIZE);
			release(&ip->ilock);
		} else {
			release(&ip->ilock);
			ilock(ip);
			if (__page_file_read(ip, off, (uint64)pa) < 0) {
				iunlock(ip);
				freepage(pa);
				return -EIO;
			}
			iunlock(ip);
		}
	}

	struct proc *p = myproc();
	if (mappages(p->pagetable, PGROUNDDOWN(badaddr), PGSIZE,
				(uint64)pa, s->flag|PTE_U) < 0)
	{
		if (!share)
			freepage(pa);	
		return -ENOMEM;
	}

	sfence_vma();
	return 0;
}

int handle_page_fault_mmap(int kind, uint64 badaddr, struct seg *s)
{
	int illegel;
	switch (kind) {
		case 0: illegel = !(s->flag & PTE_R); break;
		case 1: illegel = !(s->flag & PTE_W); break;
		case 2: illegel = !(s->flag & PTE_X); break;
		default:
			illegel = 0;
			panic("handle_page_fault_mmap: kind");
	}
	if (illegel) {	// the access broke the protection
		__debug_warn("handle_page_fault_mmap", "illegal access: kind=%d, prot=0x%x\n",
					kind, s->flag);
		return -EFAULT;
	}

	if (MMAP_ANONY(s->mmap)) {
		if (!MMAP_SHARE(s->mmap)) {		// private mapping, just like heap
			struct proc *p = myproc();
			uint64 pa = PGROUNDDOWN(badaddr);

			if (uvmalloc(p->pagetable, pa, pa + PGSIZE, s->flag) == 0)
				return -ENOMEM;

			sfence_vma();
			return 0;
		}
		else
			return handle_anonymous_shared(badaddr, s);
	}

	return handle_file_mmap(badaddr, s);
}

struct run {
	struct run *next;
	uint64 npage;
}

struct pm_allocator {
	struct spinlock lock;
	struct run *freelist;
	uint64 npage;
}

static void *__mul_alloc_no_lock(uint64 n) {
	struct run *pa;
	struct run **pprev;

	pa = multiple.freelist;
	pprev = &(multiple.freelist);

	while (NULL != pa) {
		if (pa->npage >= n) {
			struct run *ret = (struct run*)(
				(uint64)pa + PGSIZE * (pa->npage - n)
			);
			if (pa == ret) {	// this block is used up, remove it
				*pprev = pa->next;
			}
			else {
				pa->npage -= n;
				pa = ret;
			}

			multiple.npage -= n;
			break;
		}

		pprev = &(pa->next);
		pa = pa->next;
	}

	return (void*)pa;
}

static void __mul_free_no_lock(uint64 start, uint64 n) {
	if (NULL == multiple.freelist) {
		multiple.freelist = (struct run*)start;
		multiple.freelist->npage = n;
		multiple.freelist->next = NULL;
		multiple.npage = n;

		return ;
	}

	struct run *prev = NULL;
	struct run *next = multiple.freelist;
	while (NULL != next) {
		if ((uint64)next > start) {
			break;
		}
		else {
			prev = next;
			next = next->next;
		}
	}

	struct run *pa = (struct run*)start;
	pa->next = next;
	pa->npage = n;

	// merge with previous 
	if (NULL != prev) {
		if (((uint64)prev + prev->npage * PGSIZE) == (uint64)pa) {
			prev->npage += n;
			pa = prev;
		}
		else {
			prev->next = pa;
		}
	}
	else {
		multiple.freelist = pa;
		pa->npage = n;
	}

	// merge with next 
	if (NULL != next) {
		if (((uint64)pa + pa->npage * PGSIZE) == (uint64)next) {
			// mergable 
			pa->npage += next->npage;
			pa->next = next->next;
		}
	}

	multiple.npage += n;
}

static void __mul_freerange(uint64 pa_start, uint64 pa_end) {
	uint64 start = PGROUNDUP(pa_start);
	uint64 npage = (pa_end - start) / PGSIZE;

	__enter_mul_cs 
	__mul_free_no_lock(pa_start, npage);
	__leave_mul_cs 
}

static void *__sin_alloc_no_lock(void) {
	struct run *ret = single.freelist;

	if (NULL != ret) {
		single.freelist = ret->next;
		single.npage -= 1;
	}

	return ret;
}

static void __sin_free_no_lock(uint64 pa) {
	struct run *page = (struct run*)pa;

	page->next = single.freelist;
	single.freelist = page;
	single.npage += 1;
}

static void __sin_freerange(uint64 pa_start, uint64 pa_end) {
	uint64 start = PGROUNDUP(pa_start);

	__enter_sin_cs 
	while (start < pa_end) {
		__sin_free_no_lock(start);
		start += PGSIZE;
	}
	__leave_sin_cs 
}

void kpminit(void) {
	// init multiple 
	multiple.freelist = NULL;
	multiple.npage = 0;
	initlock(&multiple.lock, "multi-lock");

	// init single 
	single.freelist = NULL;
	single.npage = 0;
	initlock(&single.lock, "single-lock");

	__assert("kpminit", START_SINGLE - (uint64)boot_stack_top >= PGSIZE, 
			"START_SINGLE = %p, boot_stack_top = %p\n", 
			START_SINGLE, boot_stack_top);
	__mul_freerange((uint64)boot_stack_top, START_SINGLE);
	__sin_freerange(START_SINGLE, PHYSTOP);

	__debug_info("kpminit", "kernel_end: %p, start_single: %p, phystop: %p, npage %d\n", 
			kernel_end, (void*)START_SINGLE, (void*)PHYSTOP, multiple.npage + single.npage);
}

void *allocpage_n(uint64 n) {
	__debug_assert("allocpage_n", n > 1, "n = %d\n", n);

	void *ret;
	__enter_mul_cs 
	ret = __mul_alloc_no_lock(n);
	__leave_mul_cs 

	#ifdef DEBUG
	if (NULL != ret) {
		memset(ret, 0x5, n * PGSIZE);
	}
	#endif 
	__debug_info("allocpage_n", "%p %d page(s)\n", ret, n);

	return ret;
}

void freepage_n(uint64 start, uint64 n) {
	__debug_assert("freepage_n", 
		(start >= (uint64)kernel_end && start < START_SINGLE) && 
		(0 == start % PGSIZE) && n > 1, 
		"start = %p, n = %d\n", start, n
	);

	__enter_mul_cs 
	__mul_free_no_lock(start, n);
	__leave_mul_cs 

	__debug_info("freepage_n", "%p %d page(s)\n", start, n);
}

uint64 _allocpage(void) {
	struct run *ret;

	__enter_sin_cs 
	ret = __sin_alloc_no_lock();
	__leave_sin_cs 

	if (NULL == ret) {
		// we can't allocate one from single, let's borrow one from multiple
		__enter_mul_cs 
		ret = __mul_alloc_no_lock(1);
		__leave_mul_cs 
	}

	#ifdef DEBUG
	if (NULL != ret) {
		memset(ret, 5, PGSIZE);
	}
	#endif 
	__debug_info("allocpage", "%p\n", ret);

	return (uint64)ret;
}

void _freepage(uint64 pa) {
	uint64 start = (uint64)pa;

	__debug_assert("freepage", 
		(start >= (uint64)kernel_end && start < PHYSTOP) && 
		0 == start % PGSIZE, 
		"start = %p\n", start
	);

	if (start < START_SINGLE) {
		__enter_mul_cs 
		__mul_free_no_lock(start, 1);
		__leave_mul_cs 
	}
	else {
		__enter_sin_cs 
		__sin_free_no_lock(start);
		__leave_sin_cs 
	}

	__debug_info("freepage", "%p\n", start);
}

uint64 idlepages(void) {
	return multiple.npage + single.npage;
}

void pm_dump(void) {
	__enter_mul_cs 
	struct run *pa = multiple.freelist;
	printf("multiple avail: %d\n", multiple.npage);
	while (NULL != pa) {
		printf("\t%p %d\n", pa, pa->npage);
		pa = pa->next;
	}
	__leave_mul_cs 

	__enter_sin_cs 
	printf("single avail: %d\n", single.npage);
	__leave_sin_cs 
}

struct seg *newseg(pagetable_t pagetable, struct seg *head,
				enum segtype type, uint64 offset, uint64 sz, long flag)
{
	uint64 nstart, nend;
	nstart = PGROUNDDOWN(offset);
	nend = offset + sz;
	nend = PGROUNDUP(nend);

	// __debug_info("newseg", "type=%d nstart=%p nend=%p\n", type, nstart, nend);
	// __debug_info("newseg", "sizeof(struct seg): %d\n", sizeof(struct seg));
	struct seg *seg = NULL;
	for (struct seg *s = head; s != NULL; s = s->next) {
		// __debug_info("newseg", "type=%d start=%p end=%p\n", s->type, start, end);
		if (nend <= s->addr) {
			break;
		} else if (nstart >= s->addr + s->sz) {
			seg = s;
		} else {
			__debug_error("newseg", "segments overlap\n");
			return NULL;
		}
	}

	// __debug_info("newseg", "calling to kmalloc\n");
	struct seg *p;
	if ((p = (struct seg *)kmalloc(sizeof(struct seg))) == NULL) {
		__debug_error("newseg", "fail to kmalloc\n");
		return NULL;
	}
/*
	// __debug_info("newseg", "calling to uvmalloc\n");
	if(uvmalloc(pagetable, nstart, nend, flag) == 0)
	{
		kfree(p);
		__debug_error("newseg", "fail to uvmalloc\n");
		return NULL;
	}
*/
	if (seg == NULL) {
		p->next = head;
		head = p;
	} else {
		p->next = seg->next;
		seg->next = p;
	}
	p->addr = offset;
	p->sz = sz;
	p->type = type;
	p->flag = flag;
	p->mmap = NULL;

	// __debug_info("newseg", "done\n");
	// return p;
	return head;
}

struct seg *newseg_get(pagetable_t pagetable, struct seg *head,
				enum segtype type, uint64 offset, uint64 sz, long flag, struct seg **get)
{
	uint64 nstart, nend;
	nstart = PGROUNDDOWN(offset);
	nend = offset + sz;
	nend = PGROUNDUP(nend);

	// __debug_info("newseg", "type=%d nstart=%p nend=%p\n", type, nstart, nend);
	// __debug_info("newseg", "sizeof(struct seg): %d\n", sizeof(struct seg));
	struct seg *seg = NULL;
	for (struct seg *s = head; s != NULL; s = s->next) {
		// __debug_info("newseg", "type=%d start=%p end=%p\n", s->type, start, end);
		if (nend <= s->addr) {
			break;
		} else if (nstart >= s->addr + s->sz) {
			seg = s;
		} else {
			__debug_error("newseg", "segments overlap\n");
			return NULL;
		}
	}

	// __debug_info("newseg", "calling to kmalloc\n");
	struct seg *p;
	if ((p = (struct seg *)kmalloc(sizeof(struct seg))) == NULL) {
		__debug_error("newseg", "fail to kmalloc\n");
		return NULL;
	}
	if (seg == NULL) {
		p->next = head;
		head = p;
	} else {
		p->next = seg->next;
		seg->next = p;
	}
	p->addr = offset;
	p->sz = sz;
	p->type = type;
	p->flag = flag;
	p->mmap = NULL;

	// __debug_info("newseg", "done\n");
	// return p;
	*get = p;
	return head;
}

struct seg *locateseg(struct seg *head, uint64 addr)
{
		// __debug_info("locateseg", "addr=%p\n", addr);
	while (head) {
		uint64 start, end;
		start = PGROUNDDOWN(head->addr);
		end = head->addr + head->sz;
		// __debug_info("locateseg", "type=%d start=%p end=%p\n", head->type, start, end);
		if (addr >= start && addr < end)
			return head;
		else if (addr >= end)
			head = head->next;
		else {
			__debug_warn("locateseg", "va=%p in no segment\n", addr);
			return NULL;
		}
	}

	return NULL;
}

struct seg *getseg(struct seg *head, enum segtype type)
{
	for (struct seg *seg = head; seg != NULL; seg = seg->next) {
		if (seg->type == type)
			return seg;
	}
	return NULL;
}

struct seg *partofseg(struct seg *head, uint64 start, uint64 end)
{
	// __debug_info("partofseg", "start=%p end=%p\n", start, end);
	struct seg *s = locateseg(head, start);
	struct seg *s2 = locateseg(s, end - 1);
	if (s == NULL || s2 == NULL)
		return NULL;

	if (s != s2 && PGROUNDUP(s->addr + s->sz) != PGROUNDDOWN(s2->addr))
		return NULL;

	return s;
}

void freeseg(pagetable_t pagetable, struct seg *p)
{
	uvmdealloc(pagetable, PGROUNDDOWN(p->addr), p->addr + p->sz);
	p->sz = 0;
}

struct seg *delseg(pagetable_t pagetable, struct seg *s)
{
	struct seg *next = s->next;
	// __debug_info("delseg", "s = %p\n", s);
	// __debug_info("delseg", "s->type: %d\n", s->type);
	if (s->type == MMAP) {
		mmapdel(s, 1); // mmap的free工作是单独处理的
	}
	uvmdealloc(pagetable, PGROUNDDOWN(s->addr), s->addr + s->sz);
	kfree(s);
	return next;
}

void delsegs(pagetable_t pagetable, struct seg *head)
{
	while (head) {
		head = delseg(pagetable, head);
	}
}

struct seg *copysegs(pagetable_t pt, struct seg *seg, pagetable_t pt2)
{
	struct seg *head = NULL, *tail = NULL;
	for (; seg != NULL; seg = seg->next) {
		struct seg *s = kmalloc(sizeof(struct seg));
		if (s == NULL) {
			__debug_warn("copysegs", "seg kmalloc fail\n");
			goto bad;
		}

		// This means that the mmap segment is shared, shouldn't do COW.
		// If seg->mmap is NULL, it means the mmap is private.
		int cow = (seg->type == MMAP && MMAP_SHARE(seg->mmap)) ? 0 : 1;
		// Copy user memory from parent to child.
		if (uvmcopy(pt, pt2, PGROUNDDOWN(seg->addr), seg->addr + seg->sz, cow) < 0) 
		{
			__debug_warn("copysegs", "uvmcopy_cow fails\n");
			__debug_warn("copysegs", "%p, %p, %d\n", 
					seg->addr, seg->addr + seg->sz, seg->type);
			kfree(s);
			__debug_warn("copysegs", "exit kfree\n");
			goto bad;
		}
		memmove(s, seg, sizeof(struct seg));
		if (seg->type == MMAP) {
			mmapdup(seg);
		}
		s->next = NULL;
		if (tail == NULL) {
			head = tail = s;
		} else {
			tail->next = s;
			tail = s;
		}
	}
	return head;

bad:
	while (head) {
		tail = head->next;
		if (head->type == MMAP)
			mmapdel(head, 0);
		uvmdealloc(pt2, PGROUNDDOWN(head->addr), head->addr + head->sz);
		kfree(head);
		head = tail;
	}
	return NULL;
}

void showsegs(struct seg *seg)
{
	for (; seg != NULL; seg = seg->next) {
		printf("type:%d\tstart:%p\tsize:%d\n",seg->type,seg->addr,seg->sz);
	}
	return ;
}

int loadseg(pagetable_t pagetable, uint64 va, struct seg *s, struct inode *ip)
{
	// seg是对实际虚拟地址块的管理
	// 这里取真实va的较大者
	//printf("Enter load seg\n");
	va = PGROUNDDOWN(va) >= s->addr ? PGROUNDDOWN(va) : s->addr;
	uint64 off = s->f_off + (va - s->addr);
	int64 size = s->f_sz - (va - s->addr);
	uint64 end = va + PGSIZE;
	end = PGROUNDDOWN(end);
	// 处理尾部小于一个页面的情况
	if ((int64)(end - va) < size)
		size = end - va;

	//printf("NNN: loadseg base=0x%x, off=0x%x, size=0x%x, end=0x%x\n", va, off, size, end);
	//printf("NNN: loadseg saddr=0x%x, sz=0x%x, f_off=0x%x, f_zs=0x%x, flag=0x%x\n", s->addr, s->sz, s->f_off, s->f_sz, s->flag);
	//printf("NNN: loadseg base=0x%x, off=%d, size=%d, end=0x%x\n", va, off, size, end);
	//printf("NNN: loadseg s->saddr=0x%x, s->sz=%d, f_off=%d, f_zs=%d, flag=0x%x\n", s->addr, s->sz, s->f_off, s->f_sz, s->flag);
	//printf("NNN: real size mapped: %d\n",size);
	void *pa = allocpage();
	if (pa == NULL){
		printf("load seg 0\n");
		return -ENOMEM;
	}

	memset(pa, 0, PGSIZE);
	__debug_info("loadseg", "pa=%p, base=0x%x, f_off=0x%x, size=%d\n", pa, va, off, size);
	if (size > 0 && ip->fop->read(ip, 0, (uint64)pa + va % PGSIZE, off, size) != size) {
		__debug_warn("loadseg", "fail to load! off=0x%x, size=%d\n", off, size);
		printf("load seg 1\n");
		goto bad;
	}
	pagereg((uint64)pa, 0);
	if (mappages(pagetable, va, end - va, (uint64)pa, s->flag|PTE_U) < 0) {
	//if (mappages(pagetable, va, end - va, (uint64)pa, s->flag) < 0) {
		__debug_warn("loadseg", "fail to map! va=0x%x, end=0x%x\n", va, end);
		printf("load seg 2\n");
		goto bad;
	}
	//printf("NNN: reach here!!!\n");
	return 0;
	//return size;

bad:

	freepage(pa);
	return -1;
}

int loadseg3(pagetable_t pagetable, uint64 va, struct seg *s, struct inode *ip, uint64 *get_size)
{
	// seg是对实际虚拟地址块的管理
	// 这里取真实va的较大者
	//printf("Enter load seg\n");
	//va = PGROUNDDOWN(va);
	uint64 off = s->f_off ;
	int64 size = s->f_sz ;
	uint64 end = va + PGSIZE;
	end = PGROUNDDOWN(end);
	// 处理尾部小于一个页面的情况
	if ((int64)(end - va) < size)
		size = end - va;

	//printf("NNN: loadseg base=0x%x, off=0x%x, size=0x%x, end=0x%x\n", va, off, size, end);
	//printf("NNN: loadseg saddr=0x%x, sz=0x%x, f_off=0x%x, f_zs=0x%x, flag=0x%x\n", s->addr, s->sz, s->f_off, s->f_sz, s->flag);
	//printf("NNN: loadseg base=0x%x, off=%d, size=%d, end=0x%x\n", va, off, size, end);
	//printf("NNN: loadseg s->saddr=0x%x, s->sz=%d, f_off=%d, f_zs=%d, flag=0x%x\n", s->addr, s->sz, s->f_off, s->f_sz, s->flag);
	//printf("NNN: real size mapped: %d\n",size);
	void *pa = allocpage();
	if (pa == NULL){
		printf("load seg 0\n");
		return -ENOMEM;
	}

	memset(pa, 0, PGSIZE);
	__debug_info("loadseg", "pa=%p, base=0x%x, f_off=0x%x, size=%d\n", pa, va, off, size);
	if (size > 0 && ip->fop->read(ip, 0, (uint64)pa + va % PGSIZE, off, size) != size) {
		__debug_warn("loadseg", "fail to load! off=0x%x, size=%d\n", off, size);
		printf("load seg 1\n");
		goto bad;
	}
	pagereg((uint64)pa, 0);
	if (mappages(pagetable, va, end - va, (uint64)pa, s->flag|PTE_U) < 0) {
	//if (mappages(pagetable, va, end - va, (uint64)pa, s->flag) < 0) {
		__debug_warn("loadseg", "fail to map! va=0x%x, end=0x%x\n", va, end);
		printf("load seg 2\n");
		goto bad;
	}
	//printf("NNN: reach here!!!\n");
	*get_size = size;
	return 0;
	//return size;

bad:

	freepage(pa);
	return -1;
}

int loadseg_ext(pagetable_t pagetable, uint64 va, struct seg *s, struct inode *ip)
{
	uint64 i,n;
	for(i=0;i<s->f_sz;i+=n){
		n = loadseg(pagetable,va+i,s,ip);
	}
	printf("Have mapped: %d\n",i);
