int loadseg_ext2(pagetable_t pagetable, uint64 va, struct seg *s, struct inode *ip)
{
	printf("va_start: %d\tsize to load:%d\n",va,s->f_sz);
	uint64 i,t=0,cnt=0;
	uint64 tot = s->f_sz;
	for(i=0;i<tot;i+=t){
		loadseg3(pagetable,va+i,s,ip,&t);
		s->f_off += t;
		s->f_sz -=t;
		cnt+=t;
	}
