void userinit(void) {
	fs_first = 1;

	struct proc *p = allocproc();
	__initproc = p;

	p->parent = NULL;
	p->sibling_pprev = NULL;
	p->sibling_next = NULL;

	// allocate one user page and copy initcode's instruction 
	// and data into it 
	// uvminit(p->pagetable, newinit, newinit_size);
	uvminit(p->pagetable, initcode, sizeof(initcode));


	struct seg *s = kmalloc(sizeof(struct seg));
	s->addr = 0;
	s->sz = PGSIZE;
	s->next = NULL;
	s->type = LOAD;
	p->segment = s;

	// prepare for the very first "return from kernel"
	p->trapframe->epc = 0x0;
	p->trapframe->sp = PGSIZE;

	//safestrcpy(p->name, "newinit", sizeof(p->name));
	safestrcpy(p->name, "initcode", sizeof(p->name));

	p->tmask = 0;
	p->elf = NULL;

	for (int i = 0; i < SIGSET_LEN; i ++) {
		p->sig_set.__val[i] = ~0;
	}

	__enter_proc_cs 
	__insert_runnable(PRIORITY_NORMAL, p);
	__leave_proc_cs 

	__debug_info("userinit", "init\n");
}

