int
argfd(int n, int *pfd, struct file **pf)
{
	int fd;
	struct file *f;

	argint(n, &fd);
	if (pfd)
		*pfd = fd;
	if (fd < 0)
		return -1;
	if ((f = fd2file(fd, 0)) == NULL)
		return -1;
	if (pf)
		*pf = f;
	return 0;
}

uint64
sys_dup(void)
{
	struct file *f;
	int fd;

	if(argfd(0, 0, &f) < 0)
		return -1;
	if((fd=fdalloc(f, 0)) < 0)
		return -1;
	filedup(f);
	return fd;
}

uint64
sys_dup3(void)
{
	struct file *f;
	int old, new, flag;

	if (argfd(0, &old, &f) < 0 || argint(1, &new) < 0 || argint(2, &flag) < 0)
		return -1;
	if (old == new || new < 0)
		return -1;

	if (fdalloc3(f, new, flag) < 0)
		return -1;

	filedup(f);
	return new;
}

uint64
sys_read(void)
{
	struct file *f;
	int n;
	uint64 p;

	if (argfd(0, 0, &f) < 0)
		return -EBADF;
	argaddr(1, &p);
	argint(2, &n);
	return fileread(f, p, n);
}

uint64
sys_write(void)
{
	struct file *f;
	int n;
	uint64 p;

	if (argfd(0, 0, &f) < 0)
		return -EBADF;
	argaddr(1, &p);
	argint(2, &n);
	// 控制可以在open时进行
	return filewrite(f, p, n);
}

uint64 sys_copy_file_range(void)
{
	struct file *fp_in, *fp_out;

	uint64 p_offIn,p_offOut;

	uint32 max_len, flags, real_len;

	argfd(0,0,&fp_in);
	argint(1, &p_offIn);
	argfd(2,0,&fp_out);
	argint(3,&p_offOut);
	argint(4, &max_len);
	argint(5, &flags);

	real_len = max_len;

	int32 off_in, off_out; // 无符号比较容易出错
	if(!p_offIn){
		off_in = fp_in->off;
	}
	else{
		off_in = copyin2(&off_in, p_offIn , sizeof(int)); // AAA1 WWW:注意获取用户地址内容的方法, 以及int是多少位
	}

	if(!p_offOut){
		off_out = fp_out->off;
	}
	else{
		off_out = copyin2(&off_out, p_offOut , sizeof(int)); // AAA1 WWW:注意获取用户地址内容的方法, 以及int是多少位
	}

	if(!fp_in || !fp_out){
		return -1;
	}

	int tmp;

	if(real_len  > (tmp = fp_in->ip->size - off_in)){
		real_len = tmp;
	}

	if(real_len > (tmp = fp_out->ip->size - off_out)){
		real_len = tmp;
	}

	if(real_len < 0 ) {
		return -1;
	}

	return copy_file_range(fp_in,off_in,fp_out,off_out,real_len,flags);	

}

