		return -EFAULT;

	return 0;
}

uint64
sys_openat(void)
{
	char path[MAXPATH];
	int dirfd, fd, omode, fmode;
	struct file *f = NULL;
	struct inode *dp = NULL, *ip;

	int check = 0;

	if (argfd(0, &dirfd, &f) < 0) {
		if (dirfd != AT_FDCWD) {
			return -EBADF;
		}
		dp = myproc()->cwd;
	} else {
		dp = f->ip;
	}
	if (argstr(1, path, MAXPATH) < 0)
		return -ENAMETOOLONG;

	argint(2, &omode);
	argint(3, &fmode);



	if(omode & O_CREATE){
		//if() AAA1
		ip = create(dp, path, (fmode & ~S_IFMT) | S_IFREG);
		if(ip == NULL){
			return -1;
		}
	} else {
		if ((ip = nameifrom(dp, path)) == NULL) {
			__debug_warn("sys_openat", "can find %s\n", path);
			return -ENOENT;
		}
		if(ip == proc_INT){
			//AAA1
			check = 1;
			if((omode & (O_WRONLY|O_RDWR)) || (omode & (O_APPEND) || (omode & O_TRUNC)) ){ // AAA1具体是什么权限
				printf("WARN: Could not write on proc/interrupts\n");
				return -1; //AAA1
			}	
		}
		ilock(ip);
		if (S_ISDIR(ip->mode) && (omode & (O_WRONLY|O_RDWR))) {
			iunlockput(ip);
			__debug_warn("sys_openat", "illegel mode 0x%x\n", omode);
			return -EISDIR;
		}
		if ((omode & O_DIRECTORY) && !S_ISDIR(ip->mode)) {
			iunlockput(ip);
			__debug_warn("sys_openat", "o_dir\n");
			return -ENOTDIR;
		}
	}

	if((f = filealloc()) == NULL || (fd = fdalloc(f, omode & O_CLOEXEC)) < 0){
		if (f) {
			fileclose(f);
		}
		iunlockput(ip);
		return -ENOMEM;
	}

	__debug_info("sys_openat", "[%s] ip->mode=0x%x\n", path, ip->mode);

	if (!S_ISDIR(ip->mode) && (omode & O_TRUNC) && (omode & (O_WRONLY|O_RDWR))) {
		ip->op->truncate(ip);
	}

	if (!S_ISREG(ip->mode) && !S_ISDIR(ip->mode)) {
		f->type = FD_DEVICE;
	} else {
		f->type = FD_INODE;
		f->off = (omode & O_APPEND) ? ip->size : 0;
	}

	f->ip = ip;
	f->readable = !(omode & O_WRONLY);
	f->writable = (omode & O_WRONLY) || (omode & O_RDWR);

	iunlock(ip);

	return fd;
}

