uint64
sys_fcntl(void)
{
	int fd, cmd;
	struct file *f;
	uint64 arg;
	if (argfd(0, &fd, &f) < 0 || argint(1, &cmd) < 0 || argaddr(2, &arg) < 0)
		return -1;

	if (cmd == F_DUPFD || cmd == F_DUPFD_CLOEXEC) {
		int minfd = (int) arg;
		if (minfd < 0)
			return -1;
		minfd = fcntldup(f, minfd, cmd == F_DUPFD_CLOEXEC);
		if (minfd >= 0)
			filedup(f);
		return minfd;
	}

	__debug_warn("sys_fcntl", "unsupported cmd %d\n", cmd);

	return -1;
}

uint64
sys_pselect(void)
{
	int nfds;
	uint64 urfds, uwfds, uexfds;
	uint64 utoaddr, usmaddr;

	argint(0, &nfds);
	argaddr(1, &urfds);
	argaddr(2, &uwfds);
	argaddr(3, &uexfds);
	argaddr(4, &utoaddr);
	argaddr(5, &usmaddr);

	if (nfds <= 0 || nfds > FDSET_SIZE)
		return -EINVAL;
	if (!(urfds || uwfds || uexfds))
		return -EINVAL;

	struct fdset rfds, wfds, exfds;
	struct timespec timeout;
	__sigset_t sigmask;

	if (urfds && copyin2((char *)&rfds, urfds, sizeof(struct fdset)) < 0)
		return -EFAULT;
	if (uwfds && copyin2((char *)&wfds, uwfds, sizeof(struct fdset)) < 0)
		return -EFAULT;
	if (uexfds && copyin2((char *)&exfds, uexfds, sizeof(struct fdset)) < 0)
		return -EFAULT;
	if (utoaddr && copyin2((char *)&timeout, utoaddr, sizeof(timeout)) < 0)
		return -EFAULT;
	if (usmaddr && copyin2((char *)&sigmask, usmaddr, sizeof(sigmask)) < 0)
		return -EFAULT;

	struct proc *p = myproc();
	if (p->tmask) {
		printf(") ...\n");
	}

	int ret = pselect(nfds,
				urfds ? &rfds: NULL,
				uwfds ? &wfds: NULL,
				uexfds ? &exfds: NULL,
				utoaddr ? &timeout : NULL,
				usmaddr ? &sigmask : NULL
			);

	if (urfds)
		copyout2(urfds, (char *)&rfds, sizeof(struct fdset));
	if (uwfds)
		copyout2(uwfds, (char *)&wfds, sizeof(struct fdset));
	if (uexfds)
		copyout2(uexfds, (char *)&exfds, sizeof(struct fdset));

	if (p->tmask) {
		printf("pid %d: return from pselect(", p->pid);
	}
	return ret;
}

uint64
sys_ppoll(void)
{
	uint64 addr;
	uint32 nfds;
	uint64 timeoutaddr;
	uint64 sigmaskaddr;
	if (argaddr(0, &addr) < 0 || argint(1, (int*)&nfds) < 0 || argaddr(2, &timeoutaddr) < 0 || argaddr(3, &sigmaskaddr) < 0)
		return -1;

	// if (timeoutaddr || sigmaskaddr) {
	// 	__debug_error("sys_ppoll", "not supported yet!\n");
	// 	return -1;
	// }
	if (nfds == 0)
		return -EINVAL;

	struct pollfd *pfds = kmalloc(nfds * sizeof(struct pollfd));
	if (pfds == NULL)
		return -ENOMEM;

	for (int i = 0; i < nfds; i++) {
		if (copyin2((char *)(pfds + i), addr + i * sizeof(struct pollfd), sizeof(struct pollfd)) < 0) {
			kfree(pfds);
			return -EFAULT;
		}
	}

	struct timespec timeout;
	__sigset_t sigmask;
	if (timeoutaddr && copyin2((char *)&timeout, timeoutaddr, sizeof(timeout)) < 0)
		return -EFAULT;
	if (sigmaskaddr && copyin2((char *)&sigmask, sigmaskaddr, sizeof(sigmask)) < 0)
		return -EFAULT;

	int ret = ppoll(pfds, nfds,
					timeoutaddr ? &timeout : NULL,
					sigmaskaddr ? &sigmask : NULL);

	copyout2(addr, (char *)pfds, sizeof(struct pollfd) * nfds);
	kfree(pfds);
	return ret;
}

uint64
sys_faccessat(void)
{
	char path[MAXPATH];
	int dirfd, mode, flags;
	struct file *f = NULL;
	struct inode *dp, *ip;

	if (argfd(0, &dirfd, &f) < 0) {
		if (dirfd != AT_FDCWD) {
			return -1;
		}
		dp = myproc()->cwd;
	} else {
		dp = f->ip;
	}
	if (argstr(1, path, MAXPATH) < 0 || argint(2, &mode) < 0 || argint(3, &flags) < 0)
		return -1;

	ip = nameifrom(dp, path);
	if (ip != NULL) {
		if (mode == F_OK) {
			iput(ip);
			return 0;
		}
	} else return -1;

	// assume user as root
	int imode = (ip->mode >> 6) & 0x7;
	iput(ip);

	if ((imode & mode) != mode)
		return -1;

	return 0;
}

uint64
sys_lseek(void)
{
	int fd;
	struct file *f;
	int64 off;
	int whence;

	if (argfd(0, &fd, &f) < 0)
		return -EBADF;
	argaddr(1, (uint64 *)&off);
	argint(2, &whence);

	if (f->type != FD_INODE)
		return -ESPIPE;

	uint64 cur = f->off;	
	uint64 size = f->ip->size;
	switch (whence)
	{
		case SEEK_SET:
			cur = off;
			break;
		case SEEK_CUR:
			cur += off;
			break;
		case SEEK_END:
			cur = size + off;
			break;
		default:
			return -EINVAL;
	}

	// Doesn't support offset out of size
	if (cur > 0xffffffff)
		return -EFBIG;

	acquire(&f->lock);
	f->off = cur;
	release(&f->lock);

	return cur;
}

uint64
sys_utimensat(void)
{
	char path[MAXPATH];
	int dirfd, flags;
	uint64 addr;
	struct file *f = NULL;
	struct inode *ip;
	struct timespec times[2];

	if (argfd(0, &dirfd, &f) < 0) {
		if (dirfd != AT_FDCWD) {
			return -EBADF;
		}
		ip = myproc()->cwd;
	} else {
		ip = f->ip;
	}
	if (argstr(1, path, MAXPATH) < 0 || argaddr(2, &addr) < 0 || argint(3, &flags) < 0)
		return -ENAMETOOLONG;

	if (addr != NULL && copyin2((char *)times, addr, sizeof(times)) < 0)
		return -EFAULT;
	else if (addr == NULL) {
		// memset(times, 0, sizeof(times));

	}

	ip = nameifrom(ip, path);
	if (ip == NULL)
		return -ENOENT;

	int ret = 0;
	struct kstat st;
	memset(&st, 0, sizeof(st));

	ilock(ip);
	ip->op->getattr(ip, &st);
	st.atime_sec = times[0].sec;
	st.atime_nsec = times[0].nsec;
	st.mtime_sec = times[1].sec;
	st.mtime_nsec = times[1].nsec;
	if (!ip->op->setattr || ip->op->setattr(ip, &st) < 0) {
		ret = -EACCES;
	}
	iunlockput(ip);

	return ret;
}

uint64
sys_ioctl(void)
{
	#define TIOCGWINSZ	0x5413
	#define TCGETS		0x5401

	struct winsize {
		uint16 ws_row;		/* rows， in character */
		uint16 ws_col; 		/* columns, in characters */
		uint16 ws_xpixel;	/* horizontal size, pixels (unused) */
		uint16 ws_ypixel;	/* vertical size, pixels (unused) */
	};

	#define ICRNL		0000400
	#define OPOST		0000001
	#define ONLCR		0000004
	#define ICANON		0000002
	#define ECHO		0000010


	struct termios {
		uint16 c_iflag; /* 输入模式标志*/
		uint16 c_oflag; /* 输出模式标志*/
		uint16 c_cflag; /* 控制模式标志*/
		uint16 c_lflag; /*区域模式标志或本地模式标志或局部模式*/
		uint8 c_line; /*行控制line discipline */
		uint8 c_cc[8]; /* 控制字符特性*/
	};

	int fd;
	struct file *f;
	uint64 request;
	uint64 argp;

	if (argfd(0, &fd, &f) < 0 || argaddr(1, &request) < 0 || argaddr(2, &argp) < 0)
		return -EBADF;

	if (f->type != FD_DEVICE)
		return -EPERM;

	switch (request) {
	case TIOCGWINSZ: {
		struct winsize win = {
			.ws_row = 24,
			.ws_col = 80,
		};
		if (copyout2(argp, (char*)&win, sizeof(win)) < 0)
			return -EFAULT;
		break;
	}
	case TCGETS: {
		struct termios terminfo = {
			.c_iflag = ICRNL,
			.c_oflag = OPOST|ONLCR,
			.c_cflag = 0,
			.c_lflag = ICANON|ECHO,
			.c_line = 0,
			.c_cc = {0},
		};
		if (copyout2(argp, (char*)&terminfo, sizeof(terminfo)) < 0)
			return -EFAULT;
		break;
	}
	default:
		return -EPERM;
	}

	return 0;
}

uint64
sys_statfs(void)
{
	char path[MAXPATH];
	uint64 addr;
	if (argstr(0, path, MAXPATH) < 0 || argaddr(1, &addr) < 0)
		return -ENAMETOOLONG;

	struct inode *ip = namei(path);
	if (ip == NULL)
		return -ENOENT;

	struct superblock *sb = ip->sb;
	iput(ip);

	struct statfs stat;
	if (!sb->op.statfs)
		return -EPERM;
	if (sb->op.statfs(sb, &stat) < 0)
		return -EIO;
	if (copyout2(addr, (char *)&stat, sizeof(stat)) < 0)
		return -EFAULT;

	return 0;
}

