uint64
sys_sleep(void)
{
	int n;
	int ret = 0;
	uint64 now, expire;
	argint(0, &n);

	struct proc *p = myproc();
	int mask = p->tmask;
	if (mask) {
		printf(") ...\n");
	}

	now = readtime();
	// ont tick is 0.1s in xv6
	expire = now + n * (CLK_FREQ / 10);

	if (expire > now) {
		acquire(&p->lk);
		p->sleep_expire = expire;
		do {
			sleep(&p->sleep_expire, &p->lk);
			if (SIGTERM == p->killed) {
				ret = -EINTR;
				break;
			}
		} while (p->sleep_expire != 0);
		release(&p->lk);
	}

	if (mask) {
		printf("pid %d: return from sleep(%d", p->pid, n);
	}
	return ret;
}

uint64 sys_nanosleep(void) {
	uint64 ureq, urem;
	struct timespec req, rem;

	argaddr(0, &ureq);
	argaddr(1, &urem);
	if (copyin2((char*)&req, ureq, sizeof(struct timespec)) < 0) 
		return -EFAULT;
	if (req.nsec > 999999999L)
		return -EINVAL;

	int ret = 0;
	struct proc *p = myproc();
	int mask = p->tmask;
	if (mask) {
		printf(") ...\n");
	}

	uint64 now, expire;
	now = readtime();
	expire = now + convert_from_timespec(&req);

	if (expire > now) {
		acquire(&p->lk);
		p->sleep_expire = expire;
		do {
			sleep(&p->sleep_expire, &p->lk);
			if (SIGTERM == p->killed) {	// or signal pending with -EINTR
				ret = -EINTR;
				break;
			}
		} while (p->sleep_expire != 0);
		release(&p->lk);
	}

	if (mask) {
		printf("pid %d: return from nanosleep(", p->pid);
	}

	if (ret < 0 && urem) {
		now = readtime();
		if (now < expire) {
			convert_to_timespec(expire - now, &rem);
			copyout2(urem, (char *)&rem, sizeof(struct timespec));
		}
	}

	return ret;
}

