impl NS16550a {
	pub fn init() ->Self {
		use crate::config::*;
		use crate::config::uart::*;

		unsafe {
			// enable divisor latch
			write_volatile(
				(BASE + offset::LCR) as *mut u8, 
				mask::LCR_LATCH
			);

			// set baud rate 
			let latch = CLK / (16 * BAUDRATE);
			write_volatile(
				(BASE + offset::DLL) as *mut u8, 
				(latch & 0xff) as u8
			);
			write_volatile(
				(BASE + offset::DLH) as *mut u8, 
				(latch >> 8) as u8
			);

			// disable divisor latch and set serial format as 8N1
			write_volatile(
				(BASE + offset::LCR) as *mut u8, 
				mask::LCR_LEN0 | mask::LCR_LEN1
			);

			// enable interrupt for recv
			let int_mask = 
			if RECV_IRQ { mask::IER_RECV } else {0}
			| if TRANS_IRQ { mask::IER_TRANS } else {0};
			write_volatile(
				(BASE + offset::IER) as *mut u8, 
				int_mask
			);

			// enable FIFO 
			write_volatile(
				(BASE + offset::FCR) as *mut u8, 
				mask::FCR_FIFO_EN | 
				mask::FCR_RECV_RST | mask::FCR_TRANS_RST
			);
		}

		// finish initialization 
		Self {}
	}

	fn _getchar(&mut self) ->u8 {
		unsafe {
			if 0 == read_volatile((BASE + offset::LSR) as *const u8) & mask::LSR_RECV_READY {
				0xff
			}
			else {
				read_volatile((BASE + offset::RHR) as *const u8)
			}
		}
	}

	fn _putchar(&mut self, c: u8) {
		unsafe {
			while 0 == read_volatile((BASE + offset::LSR) as *const u8) & mask::LSR_TRANS_EMPTY {}

			write_volatile((BASE + offset::THR) as *mut u8, c);
		}
	}
}

impl core::fmt::Write for NS16550a {
	fn write_str(&mut self, fmt: &str) ->core::fmt::Result {
		let mut buffer = [0u8; 4];
		for c in fmt.chars() {
			for code_point in c.encode_utf8(&mut buffer).as_bytes().iter() {
				self._putchar(*code_point as u8);
			}
		}

		Ok(())
	}
}

impl super::UartHandler for NS16550a {
	fn getchar(&mut self) ->u8 {
		self._getchar()
	}

	fn putchar(&mut self, c: u8) {
		self._putchar(c);
	}
}

extern "C" fn trap_handler(tf: &mut TrapFrame) {
	let cause = mcause::read().cause();

	match cause {
		Trap::Exception(Exception::SupervisorEnvCall) => {
			// let mepc = mepc::read().wrapping_add(4);
			// unsafe {
			// 	// install trap vec for SBI, to support nested trap
			// 	mtvec::write(sbi_trap_vec as usize, mtvec::TrapMode::Direct);
			// 	mstatus::set_mie();
			// }
			sbi::handler(tf);
			mepc::write(mepc::read().wrapping_add(4));
			// unsafe {
			// 	// restore trap vec 
			// 	mstatus::clear_mie();
			// 	mepc::write(mepc);
			// 	mtvec::write(trap_vec as usize, mtvec::TrapMode::Direct);
			// }
		}, 
		Trap::Interrupt(Interrupt::MachineTimer) => {
			// println!("hart {} MachineTimer", mhartid::read());
			// delegate to supervisor 
			unsafe {
				mip::set_stimer();
				mie::clear_mtimer();
			}
		}, 
		Trap::Interrupt(Interrupt::MachineSoft) => {
			//println!("hart {} MachineSoft", mhartid::read());
			unsafe {
				mip::set_ssoft();
			}
			// Software Interrupt at Machine Mode can only be cleared by 
			// setting CLINT, but in Supervisor Mode, it can be done by clearing 
			// SSIP in sip
			let hartid = riscv::register::mhartid::read();
			crate::hal::clint::clear_ipi(hartid);
		}, 
		Trap::Interrupt(Interrupt::MachineExternal) => {
			//println!("hart {} MachineExternal", mhartid::read());
			match () {
				#[cfg(feature = "soft-extern")]
				() => {
					// This setting is for those which don't implement S-mode 
					// external interrupts, like k210. If your hardware does have 
					// Supervisor External Interrupt, then delegate it to S-mode 
					// may be a better solution. 
					// For the sake of k210, we deliver a software interrupt to S-mode 
					// kernel, so that the kernel can deal the it in S-mode. And after 
					// the interrupt is "complete", the kernel should re-trap into 
					// SBI to enable MEIP, which can be done by SBI function sbi_xv6_set_ext()
					unsafe {
						mie::clear_mext();
						// disable mtimer because we don't want to be interrupted
						// this may not be necessary
						mie::clear_mtimer();

						// set S-mode software interrupt 
						mip::set_ssoft();
					}
				}, 
				#[cfg(not(feature = "soft-extern"))]
				() => {
					// do nothing here
				}, 
			}
		},
		#[cfg(feature = "old-spec")]
		Trap::Exception(Exception::IllegalInstruction) => {
			let vaddr = mepc::read();

			if sbt::translation(vaddr, tf) {}

			else {
				panic!(
					"Illegal Instruction, mepc: {:016x?}\ntrap frame: {:x?}", 
					vaddr, 
					tf
				);
			}
		}, 
		_ => {
			panic!(
				"Unhandled exception! mcause: {:?}, mepc: {:016x?}, mtval: {:016x?}\ntrap frame: {:p}\n{:x?}",
				cause,
				mepc::read(),
				mtval::read(),
				&tf as *const _,
				tf
			);
		}, 
	}
}

pub fn init() {
	// install trap vector 
	unsafe {
		mtvec::write(
			sbi_trap_vec as usize, 
			mtvec::TrapMode::Direct
		);
	}

	// delegate traps
	unsafe {
		// somehow we can't set medeleg via riscv crate
		use core::arch::asm;
		asm!("
			li {0}, 0x222
			csrw mideleg, {0}
			li {0}, 0xb1ab
			csrw medeleg, {0}
		", out(reg) _);
	}

	// enable interrupts
	unsafe {
		crate::hal::clint::clear_ipi(
			mhartid::read()
		);
		mie::set_mext();
		mie::set_msoft();
		// we don't enable mtimer because it would be enabled 
		// through SBI call set_timer()
		// And enable mtimer may introduce some problem in kernel, 
		// like a mtimer interrupt before kernel's trapvec is installed.
	}
}

pub fn enter_supervisor(hartid: usize) {
	unsafe {
		// disable trap to switch trap vector 
		mstatus::clear_mie();

		mtvec::write(trap_vec as usize, mtvec::TrapMode::Direct);

		// set previous mode as supervisor 
		mstatus::set_mpp(MPP::Supervisor);
		mepc::write(KERNEL_ENTRY);
		use core::arch::asm;
		asm!(
			"csrw mscratch, sp", 
			"mret", 
			in("a0") hartid, 
			options(noreturn)
		);
	}
}

pub(super) fn translation(vaddr: usize, tf: &mut TrapFrame) ->bool {
	let ins = unsafe {extract_inst(vaddr)};
	if ins & 0xFE007FFF == 0x12000073 { // sfence.vma instruction
		// There is no `sfence.vma` in 1.9.1 privileged spec; however there is a `sfence.vm`.
		// For backward compability, here we emulate the first instruction using the second one.
		// sfence.vma: | 31..25 funct7=SFENCE.VMA(0001001) | 24..20 rs2/asid | 19..15 rs1/vaddr | 
		//               14..12 funct3=PRIV(000) | 11..7 rd, =0 | 6..0 opcode=SYSTEM(1110011) |
		// sfence.vm(1.9):  | 31..=20 SFENCE.VM(000100000100) | 19..15 rs1/vaddr |
		//               14..12 funct3=PRIV(000) | 11..7 rd, =0 | 6..0 opcode=SYSTEM(1110011) |
		// discard rs2 // let _rs2_asid = ((ins >> 20) & 0b1_1111) as u8;
		// let rs1_vaddr = ((ins >> 15) & 0b1_1111) as u8;
		// read paging mode from satp (sptbr)
		let satp_bits = satp::read().bits();
		// bit 63..20 is not readable and writeable on K210, so we cannot
		// decide paging type from the 'satp' register.
		// that also means that the asid function is not usable on this chip.
		// we have to fix it to be Sv39.
		let ppn = satp_bits & 0xFFF_FFFF_FFFF; // 43..0 PPN WARL
		// write to sptbr
		let sptbr_bits = ppn & 0x3F_FFFF_FFFF;
		// unsafe { llvm_asm!("csrw 0x180, $0"::"r"(sptbr_bits)) }; // write to sptbr
		unsafe {
			use core::arch::asm;
			asm!("csrw 0x180, {0}", in(reg) sptbr_bits);
		}
		// enable paging (in v1.9.1, mstatus: | 28..24 VM[4:0] WARL | ... )
		let mut mstatus_bits: usize; 
		// unsafe { llvm_asm!("csrr $0, mstatus":"=r"(mstatus_bits)) };
		unsafe {
			use core::arch::asm;
			asm!("csrr {0}, mstatus", out(reg) mstatus_bits);
		}
		mstatus_bits &= !0x1F00_0000;
		mstatus_bits |= 9 << 24; 
		// unsafe { llvm_asm!("csrw mstatus, $0"::"r"(mstatus_bits)) };
		unsafe {
			use core::arch::asm;
			asm!("csrw mstatus, {0}", in(reg) mstatus_bits);
		}
		// emulate with sfence.vm (declared in privileged spec v1.9)
		// unsafe { llvm_asm!(".word 0x10400073") }; // sfence.vm x0
		unsafe {
			use core::arch::asm;
			asm!(".word 0x10400073");	// sfence.vm x0
		}
		// ::"r"(rs1_vaddr)
		mepc::write(mepc::read().wrapping_add(4)); // skip current instruction

		true 
	}
	else if ins & 0xFFFFF07F == 0xC0102073 { // rdtime instruction
		// rdtime is actually a csrrw instruction
		let rd = ((ins >> 7) & 0b1_1111) as u8;
		let mtime = crate::hal::clint::get_mtime();
		let time_usize = mtime as usize;
		set_rd(tf, rd, time_usize);
		mepc::write(mepc::read().wrapping_add(4)); // skip current instruction 

		true
	}
	else {false}
}

unsafe fn extract_inst(vaddr: usize) ->u32 {
	let low = get_vaddr_u16(vaddr) as u32;
	let high = get_vaddr_u16(vaddr + 2) as u32;

	low | (high << 16)
}

unsafe fn get_vaddr_u16(vaddr: usize) ->u16 {
	let mut ans: u16;
	use core::arch::asm;
	asm!(
		"li {0}, (1 << 17)", 
		"csrrs {0}, mstatus, {0}", 
		"lhu {1}, 0({2})", 
		"csrw mstatus, {0}", 
		out(reg) _, 
		out(reg) ans, 
		in(reg) vaddr, 
	);
	ans
}

pub(super) fn handler(tf: &TrapFrame) ->SbiRet {
	let fid = tf.a6;

	match fid {
		GET_SPECIFICATION_VER => {
			// this function should always succeed
			SbiRet(
				SUCCESS, 
				make_ver(SBI_SPEC_VER_MAJOR, SBI_SPEC_VER_MINOR) as i64
			)
		}, 
		GET_IMPL_ID => {
			SbiRet(SUCCESS, SBI_IMPL_ID as i64)
		}, 
		GET_IMPL_VER => {
			SbiRet(
				SUCCESS, 
				make_ver(*SBI_IMPL_VER_MAJOR, *SBI_IMPL_VER_MINOR) as i64
			)
		}, 
		PROBE_EXTENSION => {
			let ext = tf.a0;

			if probe_extension(ext) {
				SbiRet(SUCCESS, ext)
			}
			else {
				SbiRet(ERR_FAILED, 0)
			}
		}, 
		GET_MACHINE_VENDOR_ID => {
			let val = if let Some(bits) = mvendorid::read() {
				bits.bits()
			} else {0};

			SbiRet(SUCCESS, val as i64)
		}, 
		GET_MACHINE_ARCH_ID => {
			let val = if let Some(bits) = marchid::read() {
				bits.bits()
			} else {0};

			SbiRet(SUCCESS, val as i64)
		}, 
		GET_MACHINE_IMPL_ID => {
			let val = if let Some(bits) = mimpid::read() {
				bits.bits()
			} else {0};

			SbiRet(SUCCESS, val as i64)
		}, 
		_ => {	// any unsupported sbi call for this extension
			SbiRet(ERR_NOT_SUPPORTED, 0)
		}, 
	}
}

fn make_ver(major: u32, minor: u32) ->u32 {
	let major = major & 0x7f;
	let minor = minor & 0xff_ffff;

	(major << 24) | minor
}

pub(super) fn handler(tf: &TrapFrame) ->SbiRet {
	let fid = tf.a6;

	match fid {
		SEND_IPI => {
			let hart_mask = tf.a0 as usize;
			let hart_mask_base = tf.a1 as usize;

			if hart_mask_base > NCPU {
				SbiRet(ERR_INVALID_PARAM, 0)
			}
			else {
				let max_shift = core::cmp::min(NCPU - hart_mask_base, 32);
				if 0 != (hart_mask >> max_shift) {
					SbiRet(ERR_INVALID_PARAM, 0)
				}
				else {
					for i in 0..max_shift {
						let hart = 1usize << i;
						if 0 != (hart_mask & hart) {
							clint::send_ipi(i);
						}
					}
					SbiRet(SUCCESS, 0)
				}
			}
		}, 
		_ => {
			SbiRet(ERR_NOT_SUPPORTED, 0)
		}, 
		// Different from Legacy, sPI extension does not provide 
		// `clear_ipi` calling. That's because SSIP bit can now be 
		// cleared by software in S-mode.
	}
}

pub(super) fn handler(tf: &mut TrapFrame) {
	let eid = tf.a7;

	match eid {
		EID_SET_TIMER => {
			// void sbi_set_timer(uint64_t stime_value)
			let stime_value = tf.a0 as u64;
			clint::set_timer(stime_value);
			if mip::read().mtimer() {
				unsafe {
					mip::set_stimer();
					mie::clear_mtimer();
				}
			}
			else {
				unsafe {
					mip::clear_stimer();
					mie::set_mtimer();
				}
			}
		}, 
		EID_CONSOLE_PUTCHAR => {
			// void sbi_console_putchar(int ch)
			let c = tf.a0 as u8;
			uart::putchar(c);
		}, 
		EID_CONSOLE_GETCHAR => {
			// int sbi_console_getchar(void)
			tf.a0 = (uart::getchar() as i8) as i64;
		}, 
		EID_CLEAR_IPI => {
			// void sbi_clear_ipi(void)
			// This funciton is deprecated as SSIP can be cleared in Supervisor by software now
			unsafe {
				mip::clear_ssoft();
			}
		}, 
		EID_SEND_IPI => {
			// void sbi_send_ipi(const unsigned long *hart_mask)
			// It's really wierd to pass hart_mask via a pointer, maybe it's for 
			// cases where more than 32 harts exists
			// And as this function is deprecated, the new interface use 
			// (hart_mask: u32, hart_mask_base: u32) instead, which sounds more reasonable.
			let hart_mask = unsafe {
				*(tf.a0 as *const u32)
			} as usize;

			use crate::config::NCPU;
			for hartid in 0..NCPU {
				let mask = 1 << hartid;
				if 0 != (hart_mask & mask) {
					clint::send_ipi(hartid);
				}
			}
		}, 
		EID_SHUTDOWN => {
			// void sbi_shutdown(void)
			// turn off interrupts and run into wfi

			println!("SBI shutdown...");
			unsafe {
				mstatus::clear_mie();
				mstatus::clear_sie();
				mstatus::clear_uie();

				loop {
					riscv::asm::wfi();
				}
			}
		}, 
		_ => {
			// To be simple we don't implement any "remote fence" sbi functions
			// in legacy extension. They may be added later in RFENCE Extension
			println!("unsupported legacy SBI function: {:#x}", eid);
			tf.a0 = ERR_NOT_SUPPORTED;
		}
	}
}

pub(super) fn handler(tf: &mut TrapFrame) {
	let eid = tf.a7;

	if eid >= EID_LEGACY_MIN && eid <= EID_LEGACY_MAX {
		// a legacy sbi function, which returns int or void, differs from other SBI functions
		// According to sbi spec, legacy calls are "deprecated in favor of the other
		// extensions". So I suggest avoid using them in the S-mode kernel
		legacy::handler(tf);
	}
	else {
		let ret = if EID_BASE == eid {
			base::handler(tf)
		}
		else if EID_TIME == eid {
			time::handler(tf)
		}
		else if EID_IPI == eid {
			ipi::handler(tf)
		}
		else if eid >= EID_VENDOR_MIN && eid <= EID_VENDOR_MAX {
			vendor::handler(tf)
		}
		else if eid >= EID_FIRMWARE_MIN && eid <= EID_FIRMWARE_MAX {
			firmware::handler(tf)
		}
		else {
			println!("unsupported SBI extension: {:#x}", eid);
			SbiRet(ERR_NOT_SUPPORTED, 0)
		};

		tf.a0 = ret.0;
		tf.a1 = ret.1;
	}
}

pub(super) fn handler(tf: &TrapFrame) ->SbiRet {
	let fid = tf.a6;

	match fid {
		SET_TIMER => {
			let stime_value = tf.a0 as u64;

			// set mtimecmp
			// writting to mtimecmp will clear MTIP in mip, which can only be 
			// cleared in this way
			clint::set_timer(stime_value);
			// clear MTIP pending bit and enable M-mode time interrupt 
			unsafe {
				mip::clear_stimer();
				mie::set_mtimer();
			}
			SbiRet(SUCCESS, 0)
		}, 
		_ => {
			SbiRet(ERR_NOT_SUPPORTED, 0)
		}
	}
}

pub(super) fn handler(tf: &TrapFrame) ->SbiRet {
	let eid = tf.a7;

	match eid {
		XV6_EID => {
			xv6_k210::handler(tf)
		}, 
		_ => {
			SbiRet(ERR_NOT_SUPPORTED, 0)
		}, 
	}
}

pub(super) fn has_extension(ext: i64) ->bool {
	XV6_EID == ext
}

pub(super) fn handler(tf: &TrapFrame) ->SbiRet {
	let fid = tf.a6;

	match fid {
		SET_EXT => {
			// struct sbiret sbi_xv6_set_ext();
			unsafe {
				mie::set_mext();
				mie::set_mtimer();
			}

			SbiRet(SUCCESS, 0)
		}, 
		IS_EXT => {
			// struct sbiret sbi_xv6_is_ext();
			// as what we do, when there's an external interrupt, 
			// mie::mext is clear to avoid multiple interrupts
			if mie::read().mext() {
				SbiRet(SUCCESS, 0)
			}
			else {
				SbiRet(SUCCESS, 1)
			}
		}, 
		CONSOLE_PUTS => {
			// struct sbiret sbi_xv6_puts(char *str, int n);
			let mut str = tf.a0 as *const u8;
			let n = tf.a1 as usize;

			let mut cnt = 0;
			while cnt < n {
				let c = unsafe {*str};
				if 0 == c {break;}
				else {
					uart::putchar(c);
				}

				str = str.wrapping_add(1);
				cnt += 1;
			}

			SbiRet(SUCCESS, cnt as i64)
		}, 
		GET_TIMER => {
			// struct sbiret sbi_xv6_get_timer(void);
			// This may be implemented other way, as k210 provides some other timers, 
			// they may be a better choice than mtime
			let mtime = clint::get_mtime();
			SbiRet(SUCCESS, mtime as i64)
		}, 
		_ => {
			SbiRet(ERR_NOT_SUPPORTED, 0)
		}
	}
}

pub(super) fn handler(tf: &TrapFrame) ->SbiRet {
	let eid = tf.a7;

	match eid {
		_ => {
			SbiRet(ERR_NOT_SUPPORTED, 0)
		}
	}
}

