int
countfree()
{
    int fds[2];
    if (pipe(fds) < 0) {
        printf("pipe() failed in countfree()\n");
        exit(1);
    }
    int pid = fork();
    if (pid < 0) {
        printf("fork failed in countfree()\n");
        exit(1);
    }
    if (pid == 0) {
        close(fds[0]);
        while (1) {
            uint64 a = (uint64) sbrk(4096);
            if (a == 0xffffffffffffffff)
                break;

            // modify the memory to make sure it's really allocated.
            *(char *)(a + 4096 - 1) = 1;

            // report back one more page.
            if (write(fds[1], "x", 1) != 1) {
                printf("write() failed in countfree()\n");
                exit(1);
            }
        }
        exit(0);
    }

    close(fds[1]);
    int n = 0;
    while (1) {
        char c;
        int cc = read(fds[0], &c, 1);
        if (cc < 0) {
            printf("read() failed in countfree()\n");
            exit(1);
        }
        if (cc == 0)
            break;
        n += 1;
    }

    close(fds[0]);
    wait((int*)0);
    return n;
}

char *openmmap(char *file, uint64 *len)
{
    int fd;
    struct kstat stat;
    char *start;

    if ((fd = open(file, O_RDWR)) < 0) {
        return NULL;
    }
    if (fstat(fd, &stat) < 0) {
        close(fd);
        return NULL;
    }
    *len = stat.size;
    start = mmap(NULL, stat.size, PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);
    if ((int64)start < 0) {
        return NULL;
    }
    return start;
}

void sharewirte(char *testname)
{
    int pid;
    char *start;
    uint64 len;

    pid = fork();
    if (pid < 0) {
        fprintf(2, "fork fail\n");
        exit(1);
    }
    else if (pid == 0) {
        start = openmmap("README", &len);
        if (start == NULL) {
            fprintf(2, "mmap fail\n");
            exit(1);
        }
        for (int i = 5; i < 10; i++) {
            start[i] = '0' + i;
        }
        munmap(start, len);
    } else {
        start = openmmap("README", &len);
        if (start == NULL) {
            fprintf(2, "mmap fail\n");
            exit(1);
        }
        for (int i = 0; i < 5; i++) {
            start[i] = '0' + i;
        }
        munmap(start, len);
        wait(NULL);
        int fd = open("README", O_RDONLY);
        if (fd < 0) {
            fprintf(2, "open README fail\n");
            exit(1);
        }
        char buf[11];
        buf[10] = 0;
        if (read(fd, buf, 10) != 10) {
            fprintf(2, "read README fail\n");
