int readline(int fd, char *buf){
  int i;
  char c;

  for(i = 0; ; i++){
    read(fd, &c, 1);
    if(c == '\n' || c == 0)
      break;
    else
      *(buf+i) = c;
  }
  *(buf+i) = 0;

  return i;
}

int
main(void)
{
  static char buf[128];
  int fd;

  // Ensure that three file descriptors are open.
  while((fd = open("/dev/console", O_RDWR)) >= 0){
    if(fd >= 3){
      close(fd);
      break;
    }
  }

  // Add an embedded env var(for basic commands in shell)
  fd = open("shrc", O_RDONLY);
  if(fd < 0){
    fprintf(2, "sh: cannot open shrc\n");
  } else{
    while(readline(fd, buf))
      export(buf);
    close(fd);
  }

  getcwd(mycwd, sizeof(mycwd));
  // Read and run input commands.
  while(getcmd(buf, sizeof(buf)) >= 0){
    replace(buf);
    if(buf[0] == 'c' && buf[1] == 'd' && buf[2] == ' '){
      // Chdir must be called by the parent, not the child.
      buf[strlen(buf)-1] = 0;  // chop \n
      if(chdir(buf+3) < 0)
        fprintf(2, "cannot cd %s\n", buf+3);
      getcwd(mycwd, sizeof(mycwd));
    }
    else{
      struct cmd *cmd = parsecmd(buf);
      struct execcmd *ecmd;

      ecmd = (struct execcmd*)cmd;
      if(ecmd->argv[0] == 0) {
        free(cmd);
        continue;
      }
      else if(!strcmp(ecmd->argv[0], "export"))
      {
        // Export must be called by the parent, not the child.
        if(ecmd->argv[1] == NULL)
          fprintf(2, "Usage: export [-p] [NAME=VALUE]\n");
        else if(export(ecmd->argv[1]) < 0)
          fprintf(2, "export failed\n");
        free(cmd);
        continue;
      }
      else if(fork1() == 0) 
        runcmd(cmd);
      wait(0);
      free(cmd);
    }
  }
  exit(0);
}

