void
createdelete(char *s)
{
  enum { N = 20, NCHILD=4 };
  int pid, i, fd, pi;
  char name[32];
  char illegal[] = { '\"', '*', '/', ':', '<', '>', '?', '\\', '|', 0 };
  for(pi = 0; pi < NCHILD; pi++){
    pid = fork();
    if(pid < 0){
      printf("fork failed\n", s);
      exit(1);
    }

    if(pid == 0){
      name[0] = 'p' + pi;
      name[2] = '\0';
      for(i = 0; i < N; i++){
        name[1] = '0' + i;
        if (strchr(illegal, name[1]) == 0) {
          fd = open(name, O_CREATE | O_RDWR);
          if(fd < 0){
            printf("%s: create %s failed\n", s, name);
            exit(1);
          }
          close(fd);
        }
        if(i > 0 && (i % 2 ) == 0){
          name[1] = '0' + (i / 2);
          if (strchr(illegal, name[1]) == 0) {
            if(remove(name) < 0){
              printf("%s: remove failed\n", s);
              exit(1);
            }
          }
        }
      }
      exit(0);
    }
  }

  int xstatus;
  for(pi = 0; pi < NCHILD; pi++){
    wait(&xstatus);
    if(WEXITSTATUS(xstatus) != 0)
      exit(1);
  }

  name[0] = name[1] = name[2] = 0;
  for(i = 0; i < N; i++){
    for(pi = 0; pi < NCHILD; pi++){
      name[0] = 'p' + pi;
      name[1] = '0' + i;
      if (strchr(illegal, name[1]) != 0) { continue; }
      fd = open(name, 0);
      if((i == 0 || i >= N/2) && fd < 0){
        printf("%s: oops createdelete %s didn't exist\n", s, name);
        exit(1);
      } else if((i >= 1 && i < N/2) && fd >= 0){
        printf("%s: oops createdelete %s did exist\n", s, name);
        exit(1);
      }
      if(fd >= 0)
        close(fd);
    }
  }

  for(i = 0; i < N; i++){
    for(pi = 0; pi < NCHILD; pi++){
      name[0] = 'p' + pi;
      name[1] = '0' + i;
      remove(name);
    }
  }
}

